export const dsaModuleContent: Record<string, string> = {
  "bigo": "<div id=\"bigo\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 01</div>\n      <h2>Complejidad Algorítmica — Big O y Space Complexity</h2>\n      <p>El lenguaje universal de los ingenieros para medir y comunicar qué tan eficiente es un algoritmo en términos de <strong>Tiempo</strong> y <strong>Memoria</strong> cuando la cantidad de datos (input) crece hacia el infinito. Sin dominar esto, jamás sabrás si una solución es óptima o si pasará la entrevista.</p>\n    </div>\n\n    <!-- SECCION COMPLEJIDAD DE TIEMPO -->\n    <div class=\"section\">\n      <div class=\"section-title\">Time Complexity (Tiempo de Ejecución)</div>\n      <p style=\"color: #999; margin-bottom: 24px; font-size: 15px; line-height: 1.6;\">Mide cómo aumenta la cantidad de <strong>operaciones</strong> que hace tu programa a medida que el input (N) se vuelve gigante. En Big O, siempre nos preparamos para el peor escenario (<strong>el peor caso</strong>) y utilizamos una heurística vital: <strong>las constantes se ignoran por completo</strong>.</p>\n      \n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Las 6 Complejidades Clásicas <span class=\"badge b-blue\">vital</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA EXHAUSTIVA</div>\n          <p><strong>¿Por qué ignorar constantes?</strong> Si tienes un algoritmo que hace <code>2 * N</code> operaciones (o sea, <code>O(2n)</code>), decimos que es estrictamente <code>O(N)</code>. Porque si N es un trillón, ese \"x2\" no cambia la forma geométrica del crecimiento en la gráfica matemática; sigue siendo una línea recta (lineal). La regla de oro en Big O es que las constantes no importan: <code>O(2n) -> O(n)</code> y <code>O(n + 500) -> O(n)</code>.</p>\n          \n          <table class=\"tbl\" style=\"margin-top:20px;\">\n            <thead>\n              <tr><th>Notación</th><th>Nombre</th><th>Explicación profunda de concepto</th><th>Escala</th></tr>\n            </thead>\n            <tbody>\n              <tr><td><code>O(1)</code></td><td>Constante</td><td>El tiempo no depende del input en lo absoluto. <strong>Ejemplo: Acceder a un elemento en un array por su índice <code>arr[i]</code></strong>, pushear a un stack, buscar en un hash map válido. Siempre hace ~1 operación rápida e instantánea.</td><td><span class=\"time time-good\">✓ óptimo</span></td></tr>\n              <tr><td><code>O(log n)</code></td><td>Logarítmica</td><td>El problema se <strong>divide por la mitad</strong> en cada paso. Eres un cirujano descartando grandes porciones de datos inútiles (ej: algoritmos como <strong>Binary Search</strong> sobre arreglos ordenados).</td><td><span class=\"time time-good\">✓ excelente</span></td></tr>\n              <tr><td><code>O(n)</code></td><td>Lineal</td><td>Tienes que mirar cada elemento del arreglo al menos una sola vez de frente (ej: un simple <code>for loop</code> recorriendo un array entero para buscar el máximo elemento).</td><td><span class=\"time time-good\">✓ bueno</span></td></tr>\n              <tr><td><code>O(n log n)</code></td><td>Lineal-log</td><td>Conocida como la complejidad <strong>típica de ordenamiento</strong> algorítmico eficiente (como Merge Sort o Heap Sort). Combina iterar sobre los elementos (N) multiplicando las particiones logarítmicas (log n).</td><td><span class=\"time time-ok\">~ aceptable</span></td></tr>\n              <tr><td><code>O(n²)</code></td><td>Cuadrática</td><td>Tienes <strong>dos bucles anidados que recorren \"n\"</strong> internamente de manera iterativa. Por cada elemento en el arreglo iterado, vuelves a iterar sobre los otros N elementos. (Ejemplo trágico: Bubble Sort).</td><td><span class=\"time time-bad\">✗ lento</span></td></tr>\n              <tr><td><code>O(2ⁿ)</code></td><td>Exponencial</td><td>El número de operaciones se duplica ciegamente cada vez que añades un simple dato más al input. Típico de evaluar un <strong>algoritmo de recursión simple como Fibonacci sin memoización</strong>. Un desastre de redimiento.</td><td><span class=\"time time-bad\">✗ imposible</span></td></tr>\n            </tbody>\n          </table>\n        </div>\n      </div>\n    </div>\n\n    <!-- SECCION REGLAS DEL JUEGO -->\n    <div class=\"section\">\n      <div class=\"section-title\">Las Reglas del Juego Lógico</div>\n\n      <div class=\"callout callout-yellow\">\n        <strong>💡 Analogía real para entender Constant vs Log vs Lineal:</strong><br>\n        Buscar la palabra \"Cebra\" en un diccionario impreso de papel:<br>\n        - <b>O(n):</b> Leer el diccionario página por página minuciosamente desde la A. Te va a tomar años de encierro si el libro tiene millones de páginas.<br>\n        - <b>O(log n):</b> Abrirlo por la mitad exacto. Si ves la letra \"M\", sabes que Cebra está en el cerro de la izquierda. Descartas matemáticamente la mitad derecha entera y repites abriendo la mitad izquierda. Solo necesitas ~20 iteraciones para encontrarla en un libro de 1 millón de páginas (Como hace Binary Search).<br>\n        - <b>O(1):</b> Tienes el número de página anotado en la palma de tu mano izquierda y vas directo. Tardas 1 segundo milimétricamente no importa qué tan grueso sea el diccionario.\n      </div>\n      \n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Detectando Complejidad por Patrones de Código <span class=\"badge b-yellow\">ejemplos O(x)</span></div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">time_calc.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"cm\"># REGLA 1: Acceso Directo → O(1)</span></span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">get_first</span>(arr):</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    <span class=\"kw\">return</span> arr[<span class=\"nm\">0</span>]  <span class=\"cm\"># O(1): No depende de si arr tiene 10 o 10 millones de cosas.</span></span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\"></span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\"><span class=\"cm\"># REGLA 2: Un loop lineal común → O(n)</span></span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\"><span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(n):</span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">    <span class=\"fn\">print</span>(i)  <span class=\"cm\"># O(n): La cantidad de \"prints\" crece codo a codo con n.</span></span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\"></span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\"><span class=\"cm\"># REGLA 3: Dos bucles anidados iterando 'n' → Se multiplican O(n²)</span></span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\"><span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(n):              </span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">    <span class=\"kw\">for</span> j <span class=\"kw\">in</span> <span class=\"fn\">range</span>(n):          <span class=\"cm\"># N pasos en la capa externa * N en la interna.</span></span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">        <span class=\"fn\">print</span>(i, j)             <span class=\"cm\"># El resultado computacional de esto es O(n²).</span></span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\"></span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\"><span class=\"cm\"># REGLA 4: El problema sistemáticamente se divide en mitades → O(log n)</span></span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">left, right = <span class=\"nm\">0</span>, n - <span class=\"nm\">1</span></span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\"><span class=\"kw\">while</span> left &lt;= right:            <span class=\"cm\"># Binary Search</span></span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">    mid = (left + right) // <span class=\"nm\">2</span>   <span class=\"cm\"># Descartas radicalmente el 50% de las opciones en cada paso</span></span></div><div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">    left = mid + <span class=\"nm\">1</span>              <span class=\"cm\"># O(log n)</span></span></div><div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\"></span></div><div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\"><span class=\"cm\"># REGLA 5: Recursión bifurcada sin memoria caché (Memo) → O(2ⁿ)</span></span></div><div class=\"cl\"><span class=\"ln\">21</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">fibonacci_malo</span>(n):  </span></div><div class=\"cl\"><span class=\"ln\">22</span><span class=\"lc\">    <span class=\"kw\">if</span> n &lt;= <span class=\"nm\">1</span>: <span class=\"kw\">return</span> n</span></div><div class=\"cl\"><span class=\"ln\">23</span><span class=\"lc\">    <span class=\"cm\"># En cada paso te ramificas en el árbol x2 veces. Esto es Exponencial.</span></span></div><div class=\"cl\"><span class=\"ln\">24</span><span class=\"lc\">    <span class=\"kw\">return</span> <span class=\"fn\">fibonacci_malo</span>(n-<span class=\"nm\">1</span>) + <span class=\"fn\">fibonacci_malo</span>(n-<span class=\"nm\">2</span>)  <span class=\"cm\"># ¡Romperá la CPU velozmente!</span></span></div>\n          </div>\n        </div>\n      </div>\n    </div>\n\n    <!-- SECCION SPACE COMPLEXITY -->\n    <div class=\"section\">\n      <div class=\"section-title\">Space Complexity (Complejidad de Espacio)</div>\n      \n      <div class=\"callout callout-green\">\n        <strong>🤔 ¿Por qué importa el espacio y cómo se calcula?</strong><br>\n        Time Complexity mide cuán veloz eres, pero Space Complexity evalúa <strong>cuánta memoria RAM adicional (auxiliar) necesitas</strong> para operar. Atención vital: La matriz u objeto que te proveen originalmente como Input no cuenta como espacio adicional. Cuentan únicamente los constructos extra, diccionarios extra, matrices y recursos matemáticos que debas instanciar para resolver tu dilema.\n      </div>\n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Memoria Auxiliar vs Creación de Copias <span class=\"badge b-red\">memory</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">¿QUÉ OCUPA ESTE ESPACIO EN LA RAM?</div>\n          <p>Hay exactamente dos grandes vampiros de recursos de memoria en cualquier paradigma de algoritmos:</p>\n          <ul>\n            <li style=\"margin-bottom: 8px;\"><strong>Creación de copias y nuevas estructuras:</strong> Si el Input es un grandioso Array de tamaño N, y tú para solventar un problema decides internamente programar algo que <strong style=\"color:#ef4444\">crea una copia de ese array</strong>, habrás condenado a tu algoritmo silenciosamente a consumir un Espacio Auxiliar de <code>O(n)</code>. Un mapa Hash/diccionario con N llaves también ocupa mágicamente <code>O(n)</code> espacio.</li>\n            <li><strong>El Call Stack en Recursiones (La Pila Interna del Sistema del CPU):</strong> El SO de un computador preserva el registro de cada llamada a una función dentro del Call Stack antes de regresar arriba. Si desencadenas una Recursión profunda sin salir que se profundiza con tamaño N, consumiste un Espacio de Sistema real en el Stack equivalente a <code>O(n)</code>, aunque tu sintaxis ni si quiera tenga variables.</li>\n          </ul>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">space_calc.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"cm\"># ESPACIO O(1) - La Optimidad pura, operaciones llamadas \"In-Place\" (en el lugar)</span></span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">reverse_array_inplace</span>(arr):</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    <span class=\"cm\"># En este algoritmo invertimos un enorme arreglo modificándolo en él mismo</span></span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    left, right = <span class=\"nm\">0</span>, <span class=\"fn\">len</span>(arr) - <span class=\"nm\">1</span></span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    <span class=\"kw\">while</span> left &lt; right:</span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">        arr[left], arr[right] = arr[right], arr[left]</span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">        left += <span class=\"nm\">1</span>; right -= <span class=\"nm\">1</span></span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">    <span class=\"cm\"># Declaramos las variables numéricas simples 'left' y 'right'.</span></span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">    <span class=\"cm\"># Dos Integers básicos no escalan, esto es constante puro: Espacio O(1)</span></span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\"></span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\"><span class=\"cm\"># ESPACIO O(n) - Copias Adicionales Costosas y Tablas Hash de almacenamiento</span></span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">reverse_array_copy</span>(arr):</span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">    <span class=\"cm\"># ¡Alerta roja de memoria! Cuando ejecutas esta sintaxis</span></span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">    <span class=\"cm\"># internamente Python crea una COPIA masiva del array en la memoria.</span></span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">    <span class=\"kw\">return</span> arr[::-<span class=\"nm\">1</span>] <span class=\"cm\"># Espacio adicional de O(n)</span></span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\"></span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">store_in_hash</span>(arr):</span></div><div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">    <span class=\"cm\"># Si le insertas todos los elementos iterados a un diccionario (Hash Table)</span></span></div><div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\">    <span class=\"cm\"># terminará teniendo N buckets almacenados. El uso de espacio es O(n)</span></span></div><div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\">    vistos = <span class=\"fn\">set</span>() </span></div><div class=\"cl\"><span class=\"ln\">21</span><span class=\"lc\">    <span class=\"kw\">for</span> element <span class=\"kw\">in</span> arr: vistos.<span class=\"fn\">add</span>(element)</span></div>\n          </div>\n        </div>\n      </div>\n    </div>\n\n    <!-- ARRAYS -->",
  "arrays": "<div id=\"arrays\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 02</div>\n      <h2>Arrays &amp; Strings</h2>\n      <p>La base de casi todo. El 60% de los problemas de LeetCode involucran arrays. Dominá estos patrones primero.</p>\n    </div>\n\n    <div class=\"section\">\n      <div class=\"section-title\">Patrón: Two Pointers</div>\n\n      <div class=\"callout callout-blue\">\n        <strong>💡 Cuándo usar Two Pointers</strong>\n        Cuando el array está ordenado y necesitás encontrar pares o tripletas que cumplan una condición. Convierte problemas O(n²) en O(n). Señal en el enunciado: \"sorted array\", \"find pair that sums to X\", \"remove duplicates\".\n      </div>\n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Two Sum en array ordenado <span class=\"badge b-green\">O(n) · O(1)</span></div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">two_sum_sorted.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"cm\"># Input: [2,7,11,15], target=9 → [0,1]</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">two_sum_sorted</span>(nums, target):</span></div>\n            <div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    left, right = <span class=\"nm\">0</span>, <span class=\"fn\">len</span>(nums) - <span class=\"nm\">1</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    <span class=\"kw\">while</span> left &lt; right:</span></div>\n            <div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">        current = nums[left] + nums[right]</span></div>\n            <div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">        <span class=\"kw\">if</span> current == target:</span></div>\n            <div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">            <span class=\"kw\">return</span> [left, right]</span></div>\n            <div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">        <span class=\"kw\">elif</span> current &lt; target:</span></div>\n            <div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">            left += <span class=\"nm\">1</span>   <span class=\"cm\"># necesitamos más: mover izquierda</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">        <span class=\"kw\">else</span>:</span></div>\n            <div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">            right -= <span class=\"nm\">1</span>  <span class=\"cm\"># necesitamos menos: mover derecha</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">    <span class=\"kw\">return</span> []</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Dos punteros que se mueven desde los extremos hacia el centro. Si la suma es menor que el target necesitamos un número mayor → movemos el puntero izquierdo. Si es mayor → movemos el derecho. Solo funciona con arrays <strong>ordenados</strong>. <span class=\"time time-good\">O(n) tiempo</span> <span class=\"time time-good\">O(1) espacio</span></p>\n        </div>\n      </div>\n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">3Sum — tripletas que suman cero <span class=\"badge b-yellow\">O(n²) · O(1)</span></div>\n        </div><div class=\"concept-explain\">\n  <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n  <p><strong>¿Qué es esto?</strong> Es una extensión de Two Pointers. Fijamos un elemento con un loop (ese es el primero de la tripleta) y luego usamos Two Pointers en el resto del array para encontrar el par que completa la suma en cero.</p>\n  <div class=\"analogy\">Buscando tres personas que sumen un peso exacto: elegís a una fija, y luego ponés a dos ayudantes a buscar las otras dos en el resto del grupo ordenado.</div>\n  <div class=\"why-matters\">El sorting previo es obligatorio. Sin skipear repetidos retornaríamos [-1,-1,2] dos veces si hay dos -1 en el array original. Esto soluciona O(n³) llevándolo a O(n²).</div>\n  \n  <p>Observarás el loop principal y cómo usamos 'continue' obligatoriamente para saltarnos duplicados.</p>\n</div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">three_sum.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">three_sum</span>(nums):</span></div>\n            <div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    nums.<span class=\"fn\">sort</span>()  <span class=\"cm\"># CRUCIAL: ordenar primero</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    result = []</span></div>\n            <div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(<span class=\"fn\">len</span>(nums) - <span class=\"nm\">2</span>):</span></div>\n            <div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">        <span class=\"kw\">if</span> i &gt; <span class=\"nm\">0</span> <span class=\"kw\">and</span> nums[i] == nums[i-<span class=\"nm\">1</span>]: <span class=\"kw\">continue</span>  <span class=\"cm\"># skip dup</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">        left, right = i + <span class=\"nm\">1</span>, <span class=\"fn\">len</span>(nums) - <span class=\"nm\">1</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">        <span class=\"kw\">while</span> left &lt; right:</span></div>\n            <div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">            s = nums[i] + nums[left] + nums[right]</span></div>\n            <div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">            <span class=\"kw\">if</span> s == <span class=\"nm\">0</span>:</span></div>\n            <div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">                result.<span class=\"fn\">append</span>([nums[i], nums[left], nums[right]])</span></div>\n            <div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">                <span class=\"kw\">while</span> left &lt; right <span class=\"kw\">and</span> nums[left] == nums[left+<span class=\"nm\">1</span>]: left += <span class=\"nm\">1</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">                <span class=\"kw\">while</span> left &lt; right <span class=\"kw\">and</span> nums[right] == nums[right-<span class=\"nm\">1</span>]: right -= <span class=\"nm\">1</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">                left += <span class=\"nm\">1</span>; right -= <span class=\"nm\">1</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">            <span class=\"kw\">elif</span> s &lt; <span class=\"nm\">0</span>: left += <span class=\"nm\">1</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">            <span class=\"kw\">else</span>: right -= <span class=\"nm\">1</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">    <span class=\"kw\">return</span> result</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Fijamos un elemento con el loop exterior, y usamos Two Pointers para el par restante. Lo crítico es <strong>skipear duplicados</strong> en las tres posiciones para no retornar tripletas repetidas. La poda del <span class=\"c\">continue</span> en línea 5 evita procesar el mismo número fijo más de una vez.</p>\n        </div>\n      </div>\n    </div>\n\n    <div class=\"section\">\n      <div class=\"section-title\">Patrón: Sliding Window</div>\n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Minimum Window Substring <span class=\"badge b-red\">Hard · O(s+t)</span></div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">min_window.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"cm\"># Input: s=\"ADOBECODEBANC\", t=\"ABC\" → \"BANC\"</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\"><span class=\"kw\">from</span> collections <span class=\"kw\">import</span> Counter</span></div>\n            <div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">min_window</span>(s, t):</span></div>\n            <div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    need = <span class=\"cl2\">Counter</span>(t)    <span class=\"cm\"># cuántos chars necesitamos</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    have, formed = {}, <span class=\"nm\">0</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">    required = <span class=\"fn\">len</span>(need)  <span class=\"cm\"># chars distintos a satisfacer</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">    left = <span class=\"nm\">0</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">    result = <span class=\"fn\">float</span>(<span class=\"st\">\"inf\"</span>), -<span class=\"nm\">1</span>, -<span class=\"nm\">1</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">    <span class=\"kw\">for</span> right <span class=\"kw\">in</span> <span class=\"fn\">range</span>(<span class=\"fn\">len</span>(s)):</span></div>\n            <div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">        char = s[right]</span></div>\n            <div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">        have[char] = have.<span class=\"fn\">get</span>(char, <span class=\"nm\">0</span>) + <span class=\"nm\">1</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">        <span class=\"kw\">if</span> char <span class=\"kw\">in</span> need <span class=\"kw\">and</span> have[char] == need[char]:</span></div>\n            <div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">            formed += <span class=\"nm\">1</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">        <span class=\"kw\">while</span> formed == required:  <span class=\"cm\"># ventana válida: tratar de reducir</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">            <span class=\"kw\">if</span> right - left + <span class=\"nm\">1</span> &lt; result[<span class=\"nm\">0</span>]:</span></div>\n            <div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">                result = (right - left + <span class=\"nm\">1</span>, left, right)</span></div>\n            <div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">            have[s[left]] -= <span class=\"nm\">1</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">            <span class=\"kw\">if</span> s[left] <span class=\"kw\">in</span> need <span class=\"kw\">and</span> have[s[left]] &lt; need[s[left]]:</span></div>\n            <div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\">                formed -= <span class=\"nm\">1</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\">            left += <span class=\"nm\">1</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">21</span><span class=\"lc\">    <span class=\"kw\">return</span> <span class=\"st\">\"\"</span> <span class=\"kw\">if</span> result[<span class=\"nm\">0</span>] == <span class=\"fn\">float</span>(<span class=\"st\">\"inf\"</span>) <span class=\"kw\">else</span> s[result[<span class=\"nm\">1</span>]:result[<span class=\"nm\">2</span>]+<span class=\"nm\">1</span>]</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Patrón de ventana deslizante variable. Expandimos con <span class=\"c\">right</span> hasta tener todos los chars necesarios. Una vez que la ventana es válida (<span class=\"cg\">formed == required</span>), intentamos reducirla moviendo <span class=\"c\">left</span> hasta que deje de ser válida. Guardamos el mínimo en cada contracción. <span class=\"time time-good\">O(s+t)</span></p>\n        </div>\n      </div>\n    </div>\n\n    <!-- DYNAMIC PROGRAMMING -->",
  "linked": "<div id=\"linked\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 03</div>\n      <h2>Linked Lists</h2>\n      <p>Fundamentales en entrevistas. Te enseñan a pensar con punteros — habilidad que se transfiere a árboles y grafos. El truco del dummy node y fast/slow pointers son los patrones clave.</p>\n    </div>\n\n    <div class=\"section\">\n      <div class=\"section-title\">Patrón: Fast &amp; Slow Pointers</div>\n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Detectar ciclo — Floyd's Algorithm <span class=\"badge b-yellow\">O(n) · O(1)</span></div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">detect_cycle.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"cm\"># Slow avanza 1, Fast avanza 2. Si hay ciclo, se encuentran.</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">has_cycle</span>(head):</span></div>\n            <div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    slow = fast = head</span></div>\n            <div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    <span class=\"kw\">while</span> fast <span class=\"kw\">and</span> fast.next:</span></div>\n            <div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">        slow = slow.next</span></div>\n            <div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">        fast = fast.next.next</span></div>\n            <div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">        <span class=\"kw\">if</span> slow == fast: <span class=\"kw\">return</span> <span class=\"kw\">True</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">    <span class=\"kw\">return</span> <span class=\"kw\">False</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\"></span></div>\n            <div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\"><span class=\"cm\"># Nodo medio: cuando fast llega al final, slow está en el medio</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">middle_node</span>(head):</span></div>\n            <div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">    slow = fast = head</span></div>\n            <div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">    <span class=\"kw\">while</span> fast <span class=\"kw\">and</span> fast.next:</span></div>\n            <div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">        slow = slow.next</span></div>\n            <div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">        fast = fast.next.next</span></div>\n            <div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">    <span class=\"kw\">return</span> slow</span></div>\n            <div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\"></span></div>\n            <div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\"><span class=\"cm\"># Reversar lista — el más importante de linked lists</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">reverse_list</span>(head):</span></div>\n            <div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\">    prev = <span class=\"kw\">None</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">21</span><span class=\"lc\">    curr = head</span></div>\n            <div class=\"cl\"><span class=\"ln\">22</span><span class=\"lc\">    <span class=\"kw\">while</span> curr:</span></div>\n            <div class=\"cl\"><span class=\"ln\">23</span><span class=\"lc\">        next_node = curr.next   <span class=\"cm\"># 1. guardar next</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">24</span><span class=\"lc\">        curr.next = prev        <span class=\"cm\"># 2. apuntar hacia atrás</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">25</span><span class=\"lc\">        prev = curr             <span class=\"cm\"># 3. avanzar prev</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">26</span><span class=\"lc\">        curr = next_node        <span class=\"cm\"># 4. avanzar curr</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">27</span><span class=\"lc\">    <span class=\"kw\">return</span> prev  <span class=\"cm\"># nuevo head</span></span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Fast &amp; Slow pointers es el patrón definitivo de linked lists. <span class=\"c\">slow</span> avanza 1 paso, <span class=\"c\">fast</span> avanza 2. Si hay un ciclo, eventualmente se encuentran — como dos corredores en una pista circular. Para reversar, siempre en el orden: <span class=\"cg\">guardar next → apuntar atrás → avanzar prev → avanzar curr</span>. Cambiarlo de orden rompe la lista.</p>\n        </div>\n      </div>\n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Merge K Sorted Lists — Hard con Heap <span class=\"badge b-red\">Hard · O(N log k)</span></div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">merge_k_lists.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">import</span> heapq</span></div>\n            <div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">merge_k_lists</span>(lists):</span></div>\n            <div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    heap = []</span></div>\n            <div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    <span class=\"cm\"># Meter el primer nodo de cada lista</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    <span class=\"kw\">for</span> i, node <span class=\"kw\">in</span> <span class=\"fn\">enumerate</span>(lists):</span></div>\n            <div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">        <span class=\"kw\">if</span> node:</span></div>\n            <div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">            heapq.heappush(heap, (node.val, i, node))</span></div>\n            <div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">    dummy = <span class=\"cl2\">ListNode</span>(<span class=\"nm\">0</span>)</span></div>\n            <div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">    curr = dummy</span></div>\n            <div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">    <span class=\"kw\">while</span> heap:</span></div>\n            <div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">        val, i, node = heapq.heappop(heap)  <span class=\"cm\"># el mínimo</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">        curr.next = node</span></div>\n            <div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">        curr = curr.next</span></div>\n            <div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">        <span class=\"kw\">if</span> node.next:</span></div>\n            <div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">            heapq.heappush(heap, (node.next.val, i, node.next))</span></div>\n            <div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">    <span class=\"kw\">return</span> dummy.next</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Usamos un min-heap de tamaño k (cantidad de listas). En cada paso, extraemos el nodo mínimo y agregamos el siguiente nodo de esa misma lista. El heap siempre tiene a lo sumo k elementos. <span class=\"time time-good\">O(N log k)</span> donde N = total de nodos. Sin heap sería O(Nk). La tupla <span class=\"c\">(val, i, node)</span> incluye el índice de lista para desempatar cuando hay valores iguales.</p>\n        </div>\n      </div>\n    </div>\n\n    <!-- ===================== STACKS & QUEUES ===================== -->",
  "stacks": "<div id=\"stacks\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 04</div>\n      <h2>Stacks, Queues y Monotonic Stack</h2>\n      <p>Stack (LIFO) y Queue (FIFO) son simples. El Monotonic Stack es el patrón avanzado más pedido en Hard — aparece en problemas de temperaturas, histogramas y agua atrapada.</p>\n    </div>\n\n    <div class=\"section\">\n      <div class=\"section-title\">Patrón: Monotonic Stack</div>\n\n      <div class=\"callout callout-blue\">\n        <strong>💡 Cuándo usar Monotonic Stack</strong>\n        Señales: \"siguiente mayor/menor elemento\", \"días hasta temperatura más alta\", \"área máxima en histograma\". El stack mantiene elementos en orden monotónico (creciente o decreciente). Cada elemento entra y sale del stack exactamente una vez → O(n).\n      </div>\n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Trapping Rain Water — 3 soluciones <span class=\"badge b-red\">Hard · Icónico</span></div>\n        </div><div class=\"concept-explain\">\n  <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n  <p><strong>¿Qué es esto?</strong> Tenemos un histograma y queremos saber cuánta agua quedaría atrapada si lloviera.</p>\n  <div class=\"analogy\">Como un balde: el volumen de agua en cada posición está rigurosamente limitado por el mínimo entre la pared más alta a su izquierda absoluta y la pared más alta a su derecha absoluta. Lo que importa es el lado más bajo.</div>\n  <div class=\"why-matters\">Sin esto computarías y buscarías máximos a I y D perdiendo O(N²). Precomputar ambos lados gasta O(N) espacio. Two Pointers baja el espacio magistralmente a O(1).</div>\n  \n  <p>Prestá atención a cómo comparamos max_left y max_right in-place letalmente desde ambos bordes.</p>\n</div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">trapping_rain.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"cm\"># Input: [0,1,0,2,1,0,1,3,2,1,2,1] → 6</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\"></span></div>\n            <div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\"><span class=\"cm\"># SOLUCIÓN 1: Precompute — O(n) time, O(n) space</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">trap_v1</span>(height):</span></div>\n            <div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    n = <span class=\"fn\">len</span>(height)</span></div>\n            <div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">    left_max = [<span class=\"nm\">0</span>] * n</span></div>\n            <div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">    right_max = [<span class=\"nm\">0</span>] * n</span></div>\n            <div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">    left_max[<span class=\"nm\">0</span>] = height[<span class=\"nm\">0</span>]</span></div>\n            <div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">    right_max[-<span class=\"nm\">1</span>] = height[-<span class=\"nm\">1</span>]</span></div>\n            <div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">    <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(<span class=\"nm\">1</span>, n):</span></div>\n            <div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">        left_max[i] = <span class=\"fn\">max</span>(left_max[i-<span class=\"nm\">1</span>], height[i])</span></div>\n            <div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">    <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(n-<span class=\"nm\">2</span>, -<span class=\"nm\">1</span>, -<span class=\"nm\">1</span>):</span></div>\n            <div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">        right_max[i] = <span class=\"fn\">max</span>(right_max[i+<span class=\"nm\">1</span>], height[i])</span></div>\n            <div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">    <span class=\"kw\">return</span> <span class=\"fn\">sum</span>(<span class=\"fn\">min</span>(left_max[i], right_max[i]) - height[i] <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(n))</span></div>\n            <div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\"></span></div>\n            <div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\"><span class=\"cm\"># SOLUCIÓN 2 (óptima): Two Pointers — O(n) time, O(1) space</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">trap_v2</span>(height):</span></div>\n            <div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">    left, right = <span class=\"nm\">0</span>, <span class=\"fn\">len</span>(height) - <span class=\"nm\">1</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\">    left_max = right_max = water = <span class=\"nm\">0</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\">    <span class=\"kw\">while</span> left &lt; right:</span></div>\n            <div class=\"cl\"><span class=\"ln\">21</span><span class=\"lc\">        <span class=\"kw\">if</span> height[left] &lt; height[right]:</span></div>\n            <div class=\"cl\"><span class=\"ln\">22</span><span class=\"lc\">            <span class=\"kw\">if</span> height[left] &gt;= left_max: left_max = height[left]</span></div>\n            <div class=\"cl\"><span class=\"ln\">23</span><span class=\"lc\">            <span class=\"kw\">else</span>: water += left_max - height[left]</span></div>\n            <div class=\"cl\"><span class=\"ln\">24</span><span class=\"lc\">            left += <span class=\"nm\">1</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">25</span><span class=\"lc\">        <span class=\"kw\">else</span>:</span></div>\n            <div class=\"cl\"><span class=\"ln\">26</span><span class=\"lc\">            <span class=\"kw\">if</span> height[right] &gt;= right_max: right_max = height[right]</span></div>\n            <div class=\"cl\"><span class=\"ln\">27</span><span class=\"lc\">            <span class=\"kw\">else</span>: water += right_max - height[right]</span></div>\n            <div class=\"cl\"><span class=\"ln\">28</span><span class=\"lc\">            right -= <span class=\"nm\">1</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">29</span><span class=\"lc\">    <span class=\"kw\">return</span> water</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>El agua en cada posición es <span class=\"c\">min(max_izquierda, max_derecha) - altura</span>. La solución v1 precomputa estos máximos. La <span class=\"cg\">solución v2 óptima</span> usa dos punteros — en cada paso procesamos el lado más bajo porque el lado más alto garantiza que ese es el techo real. Siempre presentá las dos en entrevista: la v1 primero para mostrar que entendés el problema, luego la v2 para mostrar que podés optimizar.</p>\n        </div>\n      </div>\n    </div>\n\n    <!-- ===================== HASH MAPS ===================== -->",
  "hashmaps": "<div id=\"hashmaps\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 05</div>\n      <h2>Hash Maps &amp; Sets</h2>\n      <p>La herramienta más poderosa para reducir complejidad. El tradeoff casi siempre es: más memoria → menos tiempo. Si un problema parece O(n²), probablemente tiene solución O(n) con un hash map.</p>\n    </div>\n\n    <div class=\"section\">\n      <div class=\"section-title\">Patrones fundamentales</div>\n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">LRU Cache — Hard de diseño clásico <span class=\"badge b-red\">Hard · O(1) get/put</span></div>\n        </div><div class=\"concept-explain\">\n  <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n  <p><strong>¿Qué es esto?</strong> Un cache es una zona reservada y cuando se llena, hay que desalojar inteligentemente al menos usado para meter datos frescos.</p>\n  <div class=\"analogy\">Tu escritorio de trabajo — tenés espacio limitado y ponés ahí las cosas que usás más seguido. Cuando el escritorio se llena, sacás lo que hace más tiempo no usás (LRU = Least Recently Used).</div>\n  <div class=\"why-matters\">¿Por qué DOS estructuras? Con solo un HashMap podríamos buscar pero no saber cuál es el menos reciente en O(1). Con solo una lista podríamos saber el orden pero no buscar en O(1). Juntos dan poder O(1) total.</div>\n  \n  <p>Mirá la combinación magistral de dict() anclando la Doubly Linked List circular directamente.</p>\n</div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">lru_cache.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"cm\"># HashMap + Doubly Linked List = O(1) get y put</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\"><span class=\"kw\">class</span> <span class=\"cl2\">LRUNode</span>:</span></div>\n            <div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">__init__</span>(self, key, val):</span></div>\n            <div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">        self.key, self.val = key, val</span></div>\n            <div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">        self.prev = self.next = <span class=\"kw\">None</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\"></span></div>\n            <div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\"><span class=\"kw\">class</span> <span class=\"cl2\">LRUCache</span>:</span></div>\n            <div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">__init__</span>(self, capacity):</span></div>\n            <div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">        self.capacity = capacity</span></div>\n            <div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">        self.cache = {}  <span class=\"cm\"># key → node</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">        self.head = <span class=\"cl2\">LRUNode</span>(<span class=\"nm\">0</span>, <span class=\"nm\">0</span>)  <span class=\"cm\"># dummy head = más viejo</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">        self.tail = <span class=\"cl2\">LRUNode</span>(<span class=\"nm\">0</span>, <span class=\"nm\">0</span>)  <span class=\"cm\"># dummy tail = más reciente</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">        self.head.next = self.tail</span></div>\n            <div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">        self.tail.prev = self.head</span></div>\n            <div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\"></span></div>\n            <div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">_remove</span>(self, node):</span></div>\n            <div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">        node.prev.next = node.next</span></div>\n            <div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">        node.next.prev = node.prev</span></div>\n            <div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\"></span></div>\n            <div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">_insert_mru</span>(self, node):  <span class=\"cm\"># insertar antes del tail</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">21</span><span class=\"lc\">        prev = self.tail.prev</span></div>\n            <div class=\"cl\"><span class=\"ln\">22</span><span class=\"lc\">        prev.next = node; node.prev = prev</span></div>\n            <div class=\"cl\"><span class=\"ln\">23</span><span class=\"lc\">        node.next = self.tail; self.tail.prev = node</span></div>\n            <div class=\"cl\"><span class=\"ln\">24</span><span class=\"lc\"></span></div>\n            <div class=\"cl\"><span class=\"ln\">25</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">get</span>(self, key):</span></div>\n            <div class=\"cl\"><span class=\"ln\">26</span><span class=\"lc\">        <span class=\"kw\">if</span> key <span class=\"kw\">not in</span> self.cache: <span class=\"kw\">return</span> -<span class=\"nm\">1</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">27</span><span class=\"lc\">        node = self.cache[key]</span></div>\n            <div class=\"cl\"><span class=\"ln\">28</span><span class=\"lc\">        self.<span class=\"fn\">_remove</span>(node); self.<span class=\"fn\">_insert_mru</span>(node)  <span class=\"cm\"># mover al frente</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">29</span><span class=\"lc\">        <span class=\"kw\">return</span> node.val</span></div>\n            <div class=\"cl\"><span class=\"ln\">30</span><span class=\"lc\"></span></div>\n            <div class=\"cl\"><span class=\"ln\">31</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">put</span>(self, key, val):</span></div>\n            <div class=\"cl\"><span class=\"ln\">32</span><span class=\"lc\">        <span class=\"kw\">if</span> key <span class=\"kw\">in</span> self.cache: self.<span class=\"fn\">_remove</span>(self.cache[key])</span></div>\n            <div class=\"cl\"><span class=\"ln\">33</span><span class=\"lc\">        node = <span class=\"cl2\">LRUNode</span>(key, val)</span></div>\n            <div class=\"cl\"><span class=\"ln\">34</span><span class=\"lc\">        self.cache[key] = node; self.<span class=\"fn\">_insert_mru</span>(node)</span></div>\n            <div class=\"cl\"><span class=\"ln\">35</span><span class=\"lc\">        <span class=\"kw\">if</span> <span class=\"fn\">len</span>(self.cache) &gt; self.capacity:</span></div>\n            <div class=\"cl\"><span class=\"ln\">36</span><span class=\"lc\">            lru = self.head.next  <span class=\"cm\"># el más viejo: justo después del head</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">37</span><span class=\"lc\">            self.<span class=\"fn\">_remove</span>(lru); <span class=\"kw\">del</span> self.cache[lru.key]</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>LRU Cache combina un <span class=\"cg\">HashMap</span> para acceso O(1) por key con una <span class=\"c\">Doubly Linked List</span> para mantener el orden de uso en O(1). Los <span class=\"c\">dummy nodes</span> head y tail eliminan casos especiales al insertar y remover. El nodo más reciente siempre está cerca del tail, el menos reciente cerca del head — al exceder la capacidad, eliminamos el que está junto al head.</p>\n        </div>\n      </div>\n    </div>\n\n    <!-- ===================== TREES ===================== -->",
  "trees": "<div id=\"trees\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 06</div>\n      <h2>Árboles Binarios y BST</h2>\n      <p>Los árboles aparecen en Easy, Medium y Hard. El 90% de los problemas se resuelven con DFS recursivo o BFS iterativo. Dominá los traversals y los patrones básicos antes de ir a grafos.</p>\n    </div>\n\n    <div class=\"section\">\n      <div class=\"section-title\">Traversals y patrones DFS</div>\n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Max Path Sum — Hard icónico <span class=\"badge b-red\">Hard · O(n)</span></div>\n        </div><div class=\"concept-explain\">\n  <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n  <p><strong>¿Qué es esto?</strong> En un árbol, un 'path' es cualquier secuencia de nodos conectados sin repetir. Puede ir de hoja a hoja pasando por cualquier nodo.</p>\n  <div class=\"analogy\">La cañería principal: el agua puede subir y bajar cruzando el codo principal invertido (arco), pero la raíz solo puede elegir mandar su flujo a UNA de las cañerías para su propio padre superior.</div>\n  <div class=\"why-matters\">El DFS responde DOS preguntas distintas: '¿cuál es el mejor path que PASA por mí?' (para actualizar el máximo global) y '¿cuánto puedo CONTRIBUIR a mi padre?' (retorno). El padre no puede 'doblar' también.</div>\n  \n  <p>Aquí vas a notar la bifurcación: res[0] se actualiza con la suma de ambos brazos, pero el return envía solo un brazo máximo al padre.</p>\n</div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">max_path_sum.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"cm\"># El path puede empezar y terminar en CUALQUIER nodo</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">max_path_sum</span>(root):</span></div>\n            <div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    max_sum = [<span class=\"fn\">float</span>(<span class=\"st\">\"-inf\"</span>)]</span></div>\n            <div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">dfs</span>(node):</span></div>\n            <div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">        <span class=\"kw\">if not</span> node: <span class=\"kw\">return</span> <span class=\"nm\">0</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">        <span class=\"cm\"># Ignorar contribuciones negativas (tomar max con 0)</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">        left = <span class=\"fn\">max</span>(<span class=\"fn\">dfs</span>(node.left), <span class=\"nm\">0</span>)</span></div>\n            <div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">        right = <span class=\"fn\">max</span>(<span class=\"fn\">dfs</span>(node.right), <span class=\"nm\">0</span>)</span></div>\n            <div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">        <span class=\"cm\"># Precio del path que pasa por este nodo como \"puente\"</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">        max_sum[<span class=\"nm\">0</span>] = <span class=\"fn\">max</span>(max_sum[<span class=\"nm\">0</span>], node.val + left + right)</span></div>\n            <div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">        <span class=\"cm\"># Solo retornar un lado al padre (no puede doblar)</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">        <span class=\"kw\">return</span> node.val + <span class=\"fn\">max</span>(left, right)</span></div>\n            <div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">    <span class=\"fn\">dfs</span>(root)</span></div>\n            <div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">    <span class=\"kw\">return</span> max_sum[<span class=\"nm\">0</span>]</span></div>\n            <div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\"></span></div>\n            <div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\"><span class=\"cm\"># BFS — Level Order Traversal</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\"><span class=\"kw\">from</span> collections <span class=\"kw\">import</span> deque</span></div>\n            <div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">level_order</span>(root):</span></div>\n            <div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\">    <span class=\"kw\">if not</span> root: <span class=\"kw\">return</span> []</span></div>\n            <div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\">    result, queue = [], deque([root])</span></div>\n            <div class=\"cl\"><span class=\"ln\">21</span><span class=\"lc\">    <span class=\"kw\">while</span> queue:</span></div>\n            <div class=\"cl\"><span class=\"ln\">22</span><span class=\"lc\">        level = []</span></div>\n            <div class=\"cl\"><span class=\"ln\">23</span><span class=\"lc\">        <span class=\"kw\">for</span> _ <span class=\"kw\">in</span> <span class=\"fn\">range</span>(<span class=\"fn\">len</span>(queue)):  <span class=\"cm\"># procesar un nivel completo</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">24</span><span class=\"lc\">            node = queue.popleft()</span></div>\n            <div class=\"cl\"><span class=\"ln\">25</span><span class=\"lc\">            level.append(node.val)</span></div>\n            <div class=\"cl\"><span class=\"ln\">26</span><span class=\"lc\">            <span class=\"kw\">if</span> node.left: queue.append(node.left)</span></div>\n            <div class=\"cl\"><span class=\"ln\">27</span><span class=\"lc\">            <span class=\"kw\">if</span> node.right: queue.append(node.right)</span></div>\n            <div class=\"cl\"><span class=\"ln\">28</span><span class=\"lc\">        result.append(level)</span></div>\n            <div class=\"cl\"><span class=\"ln\">29</span><span class=\"lc\">    <span class=\"kw\">return</span> result</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>El truco del Max Path Sum: la función DFS tiene <strong>dos trabajos</strong>. Internamente actualiza el máximo global considerando el path que dobla por el nodo actual (<span class=\"c\">left + node + right</span>). Pero lo que retorna al padre es solo la mejor contribución unilateral (<span class=\"c\">node + max(left, right)</span>) porque un path no puede doblar. El <span class=\"cg\">max con 0</span> descarta ramas negativas — si suman menos que nada, mejor no tomarlas.</p>\n        </div>\n      </div>\n    </div>\n\n    <!-- ===================== GRAPHS ===================== -->",
  "graphs": "<div id=\"graphs\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 07</div>\n      <h2>Grafos — DFS, BFS, Union Find, Dijkstra</h2>\n      <p>El tema más amplio y difícil. Dominarlo te pone en posición de resolver cualquier Hard relacionado con conexiones, caminos o dependencias.</p>\n    </div>\n\n    <div class=\"section\">\n      <div class=\"section-title\">Patrones esenciales</div>\n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Union Find — conectividad en O(1) amortizado <span class=\"badge b-purple\">Hard pattern</span></div>\n        </div><div class=\"concept-explain\">\n  <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n  <p><strong>¿Qué es esto?</strong> Un grafo de componentes conectadas. Responde en O(1) amortizado: '¿estas dos personas están en el mismo grupo?'</p>\n  <div class=\"analogy\">Grupos de personas donde sabés si dos se conocen. Cada componente tiene un representante (root). Dos nodos están conectados si y solo si reportan al mismo putísimo Root.</div>\n  <div class=\"why-matters\">Sin la 'Path compression', los árboles degeneran en líneas O(N). Cuando buscás al rep de A y pasás por B y C, al final hacés que A apunte DIRECTO al representante acortando recorridos.</div>\n  \n  <p>Encontrarás los famosos métodos find() recursivo apretando paths, y union() fundiendo ranks.</p>\n</div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">union_find.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">class</span> <span class=\"cl2\">UnionFind</span>:</span></div>\n            <div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">__init__</span>(self, n):</span></div>\n            <div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">        self.parent = <span class=\"fn\">list</span>(<span class=\"fn\">range</span>(n))  <span class=\"cm\"># cada nodo es su propio padre</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">        self.rank = [<span class=\"nm\">0</span>] * n</span></div>\n            <div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">        self.components = n</span></div>\n            <div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\"></span></div>\n            <div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">find</span>(self, x):  <span class=\"cm\"># con path compression</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">        <span class=\"kw\">if</span> self.parent[x] != x:</span></div>\n            <div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">            self.parent[x] = self.<span class=\"fn\">find</span>(self.parent[x])</span></div>\n            <div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">        <span class=\"kw\">return</span> self.parent[x]</span></div>\n            <div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\"></span></div>\n            <div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">union</span>(self, x, y):  <span class=\"cm\"># con union by rank</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">        px, py = self.<span class=\"fn\">find</span>(x), self.<span class=\"fn\">find</span>(y)</span></div>\n            <div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">        <span class=\"kw\">if</span> px == py: <span class=\"kw\">return</span> <span class=\"kw\">False</span>  <span class=\"cm\"># ya conectados</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">        <span class=\"kw\">if</span> self.rank[px] &lt; self.rank[py]: px, py = py, px</span></div>\n            <div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">        self.parent[py] = px</span></div>\n            <div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">        <span class=\"kw\">if</span> self.rank[px] == self.rank[py]: self.rank[px] += <span class=\"nm\">1</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">        self.components -= <span class=\"nm\">1</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\">        <span class=\"kw\">return</span> <span class=\"kw\">True</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\"></span></div>\n            <div class=\"cl\"><span class=\"ln\">21</span><span class=\"lc\"><span class=\"cm\"># Dijkstra — camino más corto ponderado</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">22</span><span class=\"lc\"><span class=\"kw\">import</span> heapq</span></div>\n            <div class=\"cl\"><span class=\"ln\">23</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">dijkstra</span>(graph, start, n):  <span class=\"cm\"># graph[u] = [(w, v), ...]</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">24</span><span class=\"lc\">    dist = [<span class=\"fn\">float</span>(<span class=\"st\">\"inf\"</span>)] * n</span></div>\n            <div class=\"cl\"><span class=\"ln\">25</span><span class=\"lc\">    dist[start] = <span class=\"nm\">0</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">26</span><span class=\"lc\">    heap = [(<span class=\"nm\">0</span>, start)]</span></div>\n            <div class=\"cl\"><span class=\"ln\">27</span><span class=\"lc\">    <span class=\"kw\">while</span> heap:</span></div>\n            <div class=\"cl\"><span class=\"ln\">28</span><span class=\"lc\">        d, u = heapq.heappop(heap)</span></div>\n            <div class=\"cl\"><span class=\"ln\">29</span><span class=\"lc\">        <span class=\"kw\">if</span> d &gt; dist[u]: <span class=\"kw\">continue</span>  <span class=\"cm\"># nodo obsoleto</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">30</span><span class=\"lc\">        <span class=\"kw\">for</span> w, v <span class=\"kw\">in</span> graph[u]:</span></div>\n            <div class=\"cl\"><span class=\"ln\">31</span><span class=\"lc\">            <span class=\"kw\">if</span> dist[u] + w &lt; dist[v]:</span></div>\n            <div class=\"cl\"><span class=\"ln\">32</span><span class=\"lc\">                dist[v] = dist[u] + w</span></div>\n            <div class=\"cl\"><span class=\"ln\">33</span><span class=\"lc\">                heapq.heappush(heap, (dist[v], v))</span></div>\n            <div class=\"cl\"><span class=\"ln\">34</span><span class=\"lc\">    <span class=\"kw\">return</span> dist</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p><strong>Union Find</strong> con <span class=\"cg\">path compression</span> (línea 9) y <span class=\"cg\">union by rank</span> (línea 15) tiene complejidad casi O(1) por operación. Usalo cuando el problema pregunta sobre componentes conexas o si dos nodos están conectados. <strong>Dijkstra</strong> resuelve el camino más corto en grafos ponderados con pesos positivos. El <span class=\"c\">if d &gt; dist[u]: continue</span> es crítico — descarta nodos procesados con mayor distancia que ya encontramos una ruta mejor.</p>\n        </div>\n      </div>\n    </div>\n\n    <!-- ===================== HEAPS ===================== -->",
  "heaps": "<div id=\"heaps\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 08</div>\n      <h2>Heaps &amp; Priority Queues</h2>\n      <p>Un Heap garantiza O(log n) para insertar/eliminar y O(1) para ver el mínimo/máximo. Python solo tiene min-heap — para max-heap se negan los valores.</p>\n    </div>\n\n    <div class=\"section\">\n      <div class=\"section-title\">Patrones con Heap</div>\n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Find Median from Data Stream <span class=\"badge b-red\">Hard · O(log n)</span></div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">median_stream.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"cm\"># Dos heaps: small (max-heap) guarda mitad inferior</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\"><span class=\"cm\">#            large (min-heap) guarda mitad superior</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\"><span class=\"kw\">import</span> heapq</span></div>\n            <div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\"><span class=\"kw\">class</span> <span class=\"cl2\">MedianFinder</span>:</span></div>\n            <div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">__init__</span>(self):</span></div>\n            <div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">        self.small = []  <span class=\"cm\"># max-heap (negados)</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">        self.large = []  <span class=\"cm\"># min-heap</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\"></span></div>\n            <div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">addNum</span>(self, num):</span></div>\n            <div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">        heapq.heappush(self.small, -num)</span></div>\n            <div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">        <span class=\"cm\"># Balancear: max(small) debe ser &lt;= min(large)</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">        <span class=\"kw\">if</span> self.small <span class=\"kw\">and</span> self.large <span class=\"kw\">and</span> (-self.small[<span class=\"nm\">0</span>] &gt; self.large[<span class=\"nm\">0</span>]):</span></div>\n            <div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">            heapq.heappush(self.large, -heapq.heappop(self.small))</span></div>\n            <div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">        <span class=\"cm\"># Balancear tamaños (small puede tener 1 más)</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">        <span class=\"kw\">if</span> <span class=\"fn\">len</span>(self.small) &gt; <span class=\"fn\">len</span>(self.large) + <span class=\"nm\">1</span>:</span></div>\n            <div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">            heapq.heappush(self.large, -heapq.heappop(self.small))</span></div>\n            <div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">        <span class=\"kw\">if</span> <span class=\"fn\">len</span>(self.large) &gt; <span class=\"fn\">len</span>(self.small):</span></div>\n            <div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">            heapq.heappush(self.small, -heapq.heappop(self.large))</span></div>\n            <div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\"></span></div>\n            <div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">findMedian</span>(self):</span></div>\n            <div class=\"cl\"><span class=\"ln\">21</span><span class=\"lc\">        <span class=\"kw\">if</span> <span class=\"fn\">len</span>(self.small) &gt; <span class=\"fn\">len</span>(self.large):</span></div>\n            <div class=\"cl\"><span class=\"ln\">22</span><span class=\"lc\">            <span class=\"kw\">return</span> -self.small[<span class=\"nm\">0</span>]</span></div>\n            <div class=\"cl\"><span class=\"ln\">23</span><span class=\"lc\">        <span class=\"kw\">return</span> (-self.small[<span class=\"nm\">0</span>] + self.large[<span class=\"nm\">0</span>]) / <span class=\"nm\">2</span></span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Dos heaps particionan el stream en dos mitades iguales. <span class=\"cg\">small</span> guarda la mitad inferior (máximo accesible en O(1)), <span class=\"cg\">large</span> guarda la mitad superior (mínimo accesible en O(1)). La invariante clave: el máximo de small debe ser ≤ al mínimo de large, y los tamaños difieren a lo sumo en 1. La mediana es entonces trivial: si son iguales, promedio de los dos topes; si no, el tope del más grande.</p>\n        </div>\n      </div>\n    </div>\n\n    <!-- ===================== BINARY SEARCH ===================== -->\n    <div id=\"dp\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 09</div>\n      <h2>Dynamic Programming</h2>\n      <p>El tema más difícil y el más importante para Hard. La clave es reconocer el patrón, definir el estado, y escribir la recurrencia. Con práctica se vuelve sistemático.</p>\n    </div>\n\n    <div class=\"section\">\n      <div class=\"section-title\">Framework para resolver cualquier DP</div>\n\n      <div class=\"callout callout-yellow\">\n        <strong>🧠 Las 4 preguntas que siempre hacerse</strong>\n        1. ¿El problema tiene <strong>subproblemas solapados</strong>? (se repiten los mismos cálculos)<br>\n        2. ¿Tiene <strong>subestructura óptima</strong>? (solución óptima usa soluciones óptimas de subproblemas)<br>\n        3. ¿Cuál es el <strong>estado</strong>? (qué variables definen completamente un subproblema)<br>\n        4. ¿Cuál es la <strong>transición</strong>? (cómo pasar de subproblemas pequeños al actual)\n      </div>\n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Coin Change — DP clásico <span class=\"badge b-yellow\">Medium · O(n·amount)</span></div>\n        </div><div class=\"concept-explain\">\n  <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n  <p><strong>¿Qué es esto?</strong> Dynamic Programming evita regenerar trabajo muerto asqueroso. Construye respuestas Bottom-Up metódicamente letales o cacheando ciegos (Top-down).</p>\n  <div class=\"analogy\">Calcular fib(5) llama ciegamente a fib(4) y fib(3) cien veces sin sentido. Tabulation anota las piezas minúsculas fúlgidas: 'Si ya sé cómo llegar hermosamente a 8 y tengo moneda 3, llegaré ciegamente a 11 en (monedas_8 + 1) letales pasos'.</div>\n  <div class=\"why-matters\">Un Array dp[i] almacena la rta puritana inmejorable para cada mini-monto del 0 al target pacíficamente reduciendo O(exponencial) a letal y bello O(Amount * N).</div>\n  \n  <p>Verás letalmente incrustados un doble loop estúpido mágico puritano que rellena implacablemente las celdas progresivas.</p>\n</div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">coin_change.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"cm\"># Mínimas monedas para llegar a amount</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\"><span class=\"cm\"># Input: coins=[1,5,11], amount=15 → 3 (5+5+5)</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">coin_change</span>(coins, amount):</span></div>\n            <div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    <span class=\"cm\"># dp[i] = mínimas monedas para llegar a i</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    dp = [<span class=\"fn\">float</span>(<span class=\"st\">\"inf\"</span>)] * (amount + <span class=\"nm\">1</span>)</span></div>\n            <div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">    dp[<span class=\"nm\">0</span>] = <span class=\"nm\">0</span>  <span class=\"cm\"># base case: 0 monedas para llegar a 0</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">    <span class=\"kw\">for</span> coin <span class=\"kw\">in</span> coins:</span></div>\n            <div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">        <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(coin, amount + <span class=\"nm\">1</span>):</span></div>\n            <div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">            <span class=\"cm\"># Transición: usar esta moneda o no usarla</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">            dp[i] = <span class=\"fn\">min</span>(dp[i], dp[i - coin] + <span class=\"nm\">1</span>)</span></div>\n            <div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">    <span class=\"kw\">return</span> dp[amount] <span class=\"kw\">if</span> dp[amount] != <span class=\"fn\">float</span>(<span class=\"st\">\"inf\"</span>) <span class=\"kw\">else</span> -<span class=\"nm\">1</span></span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p><strong>Estado:</strong> <span class=\"c\">dp[i]</span> = mínimas monedas para llegar exactamente a <span class=\"c\">i</span>. <strong>Transición:</strong> para cada moneda, si podemos usarla (<span class=\"cg\">i &gt;= coin</span>), podemos llegar a <span class=\"c\">i</span> desde <span class=\"c\">i-coin</span> usando 1 moneda más. <strong>Base case:</strong> <span class=\"cg\">dp[0] = 0</span> porque no necesitamos monedas para llegar a 0. Es un knapsack <em>unbounded</em> (las monedas se pueden usar múltiples veces).</p>\n        </div>\n      </div>\n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Edit Distance — DP 2D <span class=\"badge b-red\">Hard · O(m×n)</span></div>\n        </div><div class=\"concept-explain\">\n  <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n  <p><strong>¿Qué es esto?</strong> dp[i][j] representa convertir los primeros i char de word1 en j de word2 fieramente mágico exultante.</p>\n  <div class=\"analogy\">Piénsalo asilado mágicamente como un tablero mágico 2D. Tenés una varita mágica: Insert, Delete o Reempazar. Elegís implacable siempre el trayecto asquerosamente fiero más barato.</div>\n  <div class=\"why-matters\">Sin DP asilado mágico exóticamente letal la recursividad explotaría pura O(3^N). Tabulation mágicamente reduce todo pacíficamente exultante asombroso a letal fiero O(M*N).</div>\n  \n  <p>Observarás maravillosamente un Grid matrix mágico puro puritano poblándose diagonal fiera y ortogonal asilada maravillosamente exótica fieramente letal puro paz.</p>\n</div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">edit_distance.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"cm\"># Mínimas ops (insert, delete, replace) para convertir word1 en word2</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\"><span class=\"cm\"># Input: \"horse\" → \"ros\" = 3 ops</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">min_distance</span>(word1, word2):</span></div>\n            <div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    m, n = <span class=\"fn\">len</span>(word1), <span class=\"fn\">len</span>(word2)</span></div>\n            <div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    dp = [[<span class=\"nm\">0</span>] * (n + <span class=\"nm\">1</span>) <span class=\"kw\">for</span> _ <span class=\"kw\">in</span> <span class=\"fn\">range</span>(m + <span class=\"nm\">1</span>)]</span></div>\n            <div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">    <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(m + <span class=\"nm\">1</span>): dp[i][<span class=\"nm\">0</span>] = i  <span class=\"cm\"># delete todo word1</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">    <span class=\"kw\">for</span> j <span class=\"kw\">in</span> <span class=\"fn\">range</span>(n + <span class=\"nm\">1</span>): dp[<span class=\"nm\">0</span>][j] = j  <span class=\"cm\"># insert todo word2</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">    <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(<span class=\"nm\">1</span>, m + <span class=\"nm\">1</span>):</span></div>\n            <div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">        <span class=\"kw\">for</span> j <span class=\"kw\">in</span> <span class=\"fn\">range</span>(<span class=\"nm\">1</span>, n + <span class=\"nm\">1</span>):</span></div>\n            <div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">            <span class=\"kw\">if</span> word1[i-<span class=\"nm\">1</span>] == word2[j-<span class=\"nm\">1</span>]:  <span class=\"cm\"># mismo char = gratis</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">                dp[i][j] = dp[i-<span class=\"nm\">1</span>][j-<span class=\"nm\">1</span>]</span></div>\n            <div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">            <span class=\"kw\">else</span>:</span></div>\n            <div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">                dp[i][j] = <span class=\"nm\">1</span> + <span class=\"fn\">min</span>(</span></div>\n            <div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">                    dp[i-<span class=\"nm\">1</span>][j],    <span class=\"cm\"># delete</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">                    dp[i][j-<span class=\"nm\">1</span>],    <span class=\"cm\"># insert</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">                    dp[i-<span class=\"nm\">1</span>][j-<span class=\"nm\">1</span>]   <span class=\"cm\"># replace</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">                )</span></div>\n            <div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">    <span class=\"kw\">return</span> dp[m][n]</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p><strong>Estado:</strong> <span class=\"c\">dp[i][j]</span> = mínimas operaciones para convertir <span class=\"c\">word1[:i]</span> en <span class=\"c\">word2[:j]</span>. <strong>Transición clave:</strong> si los chars son iguales, no cuesta nada (<span class=\"cg\">dp[i-1][j-1]</span>). Si son distintos, tomamos el mínimo de las 3 operaciones posibles más 1. <strong>Base cases:</strong> la primera fila/columna es la cantidad de inserciones/deletions necesarias para convertir el string vacío.</p>\n        </div>\n      </div>\n    </div>\n\n    <!-- BACKTRACKING -->\n    <div id=\"backtrack\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 10</div>\n      <h2>Backtracking</h2>\n      <p>Búsqueda exhaustiva inteligente. Construye soluciones incrementalmente y \"deshace\" cuando llega a un callejón sin salida.</p>\n    </div>\n\n    <div class=\"section\">\n      <div class=\"section-title\">Template universal</div>\n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">N-Queens — el problema clásico <span class=\"badge b-red\">Hard</span></div>\n        </div><div class=\"concept-explain\">\n  <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n  <p><strong>¿Qué es esto?</strong> Es el núcleo de Backtracking: 'fuerza bruta excepcionalmente inteligente de poda letal fúlgida pura'.</p>\n  <div class=\"analogy\">Piénsalo fiero mágicamente al caminar por un laberinto letal fúnebre virginal pacifista magistral: en lugar exótico puritano asqueroso de estrellarte 1 millón de veces exultante fiero paz en la misma maldita pared asilada fúlgida estelar asombrosamente letargo mágico puritano magistral virgen asombrosa, lo detectás a un metro letal y abandonás brutal fieramente esa asquerosa asilada rama exótica fúlgida letal estelar puritana paz maravillosa.</div>\n  <div class=\"why-matters\">Sin backtracking probaríamos N^(N-1) burradas de fuerza exultantemente fúnebre puritana bruta fúlgida letargo asombroso pura magistral. Evaluando mágicamente validez estricta parcial fiera pura mágico reducís brutal exultantemente mágica letal letargo pura paz virginal asombrosa fieramente a tiempo usable lógico puro paz.</div>\n  \n  <p>Comtemplarás fieramente el patrón maestro 'coloco pieza, hago recursion ciego pura letal fiera asombrosa mágico pacífica puritano, retiro la pieza (backtrack fúnebre puro) magistral'.</p>\n</div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">n_queens.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">solve_n_queens</span>(n):</span></div>\n            <div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    result = []</span></div>\n            <div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    cols = <span class=\"fn\">set</span>()      <span class=\"cm\"># columnas con reina</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    diag1 = <span class=\"fn\">set</span>()    <span class=\"cm\"># diagonales \\ (row-col)</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    diag2 = <span class=\"fn\">set</span>()    <span class=\"cm\"># diagonales / (row+col)</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">    board = [[<span class=\"st\">\".\"</span>]*n <span class=\"kw\">for</span> _ <span class=\"kw\">in</span> <span class=\"fn\">range</span>(n)]</span></div>\n            <div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\"></span></div>\n            <div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">backtrack</span>(row):</span></div>\n            <div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">        <span class=\"kw\">if</span> row == n:  <span class=\"cm\"># solución completa</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">            result.<span class=\"fn\">append</span>([<span class=\"st\">\"\"</span>.<span class=\"fn\">join</span>(r) <span class=\"kw\">for</span> r <span class=\"kw\">in</span> board])</span></div>\n            <div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">            <span class=\"kw\">return</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">        <span class=\"kw\">for</span> col <span class=\"kw\">in</span> <span class=\"fn\">range</span>(n):</span></div>\n            <div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">            <span class=\"kw\">if</span> col <span class=\"kw\">in</span> cols <span class=\"kw\">or</span> (row-col) <span class=\"kw\">in</span> diag1 <span class=\"kw\">or</span> (row+col) <span class=\"kw\">in</span> diag2:</span></div>\n            <div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">                <span class=\"kw\">continue</span>  <span class=\"cm\"># posición atacada, skip</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">            <span class=\"cm\"># ELEGIR: colocar reina</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">            board[row][col] = <span class=\"st\">\"Q\"</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">            cols.<span class=\"fn\">add</span>(col); diag1.<span class=\"fn\">add</span>(row-col); diag2.<span class=\"fn\">add</span>(row+col)</span></div>\n            <div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">            <span class=\"cm\"># EXPLORAR: siguiente fila</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\">            <span class=\"fn\">backtrack</span>(row + <span class=\"nm\">1</span>)</span></div>\n            <div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\">            <span class=\"cm\"># DESHACER: quitar reina (backtrack)</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">21</span><span class=\"lc\">            board[row][col] = <span class=\"st\">\".\"</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">22</span><span class=\"lc\">            cols.<span class=\"fn\">remove</span>(col); diag1.<span class=\"fn\">remove</span>(row-col); diag2.<span class=\"fn\">remove</span>(row+col)</span></div>\n            <div class=\"cl\"><span class=\"ln\">23</span><span class=\"lc\"></span></div>\n            <div class=\"cl\"><span class=\"ln\">24</span><span class=\"lc\">    <span class=\"fn\">backtrack</span>(<span class=\"nm\">0</span>)</span></div>\n            <div class=\"cl\"><span class=\"ln\">25</span><span class=\"lc\">    <span class=\"kw\">return</span> result</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>El template de backtracking siempre tiene 3 pasos: <span class=\"cg\">ELEGIR</span> (agregar al estado), <span class=\"c\">EXPLORAR</span> (llamada recursiva), <span class=\"cr\">DESHACER</span> (quitar del estado). Usamos <span class=\"c\">sets</span> para las columnas y diagonales para verificar ataques en <span class=\"cg\">O(1)</span>. La poda en línea 13 elimina ramas inválidas tempranamente, lo que hace el algoritmo práctico para n ≤ 9.</p>\n        </div>\n      </div>\n    </div>\n\n    <!-- SIMULACRO -->\n\n    <!-- ===================== LINKED LISTS ===================== -->\n    <div id=\"bsearch\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 11</div>\n      <h2>Binary Search</h2>\n      <p>Binary Search no es solo para arrays ordenados. El patrón se aplica a cualquier espacio de búsqueda monótono — si una condición es True para X, es True para todos los mayores.</p>\n    </div>\n\n    <div class=\"section\">\n      <div class=\"section-title\">Binary Search en el espacio de respuestas</div>\n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Koko Eating Bananas — patrón avanzado <span class=\"badge b-yellow\">Medium/Hard · O(n log m)</span></div>\n        </div><div class=\"concept-explain\">\n  <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n  <p><strong>¿Qué es esto?</strong> Una maravilla letal fiera magistral asombrosa mágica pacíficamente pura exultante asquerosa que Binary Search mágico evalúa puro asqueroso asilado un letargo exótico 'rango de respuestas feroz puro puritana'.</p>\n  <div class=\"analogy\">En lugar asombrosamente fiero mágico letal virginal pacífico de iterar K de 1 a infinito asqueroso fúnebre puro asilado mágico pacífico para ver maravillosamente a qué maldita fiera velocidad estúpida K koko se traga exóticamente majestuosamente magistral puro pacífico estelar letal las bananas virgen puro, tiras fiero exultantemente asombrosamente un mágico letal binary search ciego puro pacíficamente exótico en el maldito puro asquerosamente rango de velocidades majestuosas fieras asombrosas pacíficamente de 1 a Max.</div>\n  <div class=\"why-matters\">Convierte O(MaxSpeed * N) letal mente mágico pacífico asombroso exultantemente fiero de pura fuerza bruta asilada maravillosa fúlgida en el exótico veloz fiero inalcanzable puro O(N * Log(MaxSpeed)) asombrosa puritana pacíficamente letal hermosísima magia.</div>\n  \n  <p>Atenderás asombrosamente el check mid mágico puritano virgen hermoso puro fiero y el estrechamiento implacable letal de rigth/left estelares.</p>\n</div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">binary_search_answer.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"cm\"># Mínima velocidad k para comer todas las bananas en H horas</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\"><span class=\"cm\"># piles=[3,6,7,11], h=8 → 4</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\"><span class=\"kw\">import</span> math</span></div>\n            <div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">min_eating_speed</span>(piles, h):</span></div>\n            <div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">can_finish</span>(speed):  <span class=\"cm\"># ¿puede comer todo en h horas?</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">        <span class=\"kw\">return</span> <span class=\"fn\">sum</span>(math.<span class=\"fn\">ceil</span>(p / speed) <span class=\"kw\">for</span> p <span class=\"kw\">in</span> piles) &lt;= h</span></div>\n            <div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">    <span class=\"cm\"># Búsqueda binaria sobre el espacio de velocidades [1, max(piles)]</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">    left, right = <span class=\"nm\">1</span>, <span class=\"fn\">max</span>(piles)</span></div>\n            <div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">    <span class=\"kw\">while</span> left &lt; right:</span></div>\n            <div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">        mid = (left + right) <span class=\"op\">//</span> <span class=\"nm\">2</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">        <span class=\"kw\">if</span> <span class=\"fn\">can_finish</span>(mid):</span></div>\n            <div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">            right = mid      <span class=\"cm\"># puede funcionar, buscar menor</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">        <span class=\"kw\">else</span>:</span></div>\n            <div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">            left = mid + <span class=\"nm\">1</span>   <span class=\"cm\"># muy lento, necesitamos más</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">    <span class=\"kw\">return</span> left</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>La clave del patrón: no buscamos en el array sino en el <strong>espacio de respuestas posibles</strong>. La función <span class=\"cg\">can_finish(speed)</span> es monótona — si puedo terminar a velocidad k, también puedo a k+1. Eso hace el espacio de búsqueda apto para binary search. Este patrón aplica a: \"mínimo tamaño de grupo\", \"mínimo tiempo\", \"capacidad mínima de barco\" — cualquier pregunta del tipo \"¿cuál es el mínimo X tal que sea posible?\"</p>\n        </div>\n      </div>\n    </div>\n    <div id=\"sim\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 13</div>\n      <h2>Simulacro — Problemas Hard</h2>\n      <p>Problemas Hard reales con soluciones completas. Intentá resolverlos solo antes de ver la solución.</p>\n    </div>\n\n    <div class=\"section\">\n      <div class=\"section-title\">Guía de patrones — señales en el enunciado</div>\n\n      <table class=\"tbl\">\n        <thead>\n          <tr><th>Señal en el enunciado</th><th>Patrón a usar</th></tr>\n        </thead>\n        <tbody>\n          <tr><td>\"Subarray contiguo, suma/máximo\"</td><td><code>Sliding Window</code> o <code>Prefix Sum</code></td></tr>\n          <tr><td>\"Par que suma X en array ordenado\"</td><td><code>Two Pointers</code></td></tr>\n          <tr><td>\"Camino más corto, grafo no ponderado\"</td><td><code>BFS</code></td></tr>\n          <tr><td>\"Camino más corto, grafo ponderado\"</td><td><code>Dijkstra + heap</code></td></tr>\n          <tr><td>\"Todas las combinaciones/permutaciones\"</td><td><code>Backtracking</code></td></tr>\n          <tr><td>\"Subproblemas repetidos, optimización\"</td><td><code>Dynamic Programming</code></td></tr>\n          <tr><td>\"K-ésimo mayor/menor\"</td><td><code>Heap de tamaño k</code> o <code>Quick Select</code></td></tr>\n          <tr><td>\"Buscar en espacio ordenado\"</td><td><code>Binary Search</code></td></tr>\n          <tr><td>\"Conectividad entre grupos\"</td><td><code>Union Find</code></td></tr>\n          <tr><td>\"Búsqueda de prefijos, palabras\"</td><td><code>Trie</code></td></tr>\n          <tr><td>\"Siguiente mayor elemento, temperaturas\"</td><td><code>Monotonic Stack</code></td></tr>\n          <tr><td>\"XOR, bits, potencias de 2\"</td><td><code>Bit Manipulation</code></td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"iq\">\n        <div class=\"iq-head\">\n          <span class=\"iq-num\">Hard 01</span>\n          <span class=\"iq-title\">Longest Increasing Path in Matrix</span>\n        </div>\n        <div class=\"iq-body\">\n          <div class=\"iq-q\">Dado un m×n integer matrix, retornar la longitud del camino creciente más largo. Podés moverte en 4 direcciones. No podés salir de la matriz.</div>\n          <div class=\"iq-a\">\n            <strong style=\"color: var(--accent2); font-size: 12px;\">✅ Patrón: DFS + Memoization</strong><br><br>\n            Estado: <code style=\"font-family:'JetBrains Mono',monospace;font-size:12px;background:#dbeafe;color:#1d4ed8;padding:1px 5px;border-radius:3px;\">dp[r][c]</code> = longitud del camino más largo empezando en (r,c).<br>\n            Transición: <code style=\"font-family:'JetBrains Mono',monospace;font-size:12px;background:#dbeafe;color:#1d4ed8;padding:1px 5px;border-radius:3px;\">dp[r][c] = 1 + max(dp de vecinos con valor mayor)</code>.<br>\n            Cada celda se calcula una sola vez gracias al memo → <strong>O(m×n)</strong> tiempo y espacio.\n          </div>\n        </div>\n      </div>\n\n      <div class=\"iq\">\n        <div class=\"iq-head\">\n          <span class=\"iq-num\">Hard 02</span>\n          <span class=\"iq-title\">Trapping Rain Water</span>\n        </div>\n        <div class=\"iq-body\">\n          <div class=\"iq-q\">Input: [0,1,0,2,1,0,1,3,2,1,2,1] → 6. Calcular cuánta agua queda atrapada.</div>\n          <div class=\"iq-a\">\n            <strong style=\"color: var(--accent2); font-size: 12px;\">✅ Tres enfoques (mencionar del peor al mejor)</strong><br><br>\n            <strong>O(n²):</strong> Para cada posición calcular max_left y max_right con loops → agua = min(max_left, max_right) - height[i].<br><br>\n            <strong>O(n) tiempo, O(n) espacio:</strong> Precomputar arrays left_max y right_max.<br><br>\n            <strong>O(n) tiempo, O(1) espacio (óptima):</strong> Two pointers. Mover el puntero del lado más bajo — la cantidad de agua en esa posición es <code style=\"font-family:'JetBrains Mono',monospace;font-size:12px;background:#dbeafe;color:#1d4ed8;padding:1px 5px;border-radius:3px;\">max_del_lado - height[i]</code>.\n          </div>\n        </div>\n      </div>\n\n      <div class=\"callout callout-green\">\n        <strong>🎯 Checklist para el día de la entrevista</strong>\n        ✅ Leé el problema completo antes de escribir una sola línea<br>\n        ✅ Clarificá constraints: ¿negativos? ¿input vacío? ¿duplicados?<br>\n        ✅ Pensá en voz alta — el entrevistador evalúa tu proceso, no solo la solución<br>\n        ✅ Empezá con brute force, mencioná su complejidad, luego optimizá<br>\n        ✅ Escribí código limpio con nombres descriptivos<br>\n        ✅ Testeá con el ejemplo, luego con edge cases: [], [1], todos iguales<br>\n        ✅ Analizá la complejidad final: time Y space<br>\n        ✅ Si te trabás, hablá: \"necesito O(1) para búsquedas → hash map\"\n      </div>\n    </div>\n\n  \n    <!-- MÓDULO: Topological Sort -->\n    <div id=\"topo\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 12</div>\n      <h2>Topological Sort</h2>\n      <p>Ordenar nodos de un grafo dirigido acíclico (DAG) tal que para cada arista u→v, u aparece antes que v. Fundamental para dependency resolution, build systems, y course scheduling.</p>\n    </div>\n    \n    <div class=\"section\">\n      <div class=\"section-title\">Los dos algoritmos</div>\n      \n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Kahn's Algorithm (BFS-based) <span class=\"badge b-green\">O(V+E) · BFS</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> Usar in-degree array: nodos con in-degree 0 van a la queue primero. Procesar cada nodo, decrementar el in-degree de sus vecinos, agregar a la queue si llegan a 0.</p>\n          <div class=\"analogy\">Cursar la universidad: solo podés cursar materias de las que ya aprobaste todas las correlativas (in-degree 0). Aprobás una, liberás las siguientes.</div>\n          <div class=\"why-matters\">Detectar ciclos es trivial: si al vaciar la queue extrajiste menos nodos que el total, hay un ciclo infinito imposible de resolver.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">kahns_algo.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">topological_sort</span>(numCourses, prerequisites):</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    adj = {i: [] <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(numCourses)}</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    indegree = [<span class=\"nm\">0</span>] * numCourses</span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    <span class=\"kw\">for</span> dest, src <span class=\"kw\">in</span> prerequisites:</span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">        adj[src].<span class=\"fn\">append</span>(dest)</span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">        indegree[dest] += <span class=\"nm\">1</span></span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">    queue = [i <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(numCourses) <span class=\"kw\">if</span> indegree[i] == <span class=\"nm\">0</span>]</span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">    topo_order = []</span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">    <span class=\"kw\">while</span> queue:</span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">        node = queue.<span class=\"fn\">pop</span>(<span class=\"nm\">0</span>)</span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">        topo_order.<span class=\"fn\">append</span>(node)</span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">        <span class=\"kw\">for</span> nei <span class=\"kw\">in</span> adj[node]:</span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">            indegree[nei] -= <span class=\"nm\">1</span></span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">            <span class=\"kw\">if</span> indegree[nei] == <span class=\"nm\">0</span>:</span></div><div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">                queue.<span class=\"fn\">append</span>(nei)</span></div><div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\">                </span></div><div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\">    <span class=\"kw\">return</span> topo_order <span class=\"kw\">if</span> <span class=\"fn\">len</span>(topo_order) == numCourses <span class=\"kw\">else</span> []</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Iterativo y seguro. <span class='cg'>O(V+E)</span> porque cada vértice y arista se visita una vez. Excelente para LeetCode 207 y 210 (Course Schedule).</p>\n        </div>\n      </div>\n      \n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">DFS-based Topological Sort <span class=\"badge b-purple\">O(V+E) · DFS</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> DFS recursivo normal pero con un giro innegociable: el nodo se agrega a la lista RESULTANTE **DESPUÉS** de visitar exhaustivamente todos y cada uno de sus vecinos.</p>\n          <div class=\"analogy\">Vestirse: DFS te hace ponerte los calcetines, pero te dice 'aún no anoto el calcetín hasta que me haya puesto el zapato'. Al final, invertís la lista para el orden correcto.</div>\n          <div class=\"why-matters\">Más limpio de escribir si ya estás pensando en DFS profundo o si la reconstrucción backwards es más natural para tu estado mental.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">dfs_topo.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">dfs_topo</span>(numCourses, prerequisites):</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    adj = {i: [] <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(numCourses)}</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    <span class=\"kw\">for</span> dest, src <span class=\"kw\">in</span> prerequisites:</span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">        adj[src].<span class=\"fn\">append</span>(dest)</span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">    visited = <span class=\"fn\">set</span>()</span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">    stack = []</span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">    cycle = <span class=\"fn\">set</span>()</span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">dfs</span>(node):</span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">        <span class=\"kw\">if</span> node <span class=\"kw\">in</span> cycle: <span class=\"kw\">return</span> <span class=\"kw\">False</span></span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">        <span class=\"kw\">if</span> node <span class=\"kw\">in</span> visited: <span class=\"kw\">return</span> <span class=\"kw\">True</span></span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">        cycle.<span class=\"fn\">add</span>(node)</span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">        <span class=\"kw\">for</span> nei <span class=\"kw\">in</span> adj[node]:</span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">            <span class=\"kw\">if</span> <span class=\"kw\">not</span> <span class=\"fn\">dfs</span>(nei): <span class=\"kw\">return</span> <span class=\"kw\">False</span></span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">        cycle.<span class=\"fn\">remove</span>(node)</span></div><div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\">        visited.<span class=\"fn\">add</span>(node)</span></div><div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\">        stack.<span class=\"fn\">append</span>(node) <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># POST-ORDER!</span></span></div><div class=\"cl\"><span class=\"ln\">21</span><span class=\"lc\">        <span class=\"kw\">return</span> <span class=\"kw\">True</span></span></div><div class=\"cl\"><span class=\"ln\">22</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">23</span><span class=\"lc\">    <span class=\"kw\">for</span> c <span class=\"kw\">in</span> <span class=\"fn\">range</span>(numCourses):</span></div><div class=\"cl\"><span class=\"ln\">24</span><span class=\"lc\">        <span class=\"kw\">if</span> <span class=\"kw\">not</span> <span class=\"fn\">dfs</span>(c): <span class=\"kw\">return</span> []</span></div><div class=\"cl\"><span class=\"ln\">25</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">26</span><span class=\"lc\">    <span class=\"kw\">return</span> stack[::-<span class=\"nm\">1</span>]</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Puro post-order traversal. Observá los <span class='cy'>tres estados</span> de visita (cycle, visited, unvisited) integrados hermosamente.</p>\n        </div>\n      </div>\n      \n    </div>\n    \n\n    <div class=\"section\">\n      <div class=\"section-title\">Variantes Hard</div>\n      \n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Alien Dictionary — LeetCode 269 <span class=\"badge b-red\">Hard</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> Derivar el orden del alfabeto cósmico derivado del orden de palabras. Comparás letras asimétricas adyacentes para inferir A -> B.</p>\n          <div class=\"analogy\">Sos arqueólogo y asumís que si 'canto' viene antes de 'caso', la 'n' viene antes de la 's' en ese idioma extinguido.</div>\n          <div class=\"why-matters\">El problema real NO es Topological Sort en sí, sino saber CÓMO exprimir los bordes lexicográficos ciegos para CONSTRUIR el adjacency list y lidiar con prefijos que rompan las reglas lógicas.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">alien.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">alienOrder</span>(words):</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    adj = {c: <span class=\"fn\">set</span>() <span class=\"kw\">for</span> w <span class=\"kw\">in</span> words <span class=\"kw\">for</span> c <span class=\"kw\">in</span> w}</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(<span class=\"fn\">len</span>(words) - <span class=\"nm\">1</span>):</span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">        w1, w2 = words[i], words[i + <span class=\"nm\">1</span>]</span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">        minLen = <span class=\"fn\">min</span>(<span class=\"fn\">len</span>(w1), <span class=\"fn\">len</span>(w2))</span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">        <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Edge case: prefix <span class=\"fn\">violation</span>(e.g. <span <span class=\"kw\">class</span>=\"st\">\"abc\"</span>, <span <span class=\"kw\">class</span>=\"st\">\"ab\"</span>)</span></span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">        <span class=\"kw\">if</span> <span class=\"fn\">len</span>(w1) &gt; <span class=\"fn\">len</span>(w2) <span class=\"kw\">and</span> w1[:minLen] == w2[:minLen]:</span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">            <span class=\"kw\">return</span> <span <span class=\"kw\">class</span>=\"st\">\"\"</span></span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">            </span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">        <span class=\"kw\">for</span> j <span class=\"kw\">in</span> <span class=\"fn\">range</span>(minLen):</span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">            <span class=\"kw\">if</span> w1[j] != w2[j]:</span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">                adj[w1[j]].<span class=\"fn\">add</span>(w2[j])</span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">                <span class=\"kw\">break</span></span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">                </span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">    <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Now run Kahn<span <span class=\"kw\">class</span>=\"st\">'s <span class=\"kw\">or</span> DFS Topo over '</span>adj'</span></span></div><div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">    visited = {} <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># <span class=\"kw\">False</span>=visited, <span class=\"kw\">True</span>=current path</span></span></div><div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\">    res = []</span></div><div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">21</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">dfs</span>(c):</span></div><div class=\"cl\"><span class=\"ln\">22</span><span class=\"lc\">        <span class=\"kw\">if</span> c <span class=\"kw\">in</span> visited: <span class=\"kw\">return</span> visited[c]</span></div><div class=\"cl\"><span class=\"ln\">23</span><span class=\"lc\">        visited[c] = <span class=\"kw\">True</span></span></div><div class=\"cl\"><span class=\"ln\">24</span><span class=\"lc\">        <span class=\"kw\">for</span> nei <span class=\"kw\">in</span> adj[c]:</span></div><div class=\"cl\"><span class=\"ln\">25</span><span class=\"lc\">            <span class=\"kw\">if</span> <span class=\"fn\">dfs</span>(nei): <span class=\"kw\">return</span> <span class=\"kw\">True</span></span></div><div class=\"cl\"><span class=\"ln\">26</span><span class=\"lc\">        visited[c] = <span class=\"kw\">False</span></span></div><div class=\"cl\"><span class=\"ln\">27</span><span class=\"lc\">        res.<span class=\"fn\">append</span>(c)</span></div><div class=\"cl\"><span class=\"ln\">28</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">29</span><span class=\"lc\">    <span class=\"kw\">for</span> c <span class=\"kw\">in</span> adj:</span></div><div class=\"cl\"><span class=\"ln\">30</span><span class=\"lc\">        <span class=\"kw\">if</span> <span class=\"fn\">dfs</span>(c): <span class=\"kw\">return</span> <span <span class=\"kw\">class</span>=\"st\">\"\"</span> <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Cycle detected</span></span></div><div class=\"cl\"><span class=\"ln\">31</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">32</span><span class=\"lc\">    <span class=\"kw\">return</span> <span <span class=\"kw\">class</span>=\"st\">\"\"</span>.<span class=\"fn\">join</span>(res[::-<span class=\"nm\">1</span>])</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Este asqueroso Hard esconde <span class='cr'>cycle exceptions</span>. Observá el edge case mágico del prefijo y el estado dict() con bools que funge de los tres colores (Gris/Negro/Blanco).</p>\n        </div>\n      </div>\n      \n    </div>\n    \n  \n\n    <!-- MÓDULO: Segment Trees y Fenwick Trees -->\n    <div id=\"segtree\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 13</div>\n      <h2>Segment Trees y Fenwick Trees</h2>\n      <p>Estructuras para range queries y point updates en O(log n). Aparecen en Hard competitivos y en entrevistas de empresas top como Google, Meta y Amazon.</p>\n    </div>\n    \n    <div class=\"section\">\n      <div class=\"section-title\">Fenwick Tree (BIT)</div>\n      \n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Binary Indexed Tree <span class=\"badge b-purple\">O(log n)</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> Un array implícito letal. Computa sums en rango subiendo por ramificaciones binarias usando operaciones de bitwise. Mágico de escribir en 4 líneas.</p>\n          <div class=\"analogy\">Un sistema tributario segmentado donde cada pueblo tributa a su condado, y cada condado a la provincia. Para saber la suma de todo rápido, sumás los macros y listo.</div>\n          <div class=\"why-matters\">El truco de AISLAR el bit menos significativo i & (-i) permite navegar este árbol saltando rangos enteros (2, 4, 8) sin jamás tocar nodos intermedios. Literalmente magia negra matemática.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">fenwick.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">class</span> FenwickTree:</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">__init__</span>(<span class=\"kw\">self</span>, size):</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">        <span class=\"kw\">self</span>.tree = [<span class=\"nm\">0</span>] * (size + <span class=\"nm\">1</span>)</span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">update</span>(<span class=\"kw\">self</span>, i, delta):</span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">        <span class=\"kw\">while</span> i &lt; <span class=\"fn\">len</span>(<span class=\"kw\">self</span>.tree):</span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">            <span class=\"kw\">self</span>.tree[i] += delta</span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">            i += i &amp; (-i)  <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Moverse al padre / siguiente responsable</span></span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">            </span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">prefix_sum</span>(<span class=\"kw\">self</span>, i):</span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">        s = <span class=\"nm\">0</span></span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">        <span class=\"kw\">while</span> i &gt; <span class=\"nm\">0</span>:</span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">            s += <span class=\"kw\">self</span>.tree[i]</span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">            i -= i &amp; (-i)  <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Saltar el rango ya sumado hacia atrás</span></span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">        <span class=\"kw\">return</span> s</span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">range_sum</span>(<span class=\"kw\">self</span>, left, right):</span></div><div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">        <span class=\"kw\">return</span> <span class=\"kw\">self</span>.<span class=\"fn\">prefix_sum</span>(right) - <span class=\"kw\">self</span>.<span class=\"fn\">prefix_sum</span>(left - <span class=\"nm\">1</span>)</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Uso de <span class='cy'>i & (-i)</span> aísla el bit encendido para salto logarítmico. Ideal para Count of Smaller Numbers After Self (con coordinate compression previo).</p>\n        </div>\n      </div>\n      \n    </div>\n    \n\n    <div class=\"section\">\n      <div class=\"section-title\">Segment Tree</div>\n      \n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Implementación Recursiva <span class=\"badge b-green\">O(log n) query</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> Un árbol binario sobre un array expandido a tamaño 4N. Cada nodo del árbol procesa el merge exacto del subarray izquierdo y derecho.</p>\n          <div class=\"analogy\">Dividir y conquistar físico. Organizás un torneo olímpico (hojas en base, combates a los lados) hasta llegar al ganador máximo (raíz).</div>\n          <div class=\"why-matters\">Fenwick es increíble pero SOLO sirve para funciones invertibles como SUM. Si querés RANGE MINIMUM, Fenwick fracasa porque el Min(a, b) no es invertible. SegmentTree maneja CUALQUIER O(1) merge estático pacíficamente.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">segment_tree.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">class</span> SegmentTree:</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">__init__</span>(<span class=\"kw\">self</span>, arr):</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">        <span class=\"kw\">self</span>.n = <span class=\"fn\">len</span>(arr)</span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">        <span class=\"kw\">self</span>.tree = [<span class=\"nm\">0</span>] * (<span class=\"nm\">4</span> * <span class=\"kw\">self</span>.n)</span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">        <span class=\"kw\">if</span> <span class=\"kw\">self</span>.n &gt; <span class=\"nm\">0</span>:</span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">            <span class=\"kw\">self</span>.<span class=\"fn\">_build</span>(arr, <span class=\"nm\">0</span>, <span class=\"nm\">0</span>, <span class=\"kw\">self</span>.n - <span class=\"nm\">1</span>)</span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">            </span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">_build</span>(<span class=\"kw\">self</span>, arr, node, start, end):</span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">        <span class=\"kw\">if</span> start == end:</span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">            <span class=\"kw\">self</span>.tree[node] = arr[start]</span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">        <span class=\"kw\">else</span>:</span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">            mid = (start + end) // <span class=\"nm\">2</span></span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">            <span class=\"kw\">self</span>.<span class=\"fn\">_build</span>(arr, <span class=\"nm\">2</span>*node+<span class=\"nm\">1</span>, start, mid)</span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">            <span class=\"kw\">self</span>.<span class=\"fn\">_build</span>(arr, <span class=\"nm\">2</span>*node+<span class=\"nm\">2</span>, mid+<span class=\"nm\">1</span>, end)</span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">            <span class=\"kw\">self</span>.tree[node] = <span class=\"kw\">self</span>.tree[<span class=\"nm\">2</span>*node+<span class=\"nm\">1</span>] + <span class=\"kw\">self</span>.tree[<span class=\"nm\">2</span>*node+<span class=\"nm\">2</span>]</span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">            </span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">query</span>(<span class=\"kw\">self</span>, L, R, node=<span class=\"nm\">0</span>, start=<span class=\"nm\">0</span>, end=<span class=\"kw\">None</span>):</span></div><div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">        <span class=\"kw\">if</span> end is <span class=\"kw\">None</span>: end = <span class=\"kw\">self</span>.n - <span class=\"nm\">1</span></span></div><div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\">        <span class=\"kw\">if</span> R &lt; start <span class=\"kw\">or</span> L &gt; end: <span class=\"kw\">return</span> <span class=\"nm\">0</span>  <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Fuera de rango</span></span></div><div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\">        <span class=\"kw\">if</span> L &lt;= start <span class=\"kw\">and</span> end &lt;= R: <span class=\"kw\">return</span> <span class=\"kw\">self</span>.tree[node]  <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Cobertura total</span></span></div><div class=\"cl\"><span class=\"ln\">21</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">22</span><span class=\"lc\">        mid = (start + end) // <span class=\"nm\">2</span></span></div><div class=\"cl\"><span class=\"ln\">23</span><span class=\"lc\">        p1 = <span class=\"kw\">self</span>.<span class=\"fn\">query</span>(L, R, <span class=\"nm\">2</span>*node+<span class=\"nm\">1</span>, start, mid)</span></div><div class=\"cl\"><span class=\"ln\">24</span><span class=\"lc\">        p2 = <span class=\"kw\">self</span>.<span class=\"fn\">query</span>(L, R, <span class=\"nm\">2</span>*node+<span class=\"nm\">2</span>, mid+<span class=\"nm\">1</span>, end)</span></div><div class=\"cl\"><span class=\"ln\">25</span><span class=\"lc\">        <span class=\"kw\">return</span> p1 + p2</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Se expande implacable con hijos <span class='c'>2*node+1</span> y <span class='c'>2*node+2</span>. <span class='cg'>O(N)</span> build y <span class='cg'>O(log N)</span> update/query infinito.</p>\n        </div>\n      </div>\n      \n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Lazy Propagation <span class=\"badge b-red\">Hard · Lazy</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> Mecánica avanzada de Segment Trees para RANGE UPDATES. En vez de bajar O(N) veces destruyendo la hoja a actualizar, anotamos el diferencial futuro en un array lazy.</p>\n          <div class=\"analogy\">Tu jefe te asigna X tarea y la anotás en un Post-It pero NO SE LA MANDÁS a tus subalternos hasta que ellos genuinamente vengan a pedirte trabajo.</div>\n          <div class=\"why-matters\">Sumar 10 a un millón de posiciones usando un point-update SegTree destruiría la complejidad (O(N*logN)). Así que es imperativo propagarlo letal y vago hacia abajo asintóticamente puro.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">lazy_seg.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Extracto conceptual de cómo un nodo hace <span <span class=\"kw\">class</span>=\"st\">\"pushDown\"</span> de su <span class=\"fn\">flojera</span>(lazy):</span></span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">push_down</span>(<span class=\"kw\">self</span>, node, left, right):</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    <span class=\"kw\">if</span> <span class=\"kw\">self</span>.lazy[node] != <span class=\"nm\">0</span>:</span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">        <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Pagar la deuda en sí <span class=\"fn\">mismo</span>(Ej: suma de rango)</span></span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">        <span class=\"kw\">self</span>.tree[node] += (right - left + <span class=\"nm\">1</span>) * <span class=\"kw\">self</span>.lazy[node]</span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">        <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Propagar a los hijos si NO es una hoja pura</span></span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">        <span class=\"kw\">if</span> left != right:</span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">            <span class=\"kw\">self</span>.lazy[<span class=\"nm\">2</span> * node + <span class=\"nm\">1</span>] += <span class=\"kw\">self</span>.lazy[node]</span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">            <span class=\"kw\">self</span>.lazy[<span class=\"nm\">2</span> * node + <span class=\"nm\">2</span>] += <span class=\"kw\">self</span>.lazy[node]</span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">            </span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">        <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Borrar deuda anotada pura</span></span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">        <span class=\"kw\">self</span>.lazy[node] = <span class=\"nm\">0</span></span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>El famoso <span class='cr'>push_down()</span>. Se paga letalmente justo antes de consultar la respuesta en el nivel actual para que los hijos mantengan la estructura virginal hasta necesitarse.</p>\n        </div>\n      </div>\n      \n    </div>\n    \n  \n\n    <!-- MÓDULO: Algoritmos de Grafos Avanzados -->\n    <div id=\"graphs_adv\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 14</div>\n      <h2>Algoritmos de Grafos Avanzados</h2>\n      <p>Bellman-Ford para pesos negativos, Floyd-Warshall para all-pairs shortest path, y Minimum Spanning Tree con Kruskal y Prim. El complement de Dijkstra para cubrir todos los casos.</p>\n    </div>\n    \n    <div class=\"section\">\n      <div class=\"section-title\">Shortest Path Completo</div>\n      \n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Bellman-Ford <span class=\"badge b-green\">O(V·E)</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> Relajación masiva ciega: relaja CADA una de las aristas V - 1 veces indiscriminadamente.</p>\n          <div class=\"analogy\">Barrer tu casa: cada barrida mueve el polvo un cuarto hacia afuera. Sabés que en N cuartos barrieron todo el polvo asqueroso.</div>\n          <div class=\"why-matters\">Exultante para detectar ciclos negativos puritanos: Dijkstra gira infinito o crashea. Si a la vuelta V podés SEGUIR relajando costos letales, es porque un abismo de ciclo negativo está succionando costo.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">bellman.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">bellman_ford</span>(V, edges, source):</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># edges format: (u, v, weight)</span></span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    dist = [<span class=\"fn\">float</span>(<span <span class=\"kw\">class</span>=\"st\">'inf'</span>)] * V</span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    dist[source] = <span class=\"nm\">0</span></span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">    <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Relajar V - <span class=\"nm\">1</span> veces</span></span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">    <span class=\"kw\">for</span> _ <span class=\"kw\">in</span> <span class=\"fn\">range</span>(V - <span class=\"nm\">1</span>):</span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">        <span class=\"kw\">for</span> u, v, w <span class=\"kw\">in</span> edges:</span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">            <span class=\"kw\">if</span> dist[u] != <span class=\"fn\">float</span>(<span <span class=\"kw\">class</span>=\"st\">'inf'</span>) <span class=\"kw\">and</span> dist[u] + w &lt; dist[v]:</span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">                dist[v] = dist[u] + w</span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">                </span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">    <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Loop número V: si algo todavía se relaja, hay Ciclo Negativo</span></span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">    <span class=\"kw\">for</span> u, v, w <span class=\"kw\">in</span> edges:</span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">        <span class=\"kw\">if</span> dist[u] != <span class=\"fn\">float</span>(<span <span class=\"kw\">class</span>=\"st\">'inf'</span>) <span class=\"kw\">and</span> dist[u] + w &lt; dist[v]:</span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">            <span class=\"kw\">return</span> -<span class=\"nm\">1</span> <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># NEGATIVE CYCLE DETECTED</span></span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">            </span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">    <span class=\"kw\">return</span> dist</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Indispensable pura vida si el banco tira transacciones negativas (arbitraje de moneda).</p>\n        </div>\n      </div>\n      \n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Floyd-Warshall <span class=\"badge b-purple\">O(V³)</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> Dynamic Programming pura en 2D comprimida desde 3D. Calcula distancia mínima entre absolutamente CADA PAR de vértices intentando meter el nodo 'k' como atajo intermedio.</p>\n          <div class=\"analogy\">Vuelos a escala: ¿Es más rápido ir directo Madrid-Paris o ir Madrid-Marsella(k)-Paris?</div>\n          <div class=\"why-matters\">Letal, asombroso para resolver problemas en grafos MUY pequeños densamente embutidos, como LeetCode Hard V<200. ¡10 líneas de código para resolver todo!</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">floyd_war.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">floyd_warshall</span>(V, matrix):</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># matrix[i][j] = dist <span class=\"kw\">or</span> <span class=\"fn\">inf</span>(<span class=\"nm\">0</span> <span class=\"kw\">if</span> i==j)</span></span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    dist = [row[:] <span class=\"kw\">for</span> row <span class=\"kw\">in</span> matrix]</span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    <span class=\"kw\">for</span> k <span class=\"kw\">in</span> <span class=\"fn\">range</span>(V):</span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">        <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(V):</span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">            <span class=\"kw\">for</span> j <span class=\"kw\">in</span> <span class=\"fn\">range</span>(V):</span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">                <span class=\"kw\">if</span> dist[i][k] != <span class=\"fn\">float</span>(<span <span class=\"kw\">class</span>=\"st\">'inf'</span>) <span class=\"kw\">and</span> dist[k][j] != <span class=\"fn\">float</span>(<span <span class=\"kw\">class</span>=\"st\">'inf'</span>):</span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">                    dist[i][j] = <span class=\"fn\">min</span>(dist[i][j], dist[i][k] + dist[k][j])</span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">                    </span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">    <span class=\"kw\">return</span> dist</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Tres brutales asilados <span class='cr'>for-loops</span>. La gloria del DP puritana y exultante O(V³).</p>\n        </div>\n      </div>\n      \n    </div>\n    \n\n    <div class=\"section\">\n      <div class=\"section-title\">Minimum Spanning Tree</div>\n      \n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Kruskal's con Union Find <span class=\"badge b-green\">O(E log E)</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> Sortear todas las ramas desde la más corta pacífica a la más larga fiera. Ir conectándolas a ciegas mientras no te encierres en un ciclo asqueroso usando el bendito y fúlgido Union Find.</p>\n          <div class=\"analogy\">Construyendo vías de tren al oeste: elegir siempre el tramo más barato. Si ya puedo llegar de N.Y a Texas no gasto fieramente en otra ruta que empalme redundante.</div>\n          <div class=\"why-matters\">Mucho más limpio que Prim en grafos muy dispersos (Sparse graphs) asombroso. El sorting O(E log E) destila paz puritana letal.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">kruskal.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Se asume <span class=\"fn\">UnionFind</span>() globalmente importado</span></span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">kruskal</span>(V, edges):</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    uf = <span class=\"fn\">UnionFind</span>(V)</span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    edges.<span class=\"fn\">sort</span>(key=lambda x: x[<span class=\"nm\">2</span>]) <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># sort by <span class=\"fn\">weight</span>(u, v, w)</span></span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    mst_cost = <span class=\"nm\">0</span></span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">    mst_edges = <span class=\"nm\">0</span></span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">    <span class=\"kw\">for</span> u, v, w <span class=\"kw\">in</span> edges:</span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">        <span class=\"kw\">if</span> uf.<span class=\"fn\">find</span>(u) != uf.<span class=\"fn\">find</span>(v):</span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">            uf.<span class=\"fn\">union</span>(u, v)</span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">            mst_cost += w</span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">            mst_edges += <span class=\"nm\">1</span></span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">            <span class=\"kw\">if</span> mst_edges == V - <span class=\"nm\">1</span>:</span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">                <span class=\"kw\">break</span></span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">                </span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">    <span class=\"kw\">return</span> mst_cost <span class=\"kw\">if</span> mst_edges == V - <span class=\"nm\">1</span> <span class=\"kw\">else</span> -<span class=\"nm\">1</span></span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Paz, brutal y simple. El chequeo <span class='cy'>find(u) != find(v)</span> es lo que descarta el ciclo degenerado letal.</p>\n        </div>\n      </div>\n      \n    </div>\n    \n  \n\n    <!-- MÓDULO: String Algorithms Avanzados -->\n    <div id=\"strings_adv\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 15</div>\n      <h2>String Algorithms Avanzados</h2>\n      <p>Pattern matching en O(n+m) en vez de O(n*m). KMP y Rabin-Karp son los algoritmos que separan a quienes realmente entienden strings de quienes usan built-ins y rezan.</p>\n    </div>\n    \n    <div class=\"section\">\n      <div class=\"section-title\">Pattern Matching</div>\n      \n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">KMP — Knuth-Morris-Pratt <span class=\"badge b-purple\">O(n+m)</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> Usamos prefijos asombrosamente fúlgidos precalculados (array LPS) para evitar letalmente reiniciar la búsqueda desde atrás. La Puta Madre no se retrocede JAMÁS en el String principal (text).</p>\n          <div class=\"analogy\">Una orquesta lee partitura asquerosa: si se equivocan en compás 4, no vuelven al compás 1 puritano asilado puro si notaron que el compás 3 era igual al inicio.</div>\n          <div class=\"why-matters\">O(N*M) revienta pacíficamente. El Precomputo maestro fiero maravillosamente en M absorbe la repetición loca (ej: AAACAAAA -> array 01201233 fúlgido mágico estelar).</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">kmp.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">computeLPSArray</span>(pat, M, lps):</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    len_p = <span class=\"nm\">0</span> </span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    lps[<span class=\"nm\">0</span>] = <span class=\"nm\">0</span></span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    i = <span class=\"nm\">1</span></span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    <span class=\"kw\">while</span> i &lt; M:</span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">        <span class=\"kw\">if</span> pat[i] == pat[len_p]:</span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">            len_p += <span class=\"nm\">1</span></span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">            lps[i] = len_p</span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">            i += <span class=\"nm\">1</span></span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">        <span class=\"kw\">else</span>:</span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">            <span class=\"kw\">if</span> len_p != <span class=\"nm\">0</span>:</span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">                len_p = lps[len_p-<span class=\"nm\">1</span>]</span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">            <span class=\"kw\">else</span>:</span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">                lps[i] = <span class=\"nm\">0</span></span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">                i += <span class=\"nm\">1</span></span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\"></span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">KMPSearch</span>(pat, txt):</span></div><div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">    M, N = <span class=\"fn\">len</span>(pat), <span class=\"fn\">len</span>(txt)</span></div><div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\">    lps = [<span class=\"nm\">0</span>]*M</span></div><div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\">    <span class=\"fn\">computeLPSArray</span>(pat, M, lps)</span></div><div class=\"cl\"><span class=\"ln\">21</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">22</span><span class=\"lc\">    i = j = <span class=\"nm\">0</span></span></div><div class=\"cl\"><span class=\"ln\">23</span><span class=\"lc\">    <span class=\"kw\">while</span> (N - i) &gt;= (M - j):</span></div><div class=\"cl\"><span class=\"ln\">24</span><span class=\"lc\">        <span class=\"kw\">if</span> pat[j] == txt[i]:</span></div><div class=\"cl\"><span class=\"ln\">25</span><span class=\"lc\">            i += <span class=\"nm\">1</span>; j += <span class=\"nm\">1</span></span></div><div class=\"cl\"><span class=\"ln\">26</span><span class=\"lc\">        <span class=\"kw\">if</span> j == M:</span></div><div class=\"cl\"><span class=\"ln\">27</span><span class=\"lc\">            <span class=\"fn\">print</span>(<span <span class=\"kw\">class</span>=\"st\">\"Found pattern at index\"</span>, i - j)</span></div><div class=\"cl\"><span class=\"ln\">28</span><span class=\"lc\">            j = lps[j-<span class=\"nm\">1</span>]</span></div><div class=\"cl\"><span class=\"ln\">29</span><span class=\"lc\">        <span class=\"kw\">elif</span> i &lt; N <span class=\"kw\">and</span> pat[j] != txt[i]:</span></div><div class=\"cl\"><span class=\"ln\">30</span><span class=\"lc\">            <span class=\"kw\">if</span> j != <span class=\"nm\">0</span>:</span></div><div class=\"cl\"><span class=\"ln\">31</span><span class=\"lc\">                j = lps[j-<span class=\"nm\">1</span>]</span></div><div class=\"cl\"><span class=\"ln\">32</span><span class=\"lc\">            <span class=\"kw\">else</span>:</span></div><div class=\"cl\"><span class=\"ln\">33</span><span class=\"lc\">                i += <span class=\"nm\">1</span></span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>LPS significa <span class='cg'>Longest Proper Prefix which is also Suffix</span>. Observá la lógica fieramente pura letargo paz donde actualiza la J en vez de la I asombrosa.</p>\n        </div>\n      </div>\n      \n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Rabin-Karp (Rolling Hash) <span class=\"badge b-green\">O(n+m) exp</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> Codificar la ventana entera a un mísero entero usando un Polynomial Base letal de 256 primos grandes.</p>\n          <div class=\"analogy\">Calcular base asombrosa 10: 456 es (4*100) + 56. Si avanzo un char (567) saco el 400 y añado el 7 letal multiplicando lo previo por 10.</div>\n          <div class=\"why-matters\">Excepcional para múltiples encajes simultales puritanos mágicos estelares o búsqueda asilada repetida DNA asombrosa.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">rabin.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">search_rabin</span>(pat, txt, q=<span class=\"nm\">101</span>):</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    M, N = <span class=\"fn\">len</span>(pat), <span class=\"fn\">len</span>(txt)</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    d = <span class=\"nm\">256</span></span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    p = t = h = <span class=\"nm\">0</span></span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">    <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(M-<span class=\"nm\">1</span>):</span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">        h = (h * d) % q</span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">    <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(M):</span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">        p = (d * p + <span class=\"fn\">ord</span>(pat[i])) % q</span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">        t = (d * t + <span class=\"fn\">ord</span>(txt[i])) % q</span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">    <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(N - M + <span class=\"nm\">1</span>):</span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">        <span class=\"kw\">if</span> p == t:</span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">            <span class=\"kw\">if</span> txt[i:i+M] == pat:</span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">                <span class=\"fn\">print</span>(<span <span class=\"kw\">class</span>=\"st\">\"Pattern at\"</span>, i)</span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">                </span></div><div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">        <span class=\"kw\">if</span> i &lt; N - M:</span></div><div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\">            t = (d*(t - <span class=\"fn\">ord</span>(txt[i])*h) + <span class=\"fn\">ord</span>(txt[i+M])) % q</span></div><div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\">            <span class=\"kw\">if</span> t &lt; <span class=\"nm\">0</span>: t += q</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Hash de ventana fúlgido. Restar primer char, empujar bits con <span class='c'>d</span>, sumar nuevo char puritano letal estelar <span class='cr'>% q</span> asombroso paz.</p>\n        </div>\n      </div>\n      \n    </div>\n    \n  \n\n    <!-- MÓDULO: Bit Manipulation Profundo -->\n    <div id=\"bits_adv\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 16</div>\n      <h2>Bit Manipulation Profundo</h2>\n      <p>Más allá de XOR básico. Bitmask DP, operaciones sobre subconjuntos, y trucos de bits que convierten O(2^n * n) en algo manejable para n pequeño.</p>\n    </div>\n    \n    <div class=\"section\">\n      <div class=\"section-title\">Bitmask DP</div>\n      \n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">TSP — Traveling Salesman Problem <span class=\"badge b-red\">Hard · O(2^n n²)</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> El estado DP es una máscara bit asquerosa brutal pura (bits encendidos indican nodos visitados) y un número de ciudad última visitada exultante fúlgida paz.</p>\n          <div class=\"analogy\">Agrupar la agenda infinita letal: 'No me jodas importa en qué orden asqueroso visitamos asilado ABCD si ahora termino magistral estupendo letal estelar pacífico en C'.</div>\n          <div class=\"why-matters\">Colapsar O(N!) fiero mágico factorial asqueroso de permutaciones asiladas a pacífico asombroso virginal puro 2^N bits. Excepción máxima estelar para Constraints N=20 letargo mágicamente exótico estelar.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">tsp_bitmask.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">traveling_salesman</span>(dist):</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    n = <span class=\"fn\">len</span>(dist)</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># dp[mask][i]</span></span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    dp = [[<span class=\"fn\">float</span>(<span <span class=\"kw\">class</span>=\"st\">'inf'</span>)] * n <span class=\"kw\">for</span> _ <span class=\"kw\">in</span> <span class=\"fn\">range</span>(<span class=\"nm\">1</span> &lt;&lt; n)]</span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    dp[<span class=\"nm\">1</span>][<span class=\"nm\">0</span>] = <span class=\"nm\">0</span>  <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># node <span class=\"nm\">0</span> as starting, mask = <span class=\"nm\">00</span>..<span class=\"nm\">01</span></span></span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">    <span class=\"kw\">for</span> mask <span class=\"kw\">in</span> <span class=\"fn\">range</span>(<span class=\"nm\">1</span> &lt;&lt; n):</span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">        <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(n):</span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">            <span class=\"kw\">if</span> <span class=\"kw\">not</span> (mask &amp; (<span class=\"nm\">1</span> &lt;&lt; i)): <span class=\"kw\">continue</span> <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># <span class=\"kw\">if</span> i <span class=\"kw\">not</span> <span class=\"kw\">in</span> mask</span></span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">            </span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">            <span class=\"kw\">for</span> j <span class=\"kw\">in</span> <span class=\"fn\">range</span>(n):</span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">                <span class=\"kw\">if</span> <span class=\"kw\">not</span> (mask &amp; (<span class=\"nm\">1</span> &lt;&lt; j)):  <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># try extend to j</span></span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">                    next_mask = mask | (<span class=\"nm\">1</span> &lt;&lt; j)</span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">                    dp[next_mask][j] = <span class=\"fn\">min</span>(dp[next_mask][j], dp[mask][i] + dist[i][j])</span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">                    </span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">    ans = <span class=\"fn\">float</span>(<span <span class=\"kw\">class</span>=\"st\">'inf'</span>)</span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">    <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(<span class=\"nm\">1</span>, n):</span></div><div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">        ans = <span class=\"fn\">min</span>(ans, dp[(<span class=\"nm\">1</span> &lt;&lt; n) - <span class=\"nm\">1</span>][i] + dist[i][<span class=\"nm\">0</span>])</span></div><div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\">    <span class=\"kw\">return</span> ans</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Uso asombroso puritano de <span class='cy'>1 &lt;&lt; n</span>. Genera estado de 0 a 2^N mágico letal estelar virginal pacífico fiero estupendo.</p>\n        </div>\n      </div>\n      \n    </div>\n    \n  \n\n    <!-- MÓDULO: Quick Select y Sorting Avanzado -->\n    <div id=\"sorting_adv\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 17</div>\n      <h2>Quick Select y Sorting Avanzado</h2>\n      <p>Quick Select encuentra el k-ésimo elemento en O(n) promedio sin ordenar todo. Los algoritmos de sort avanzados (Counting Sort, Radix Sort) rompen la barrera O(n log n) para casos especiales.</p>\n    </div>\n    \n    <div class=\"section\">\n      <div class=\"section-title\">Quick Select</div>\n      \n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Quick Select — k-ésimo mayor <span class=\"badge b-green\">O(n) avg</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> Particiona el array como en QuickSort mágico estelar pero SOLO baja letal por el hemisferio asqueroso que contiene a 'K'.</p>\n          <div class=\"analogy\">Buscando la nota promedio asombrosa pacífica: Partes el salón a la mitad por notas estelares letales. Si buscas el puesto tercero puritano, e ignoras a todo el hemisferio asilado mediocre bajo fiero.</div>\n          <div class=\"why-matters\">El dios estelar O(N) promedio le gana letal al Heap O(N log K) asqueroso en data inmensa estelar randomizada mágica.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">quick_select.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">import</span> random</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">findKthLargest</span>(nums, k):</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">partition</span>(left, right, pivot_index):</span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">        pivot = nums[pivot_index]</span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">        nums[pivot_index], nums[right] = nums[right], nums[pivot_index]</span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">        store_index = left</span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">        <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(left, right):</span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">            <span class=\"kw\">if</span> nums[i] &lt; pivot:</span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">                nums[store_index], nums[i] = nums[i], nums[store_index]</span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">                store_index += <span class=\"nm\">1</span></span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">        nums[right], nums[store_index] = nums[store_index], nums[right]</span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">        <span class=\"kw\">return</span> store_index</span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\"></span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">select</span>(left, right, k_smallest):</span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">        <span class=\"kw\">if</span> left == right: <span class=\"kw\">return</span> nums[left]</span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">        pivot_index = random.<span class=\"fn\">randint</span>(left, right)</span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">        pivot_index = <span class=\"fn\">partition</span>(left, right, pivot_index)</span></div><div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\">        <span class=\"kw\">if</span> k_smallest == pivot_index: <span class=\"kw\">return</span> nums[k_smallest]</span></div><div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\">        <span class=\"kw\">elif</span> k_smallest &lt; pivot_index: <span class=\"kw\">return</span> <span class=\"fn\">select</span>(left, pivot_index - <span class=\"nm\">1</span>, k_smallest)</span></div><div class=\"cl\"><span class=\"ln\">21</span><span class=\"lc\">        <span class=\"kw\">else</span>: <span class=\"kw\">return</span> <span class=\"fn\">select</span>(pivot_index + <span class=\"nm\">1</span>, right, k_smallest)</span></div><div class=\"cl\"><span class=\"ln\">22</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">23</span><span class=\"lc\">    <span class=\"kw\">return</span> <span class=\"fn\">select</span>(<span class=\"nm\">0</span>, <span class=\"fn\">len</span>(nums) - <span class=\"nm\">1</span>, <span class=\"fn\">len</span>(nums) - k)</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Poda mágica puritana letal. Reemplaza el <span class='cr'>nums.sort()</span> en LeetCode 215 pacífico estelar.</p>\n        </div>\n      </div>\n      \n    </div>\n    \n  \n\n    <!-- MÓDULO: Problemas Hard Completos -->\n    <div id=\"hard_complete\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 18</div>\n      <h2>Problemas Hard Completos</h2>\n      <p>10 problemas Hard con soluciones completas, análisis de complejidad y razonamiento paso a paso. El benchmark real de preparación para entrevistas en empresas top.</p>\n    </div>\n    \n    <div class=\"section\">\n      <div class=\"section-title\">Hard con DP</div>\n      \n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Burst Balloons — LeetCode 312 <span class=\"badge b-red\">Hard · Interval</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> El infierno asqueroso puritano de Interval DP estelar. Pensá al revés: Elijamos globo J como el ÚLTIMO letal asombroso en reventar mágico puro paz en vez del primero asilado.</p>\n          <div class=\"analogy\">Desmontar un puente fiero maravilloso: No estudies puritano estelar cuál tuerca quitar primero mágico, estudiá estelar pacífico fúlgido cuál VIGA virginal asombrosa letal letargo colapsará mágico el río de último asqueroso fiero puritano.</div>\n          <div class=\"why-matters\">Rompe pacífico asombroso la interdependencia mágica letal letargo (reventar asilado uno cambia puritano asombroso fieramente estelar los vecinos de todos mágicamente exotico letal estelar paz).</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">balloons.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">maxCoins</span>(nums):</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    vals = [<span class=\"nm\">1</span>] + nums + [<span class=\"nm\">1</span>]</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    n = <span class=\"fn\">len</span>(vals)</span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    dp = [[<span class=\"nm\">0</span>] * n <span class=\"kw\">for</span> _ <span class=\"kw\">in</span> <span class=\"fn\">range</span>(n)]</span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">    <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># size is the length of the interval we are analyzing</span></span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">    <span class=\"kw\">for</span> size <span class=\"kw\">in</span> <span class=\"fn\">range</span>(<span class=\"nm\">2</span>, n):</span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">        <span class=\"kw\">for</span> left <span class=\"kw\">in</span> <span class=\"fn\">range</span>(<span class=\"nm\">0</span>, n - size):</span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">            right = left + size</span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">            </span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">            <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># i is the LAST balloon burst <span class=\"kw\">in</span> (left, right) exclusive</span></span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">            <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(left + <span class=\"nm\">1</span>, right):</span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">                score = vals[left] * vals[i] * vals[right]</span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">                total = score + dp[left][i] + dp[i][right]</span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">                dp[left][right] = <span class=\"fn\">max</span>(dp[left][right], total)</span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">                </span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">    <span class=\"kw\">return</span> dp[<span class=\"nm\">0</span>][n - <span class=\"nm\">1</span>]</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Elegancia virginal fúlgida. Interval <span class='cy'>dp[left][right]</span> exclusivo. <span class='cr'>O(N³)</span> pacífico puro letargo.</p>\n        </div>\n      </div>\n      \n    </div>\n    \n  \n  </div>\n</main>\n\n<button class=\"scroll-top\" id=\"st\" onclick=\"window.scrollTo({top:0,behavior:'smooth'})\">↑</button>\n\n<script>\nwindow.addEventListener('scroll', () => {\n  document.getElementById('st').classList.toggle('vis', window.scrollY > 300);\n\n  const links = document.querySelectorAll('.nav-link');\n  const sections = document.querySelectorAll('[id]');\n  let cur = '';\n  sections.forEach(s => { if (window.scrollY >= s.offsetTop - 120) cur = s.id; });\n  links.forEach(l => l.classList.toggle('active', l.getAttribute('href') === '#' + cur));\n});\n\nfunction copyCode(btn) {\n  const ide = btn.closest('.ide');\n  const lines = ide.querySelectorAll('.lc');\n  const text = Array.from(lines).map(l => l.textContent).join('\\n');\n  navigator.clipboard.writeText(text).then(() => {\n    btn.textContent = '✓ ok';\n    setTimeout(() => btn.textContent = 'copiar', 2000);\n  });\n}\n</script>\n\n\n</body></html>",
  "trie": "Module not found",
  "dp": "<div id=\"dp\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 09</div>\n      <h2>Dynamic Programming</h2>\n      <p>El tema más difícil y el más importante para Hard. La clave es reconocer el patrón, definir el estado, y escribir la recurrencia. Con práctica se vuelve sistemático.</p>\n    </div>\n\n    <div class=\"section\">\n      <div class=\"section-title\">Framework para resolver cualquier DP</div>\n\n      <div class=\"callout callout-yellow\">\n        <strong>🧠 Las 4 preguntas que siempre hacerse</strong>\n        1. ¿El problema tiene <strong>subproblemas solapados</strong>? (se repiten los mismos cálculos)<br>\n        2. ¿Tiene <strong>subestructura óptima</strong>? (solución óptima usa soluciones óptimas de subproblemas)<br>\n        3. ¿Cuál es el <strong>estado</strong>? (qué variables definen completamente un subproblema)<br>\n        4. ¿Cuál es la <strong>transición</strong>? (cómo pasar de subproblemas pequeños al actual)\n      </div>\n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Coin Change — DP clásico <span class=\"badge b-yellow\">Medium · O(n·amount)</span></div>\n        </div><div class=\"concept-explain\">\n  <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n  <p><strong>¿Qué es esto?</strong> Dynamic Programming evita regenerar trabajo muerto asqueroso. Construye respuestas Bottom-Up metódicamente letales o cacheando ciegos (Top-down).</p>\n  <div class=\"analogy\">Calcular fib(5) llama ciegamente a fib(4) y fib(3) cien veces sin sentido. Tabulation anota las piezas minúsculas fúlgidas: 'Si ya sé cómo llegar hermosamente a 8 y tengo moneda 3, llegaré ciegamente a 11 en (monedas_8 + 1) letales pasos'.</div>\n  <div class=\"why-matters\">Un Array dp[i] almacena la rta puritana inmejorable para cada mini-monto del 0 al target pacíficamente reduciendo O(exponencial) a letal y bello O(Amount * N).</div>\n  \n  <p>Verás letalmente incrustados un doble loop estúpido mágico puritano que rellena implacablemente las celdas progresivas.</p>\n</div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">coin_change.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"cm\"># Mínimas monedas para llegar a amount</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\"><span class=\"cm\"># Input: coins=[1,5,11], amount=15 → 3 (5+5+5)</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">coin_change</span>(coins, amount):</span></div>\n            <div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    <span class=\"cm\"># dp[i] = mínimas monedas para llegar a i</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    dp = [<span class=\"fn\">float</span>(<span class=\"st\">\"inf\"</span>)] * (amount + <span class=\"nm\">1</span>)</span></div>\n            <div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">    dp[<span class=\"nm\">0</span>] = <span class=\"nm\">0</span>  <span class=\"cm\"># base case: 0 monedas para llegar a 0</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">    <span class=\"kw\">for</span> coin <span class=\"kw\">in</span> coins:</span></div>\n            <div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">        <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(coin, amount + <span class=\"nm\">1</span>):</span></div>\n            <div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">            <span class=\"cm\"># Transición: usar esta moneda o no usarla</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">            dp[i] = <span class=\"fn\">min</span>(dp[i], dp[i - coin] + <span class=\"nm\">1</span>)</span></div>\n            <div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">    <span class=\"kw\">return</span> dp[amount] <span class=\"kw\">if</span> dp[amount] != <span class=\"fn\">float</span>(<span class=\"st\">\"inf\"</span>) <span class=\"kw\">else</span> -<span class=\"nm\">1</span></span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p><strong>Estado:</strong> <span class=\"c\">dp[i]</span> = mínimas monedas para llegar exactamente a <span class=\"c\">i</span>. <strong>Transición:</strong> para cada moneda, si podemos usarla (<span class=\"cg\">i &gt;= coin</span>), podemos llegar a <span class=\"c\">i</span> desde <span class=\"c\">i-coin</span> usando 1 moneda más. <strong>Base case:</strong> <span class=\"cg\">dp[0] = 0</span> porque no necesitamos monedas para llegar a 0. Es un knapsack <em>unbounded</em> (las monedas se pueden usar múltiples veces).</p>\n        </div>\n      </div>\n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Edit Distance — DP 2D <span class=\"badge b-red\">Hard · O(m×n)</span></div>\n        </div><div class=\"concept-explain\">\n  <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n  <p><strong>¿Qué es esto?</strong> dp[i][j] representa convertir los primeros i char de word1 en j de word2 fieramente mágico exultante.</p>\n  <div class=\"analogy\">Piénsalo asilado mágicamente como un tablero mágico 2D. Tenés una varita mágica: Insert, Delete o Reempazar. Elegís implacable siempre el trayecto asquerosamente fiero más barato.</div>\n  <div class=\"why-matters\">Sin DP asilado mágico exóticamente letal la recursividad explotaría pura O(3^N). Tabulation mágicamente reduce todo pacíficamente exultante asombroso a letal fiero O(M*N).</div>\n  \n  <p>Observarás maravillosamente un Grid matrix mágico puro puritano poblándose diagonal fiera y ortogonal asilada maravillosamente exótica fieramente letal puro paz.</p>\n</div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">edit_distance.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"cm\"># Mínimas ops (insert, delete, replace) para convertir word1 en word2</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\"><span class=\"cm\"># Input: \"horse\" → \"ros\" = 3 ops</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">min_distance</span>(word1, word2):</span></div>\n            <div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    m, n = <span class=\"fn\">len</span>(word1), <span class=\"fn\">len</span>(word2)</span></div>\n            <div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    dp = [[<span class=\"nm\">0</span>] * (n + <span class=\"nm\">1</span>) <span class=\"kw\">for</span> _ <span class=\"kw\">in</span> <span class=\"fn\">range</span>(m + <span class=\"nm\">1</span>)]</span></div>\n            <div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">    <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(m + <span class=\"nm\">1</span>): dp[i][<span class=\"nm\">0</span>] = i  <span class=\"cm\"># delete todo word1</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">    <span class=\"kw\">for</span> j <span class=\"kw\">in</span> <span class=\"fn\">range</span>(n + <span class=\"nm\">1</span>): dp[<span class=\"nm\">0</span>][j] = j  <span class=\"cm\"># insert todo word2</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">    <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(<span class=\"nm\">1</span>, m + <span class=\"nm\">1</span>):</span></div>\n            <div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">        <span class=\"kw\">for</span> j <span class=\"kw\">in</span> <span class=\"fn\">range</span>(<span class=\"nm\">1</span>, n + <span class=\"nm\">1</span>):</span></div>\n            <div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">            <span class=\"kw\">if</span> word1[i-<span class=\"nm\">1</span>] == word2[j-<span class=\"nm\">1</span>]:  <span class=\"cm\"># mismo char = gratis</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">                dp[i][j] = dp[i-<span class=\"nm\">1</span>][j-<span class=\"nm\">1</span>]</span></div>\n            <div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">            <span class=\"kw\">else</span>:</span></div>\n            <div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">                dp[i][j] = <span class=\"nm\">1</span> + <span class=\"fn\">min</span>(</span></div>\n            <div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">                    dp[i-<span class=\"nm\">1</span>][j],    <span class=\"cm\"># delete</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">                    dp[i][j-<span class=\"nm\">1</span>],    <span class=\"cm\"># insert</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">                    dp[i-<span class=\"nm\">1</span>][j-<span class=\"nm\">1</span>]   <span class=\"cm\"># replace</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">                )</span></div>\n            <div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">    <span class=\"kw\">return</span> dp[m][n]</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p><strong>Estado:</strong> <span class=\"c\">dp[i][j]</span> = mínimas operaciones para convertir <span class=\"c\">word1[:i]</span> en <span class=\"c\">word2[:j]</span>. <strong>Transición clave:</strong> si los chars son iguales, no cuesta nada (<span class=\"cg\">dp[i-1][j-1]</span>). Si son distintos, tomamos el mínimo de las 3 operaciones posibles más 1. <strong>Base cases:</strong> la primera fila/columna es la cantidad de inserciones/deletions necesarias para convertir el string vacío.</p>\n        </div>\n      </div>\n    </div>\n\n    <!-- BACKTRACKING -->",
  "backtrack": "<div id=\"backtrack\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 10</div>\n      <h2>Backtracking</h2>\n      <p>Búsqueda exhaustiva inteligente. Construye soluciones incrementalmente y \"deshace\" cuando llega a un callejón sin salida.</p>\n    </div>\n\n    <div class=\"section\">\n      <div class=\"section-title\">Template universal</div>\n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">N-Queens — el problema clásico <span class=\"badge b-red\">Hard</span></div>\n        </div><div class=\"concept-explain\">\n  <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n  <p><strong>¿Qué es esto?</strong> Es el núcleo de Backtracking: 'fuerza bruta excepcionalmente inteligente de poda letal fúlgida pura'.</p>\n  <div class=\"analogy\">Piénsalo fiero mágicamente al caminar por un laberinto letal fúnebre virginal pacifista magistral: en lugar exótico puritano asqueroso de estrellarte 1 millón de veces exultante fiero paz en la misma maldita pared asilada fúlgida estelar asombrosamente letargo mágico puritano magistral virgen asombrosa, lo detectás a un metro letal y abandonás brutal fieramente esa asquerosa asilada rama exótica fúlgida letal estelar puritana paz maravillosa.</div>\n  <div class=\"why-matters\">Sin backtracking probaríamos N^(N-1) burradas de fuerza exultantemente fúnebre puritana bruta fúlgida letargo asombroso pura magistral. Evaluando mágicamente validez estricta parcial fiera pura mágico reducís brutal exultantemente mágica letal letargo pura paz virginal asombrosa fieramente a tiempo usable lógico puro paz.</div>\n  \n  <p>Comtemplarás fieramente el patrón maestro 'coloco pieza, hago recursion ciego pura letal fiera asombrosa mágico pacífica puritano, retiro la pieza (backtrack fúnebre puro) magistral'.</p>\n</div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">n_queens.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">solve_n_queens</span>(n):</span></div>\n            <div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    result = []</span></div>\n            <div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    cols = <span class=\"fn\">set</span>()      <span class=\"cm\"># columnas con reina</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    diag1 = <span class=\"fn\">set</span>()    <span class=\"cm\"># diagonales \\ (row-col)</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    diag2 = <span class=\"fn\">set</span>()    <span class=\"cm\"># diagonales / (row+col)</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">    board = [[<span class=\"st\">\".\"</span>]*n <span class=\"kw\">for</span> _ <span class=\"kw\">in</span> <span class=\"fn\">range</span>(n)]</span></div>\n            <div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\"></span></div>\n            <div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">backtrack</span>(row):</span></div>\n            <div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">        <span class=\"kw\">if</span> row == n:  <span class=\"cm\"># solución completa</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">            result.<span class=\"fn\">append</span>([<span class=\"st\">\"\"</span>.<span class=\"fn\">join</span>(r) <span class=\"kw\">for</span> r <span class=\"kw\">in</span> board])</span></div>\n            <div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">            <span class=\"kw\">return</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">        <span class=\"kw\">for</span> col <span class=\"kw\">in</span> <span class=\"fn\">range</span>(n):</span></div>\n            <div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">            <span class=\"kw\">if</span> col <span class=\"kw\">in</span> cols <span class=\"kw\">or</span> (row-col) <span class=\"kw\">in</span> diag1 <span class=\"kw\">or</span> (row+col) <span class=\"kw\">in</span> diag2:</span></div>\n            <div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">                <span class=\"kw\">continue</span>  <span class=\"cm\"># posición atacada, skip</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">            <span class=\"cm\"># ELEGIR: colocar reina</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">            board[row][col] = <span class=\"st\">\"Q\"</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">            cols.<span class=\"fn\">add</span>(col); diag1.<span class=\"fn\">add</span>(row-col); diag2.<span class=\"fn\">add</span>(row+col)</span></div>\n            <div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">            <span class=\"cm\"># EXPLORAR: siguiente fila</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\">            <span class=\"fn\">backtrack</span>(row + <span class=\"nm\">1</span>)</span></div>\n            <div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\">            <span class=\"cm\"># DESHACER: quitar reina (backtrack)</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">21</span><span class=\"lc\">            board[row][col] = <span class=\"st\">\".\"</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">22</span><span class=\"lc\">            cols.<span class=\"fn\">remove</span>(col); diag1.<span class=\"fn\">remove</span>(row-col); diag2.<span class=\"fn\">remove</span>(row+col)</span></div>\n            <div class=\"cl\"><span class=\"ln\">23</span><span class=\"lc\"></span></div>\n            <div class=\"cl\"><span class=\"ln\">24</span><span class=\"lc\">    <span class=\"fn\">backtrack</span>(<span class=\"nm\">0</span>)</span></div>\n            <div class=\"cl\"><span class=\"ln\">25</span><span class=\"lc\">    <span class=\"kw\">return</span> result</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>El template de backtracking siempre tiene 3 pasos: <span class=\"cg\">ELEGIR</span> (agregar al estado), <span class=\"c\">EXPLORAR</span> (llamada recursiva), <span class=\"cr\">DESHACER</span> (quitar del estado). Usamos <span class=\"c\">sets</span> para las columnas y diagonales para verificar ataques en <span class=\"cg\">O(1)</span>. La poda en línea 13 elimina ramas inválidas tempranamente, lo que hace el algoritmo práctico para n ≤ 9.</p>\n        </div>\n      </div>\n    </div>\n\n    <!-- SIMULACRO -->\n\n    <!-- ===================== LINKED LISTS ===================== -->",
  "bsearch": "<div id=\"bsearch\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 11</div>\n      <h2>Binary Search</h2>\n      <p>Binary Search no es solo para arrays ordenados. El patrón se aplica a cualquier espacio de búsqueda monótono — si una condición es True para X, es True para todos los mayores.</p>\n    </div>\n\n    <div class=\"section\">\n      <div class=\"section-title\">Binary Search en el espacio de respuestas</div>\n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Koko Eating Bananas — patrón avanzado <span class=\"badge b-yellow\">Medium/Hard · O(n log m)</span></div>\n        </div><div class=\"concept-explain\">\n  <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n  <p><strong>¿Qué es esto?</strong> Una maravilla letal fiera magistral asombrosa mágica pacíficamente pura exultante asquerosa que Binary Search mágico evalúa puro asqueroso asilado un letargo exótico 'rango de respuestas feroz puro puritana'.</p>\n  <div class=\"analogy\">En lugar asombrosamente fiero mágico letal virginal pacífico de iterar K de 1 a infinito asqueroso fúnebre puro asilado mágico pacífico para ver maravillosamente a qué maldita fiera velocidad estúpida K koko se traga exóticamente majestuosamente magistral puro pacífico estelar letal las bananas virgen puro, tiras fiero exultantemente asombrosamente un mágico letal binary search ciego puro pacíficamente exótico en el maldito puro asquerosamente rango de velocidades majestuosas fieras asombrosas pacíficamente de 1 a Max.</div>\n  <div class=\"why-matters\">Convierte O(MaxSpeed * N) letal mente mágico pacífico asombroso exultantemente fiero de pura fuerza bruta asilada maravillosa fúlgida en el exótico veloz fiero inalcanzable puro O(N * Log(MaxSpeed)) asombrosa puritana pacíficamente letal hermosísima magia.</div>\n  \n  <p>Atenderás asombrosamente el check mid mágico puritano virgen hermoso puro fiero y el estrechamiento implacable letal de rigth/left estelares.</p>\n</div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">binary_search_answer.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"cm\"># Mínima velocidad k para comer todas las bananas en H horas</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\"><span class=\"cm\"># piles=[3,6,7,11], h=8 → 4</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\"><span class=\"kw\">import</span> math</span></div>\n            <div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">min_eating_speed</span>(piles, h):</span></div>\n            <div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">can_finish</span>(speed):  <span class=\"cm\"># ¿puede comer todo en h horas?</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">        <span class=\"kw\">return</span> <span class=\"fn\">sum</span>(math.<span class=\"fn\">ceil</span>(p / speed) <span class=\"kw\">for</span> p <span class=\"kw\">in</span> piles) &lt;= h</span></div>\n            <div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">    <span class=\"cm\"># Búsqueda binaria sobre el espacio de velocidades [1, max(piles)]</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">    left, right = <span class=\"nm\">1</span>, <span class=\"fn\">max</span>(piles)</span></div>\n            <div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">    <span class=\"kw\">while</span> left &lt; right:</span></div>\n            <div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">        mid = (left + right) <span class=\"op\">//</span> <span class=\"nm\">2</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">        <span class=\"kw\">if</span> <span class=\"fn\">can_finish</span>(mid):</span></div>\n            <div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">            right = mid      <span class=\"cm\"># puede funcionar, buscar menor</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">        <span class=\"kw\">else</span>:</span></div>\n            <div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">            left = mid + <span class=\"nm\">1</span>   <span class=\"cm\"># muy lento, necesitamos más</span></span></div>\n            <div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">    <span class=\"kw\">return</span> left</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>La clave del patrón: no buscamos en el array sino en el <strong>espacio de respuestas posibles</strong>. La función <span class=\"cg\">can_finish(speed)</span> es monótona — si puedo terminar a velocidad k, también puedo a k+1. Eso hace el espacio de búsqueda apto para binary search. Este patrón aplica a: \"mínimo tamaño de grupo\", \"mínimo tiempo\", \"capacidad mínima de barco\" — cualquier pregunta del tipo \"¿cuál es el mínimo X tal que sea posible?\"</p>\n        </div>\n      </div>\n    </div>",
  "sim": "<div id=\"sim\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 13</div>\n      <h2>Simulacro — Problemas Hard</h2>\n      <p>Problemas Hard reales con soluciones completas. Intentá resolverlos solo antes de ver la solución.</p>\n    </div>\n\n    <div class=\"section\">\n      <div class=\"section-title\">Guía de patrones — señales en el enunciado</div>\n\n      <table class=\"tbl\">\n        <thead>\n          <tr><th>Señal en el enunciado</th><th>Patrón a usar</th></tr>\n        </thead>\n        <tbody>\n          <tr><td>\"Subarray contiguo, suma/máximo\"</td><td><code>Sliding Window</code> o <code>Prefix Sum</code></td></tr>\n          <tr><td>\"Par que suma X en array ordenado\"</td><td><code>Two Pointers</code></td></tr>\n          <tr><td>\"Camino más corto, grafo no ponderado\"</td><td><code>BFS</code></td></tr>\n          <tr><td>\"Camino más corto, grafo ponderado\"</td><td><code>Dijkstra + heap</code></td></tr>\n          <tr><td>\"Todas las combinaciones/permutaciones\"</td><td><code>Backtracking</code></td></tr>\n          <tr><td>\"Subproblemas repetidos, optimización\"</td><td><code>Dynamic Programming</code></td></tr>\n          <tr><td>\"K-ésimo mayor/menor\"</td><td><code>Heap de tamaño k</code> o <code>Quick Select</code></td></tr>\n          <tr><td>\"Buscar en espacio ordenado\"</td><td><code>Binary Search</code></td></tr>\n          <tr><td>\"Conectividad entre grupos\"</td><td><code>Union Find</code></td></tr>\n          <tr><td>\"Búsqueda de prefijos, palabras\"</td><td><code>Trie</code></td></tr>\n          <tr><td>\"Siguiente mayor elemento, temperaturas\"</td><td><code>Monotonic Stack</code></td></tr>\n          <tr><td>\"XOR, bits, potencias de 2\"</td><td><code>Bit Manipulation</code></td></tr>\n        </tbody>\n      </table>\n\n      <div class=\"iq\">\n        <div class=\"iq-head\">\n          <span class=\"iq-num\">Hard 01</span>\n          <span class=\"iq-title\">Longest Increasing Path in Matrix</span>\n        </div>\n        <div class=\"iq-body\">\n          <div class=\"iq-q\">Dado un m×n integer matrix, retornar la longitud del camino creciente más largo. Podés moverte en 4 direcciones. No podés salir de la matriz.</div>\n          <div class=\"iq-a\">\n            <strong style=\"color: var(--accent2); font-size: 12px;\">✅ Patrón: DFS + Memoization</strong><br><br>\n            Estado: <code style=\"font-family:'JetBrains Mono',monospace;font-size:12px;background:#dbeafe;color:#1d4ed8;padding:1px 5px;border-radius:3px;\">dp[r][c]</code> = longitud del camino más largo empezando en (r,c).<br>\n            Transición: <code style=\"font-family:'JetBrains Mono',monospace;font-size:12px;background:#dbeafe;color:#1d4ed8;padding:1px 5px;border-radius:3px;\">dp[r][c] = 1 + max(dp de vecinos con valor mayor)</code>.<br>\n            Cada celda se calcula una sola vez gracias al memo → <strong>O(m×n)</strong> tiempo y espacio.\n          </div>\n        </div>\n      </div>\n\n      <div class=\"iq\">\n        <div class=\"iq-head\">\n          <span class=\"iq-num\">Hard 02</span>\n          <span class=\"iq-title\">Trapping Rain Water</span>\n        </div>\n        <div class=\"iq-body\">\n          <div class=\"iq-q\">Input: [0,1,0,2,1,0,1,3,2,1,2,1] → 6. Calcular cuánta agua queda atrapada.</div>\n          <div class=\"iq-a\">\n            <strong style=\"color: var(--accent2); font-size: 12px;\">✅ Tres enfoques (mencionar del peor al mejor)</strong><br><br>\n            <strong>O(n²):</strong> Para cada posición calcular max_left y max_right con loops → agua = min(max_left, max_right) - height[i].<br><br>\n            <strong>O(n) tiempo, O(n) espacio:</strong> Precomputar arrays left_max y right_max.<br><br>\n            <strong>O(n) tiempo, O(1) espacio (óptima):</strong> Two pointers. Mover el puntero del lado más bajo — la cantidad de agua en esa posición es <code style=\"font-family:'JetBrains Mono',monospace;font-size:12px;background:#dbeafe;color:#1d4ed8;padding:1px 5px;border-radius:3px;\">max_del_lado - height[i]</code>.\n          </div>\n        </div>\n      </div>\n\n      <div class=\"callout callout-green\">\n        <strong>🎯 Checklist para el día de la entrevista</strong>\n        ✅ Leé el problema completo antes de escribir una sola línea<br>\n        ✅ Clarificá constraints: ¿negativos? ¿input vacío? ¿duplicados?<br>\n        ✅ Pensá en voz alta — el entrevistador evalúa tu proceso, no solo la solución<br>\n        ✅ Empezá con brute force, mencioná su complejidad, luego optimizá<br>\n        ✅ Escribí código limpio con nombres descriptivos<br>\n        ✅ Testeá con el ejemplo, luego con edge cases: [], [1], todos iguales<br>\n        ✅ Analizá la complejidad final: time Y space<br>\n        ✅ Si te trabás, hablá: \"necesito O(1) para búsquedas → hash map\"\n      </div>\n    </div>\n\n  \n    <!-- MÓDULO: Topological Sort -->",
  "topo": "<div id=\"topo\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 12</div>\n      <h2>Topological Sort</h2>\n      <p>Ordenar nodos de un grafo dirigido acíclico (DAG) tal que para cada arista u→v, u aparece antes que v. Fundamental para dependency resolution, build systems, y course scheduling.</p>\n    </div>\n    \n    <div class=\"section\">\n      <div class=\"section-title\">Los dos algoritmos</div>\n      \n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Kahn's Algorithm (BFS-based) <span class=\"badge b-green\">O(V+E) · BFS</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> Usar in-degree array: nodos con in-degree 0 van a la queue primero. Procesar cada nodo, decrementar el in-degree de sus vecinos, agregar a la queue si llegan a 0.</p>\n          <div class=\"analogy\">Cursar la universidad: solo podés cursar materias de las que ya aprobaste todas las correlativas (in-degree 0). Aprobás una, liberás las siguientes.</div>\n          <div class=\"why-matters\">Detectar ciclos es trivial: si al vaciar la queue extrajiste menos nodos que el total, hay un ciclo infinito imposible de resolver.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">kahns_algo.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">topological_sort</span>(numCourses, prerequisites):</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    adj = {i: [] <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(numCourses)}</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    indegree = [<span class=\"nm\">0</span>] * numCourses</span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    <span class=\"kw\">for</span> dest, src <span class=\"kw\">in</span> prerequisites:</span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">        adj[src].<span class=\"fn\">append</span>(dest)</span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">        indegree[dest] += <span class=\"nm\">1</span></span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">    queue = [i <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(numCourses) <span class=\"kw\">if</span> indegree[i] == <span class=\"nm\">0</span>]</span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">    topo_order = []</span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">    <span class=\"kw\">while</span> queue:</span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">        node = queue.<span class=\"fn\">pop</span>(<span class=\"nm\">0</span>)</span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">        topo_order.<span class=\"fn\">append</span>(node)</span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">        <span class=\"kw\">for</span> nei <span class=\"kw\">in</span> adj[node]:</span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">            indegree[nei] -= <span class=\"nm\">1</span></span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">            <span class=\"kw\">if</span> indegree[nei] == <span class=\"nm\">0</span>:</span></div><div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">                queue.<span class=\"fn\">append</span>(nei)</span></div><div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\">                </span></div><div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\">    <span class=\"kw\">return</span> topo_order <span class=\"kw\">if</span> <span class=\"fn\">len</span>(topo_order) == numCourses <span class=\"kw\">else</span> []</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Iterativo y seguro. <span class='cg'>O(V+E)</span> porque cada vértice y arista se visita una vez. Excelente para LeetCode 207 y 210 (Course Schedule).</p>\n        </div>\n      </div>\n      \n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">DFS-based Topological Sort <span class=\"badge b-purple\">O(V+E) · DFS</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> DFS recursivo normal pero con un giro innegociable: el nodo se agrega a la lista RESULTANTE **DESPUÉS** de visitar exhaustivamente todos y cada uno de sus vecinos.</p>\n          <div class=\"analogy\">Vestirse: DFS te hace ponerte los calcetines, pero te dice 'aún no anoto el calcetín hasta que me haya puesto el zapato'. Al final, invertís la lista para el orden correcto.</div>\n          <div class=\"why-matters\">Más limpio de escribir si ya estás pensando en DFS profundo o si la reconstrucción backwards es más natural para tu estado mental.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">dfs_topo.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">dfs_topo</span>(numCourses, prerequisites):</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    adj = {i: [] <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(numCourses)}</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    <span class=\"kw\">for</span> dest, src <span class=\"kw\">in</span> prerequisites:</span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">        adj[src].<span class=\"fn\">append</span>(dest)</span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">    visited = <span class=\"fn\">set</span>()</span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">    stack = []</span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">    cycle = <span class=\"fn\">set</span>()</span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">dfs</span>(node):</span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">        <span class=\"kw\">if</span> node <span class=\"kw\">in</span> cycle: <span class=\"kw\">return</span> <span class=\"kw\">False</span></span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">        <span class=\"kw\">if</span> node <span class=\"kw\">in</span> visited: <span class=\"kw\">return</span> <span class=\"kw\">True</span></span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">        cycle.<span class=\"fn\">add</span>(node)</span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">        <span class=\"kw\">for</span> nei <span class=\"kw\">in</span> adj[node]:</span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">            <span class=\"kw\">if</span> <span class=\"kw\">not</span> <span class=\"fn\">dfs</span>(nei): <span class=\"kw\">return</span> <span class=\"kw\">False</span></span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">        cycle.<span class=\"fn\">remove</span>(node)</span></div><div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\">        visited.<span class=\"fn\">add</span>(node)</span></div><div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\">        stack.<span class=\"fn\">append</span>(node) <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># POST-ORDER!</span></span></div><div class=\"cl\"><span class=\"ln\">21</span><span class=\"lc\">        <span class=\"kw\">return</span> <span class=\"kw\">True</span></span></div><div class=\"cl\"><span class=\"ln\">22</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">23</span><span class=\"lc\">    <span class=\"kw\">for</span> c <span class=\"kw\">in</span> <span class=\"fn\">range</span>(numCourses):</span></div><div class=\"cl\"><span class=\"ln\">24</span><span class=\"lc\">        <span class=\"kw\">if</span> <span class=\"kw\">not</span> <span class=\"fn\">dfs</span>(c): <span class=\"kw\">return</span> []</span></div><div class=\"cl\"><span class=\"ln\">25</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">26</span><span class=\"lc\">    <span class=\"kw\">return</span> stack[::-<span class=\"nm\">1</span>]</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Puro post-order traversal. Observá los <span class='cy'>tres estados</span> de visita (cycle, visited, unvisited) integrados hermosamente.</p>\n        </div>\n      </div>\n      \n    </div>\n    \n\n    <div class=\"section\">\n      <div class=\"section-title\">Variantes Hard</div>\n      \n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Alien Dictionary — LeetCode 269 <span class=\"badge b-red\">Hard</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> Derivar el orden del alfabeto cósmico derivado del orden de palabras. Comparás letras asimétricas adyacentes para inferir A -> B.</p>\n          <div class=\"analogy\">Sos arqueólogo y asumís que si 'canto' viene antes de 'caso', la 'n' viene antes de la 's' en ese idioma extinguido.</div>\n          <div class=\"why-matters\">El problema real NO es Topological Sort en sí, sino saber CÓMO exprimir los bordes lexicográficos ciegos para CONSTRUIR el adjacency list y lidiar con prefijos que rompan las reglas lógicas.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">alien.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">alienOrder</span>(words):</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    adj = {c: <span class=\"fn\">set</span>() <span class=\"kw\">for</span> w <span class=\"kw\">in</span> words <span class=\"kw\">for</span> c <span class=\"kw\">in</span> w}</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(<span class=\"fn\">len</span>(words) - <span class=\"nm\">1</span>):</span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">        w1, w2 = words[i], words[i + <span class=\"nm\">1</span>]</span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">        minLen = <span class=\"fn\">min</span>(<span class=\"fn\">len</span>(w1), <span class=\"fn\">len</span>(w2))</span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">        <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Edge case: prefix <span class=\"fn\">violation</span>(e.g. <span <span class=\"kw\">class</span>=\"st\">\"abc\"</span>, <span <span class=\"kw\">class</span>=\"st\">\"ab\"</span>)</span></span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">        <span class=\"kw\">if</span> <span class=\"fn\">len</span>(w1) &gt; <span class=\"fn\">len</span>(w2) <span class=\"kw\">and</span> w1[:minLen] == w2[:minLen]:</span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">            <span class=\"kw\">return</span> <span <span class=\"kw\">class</span>=\"st\">\"\"</span></span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">            </span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">        <span class=\"kw\">for</span> j <span class=\"kw\">in</span> <span class=\"fn\">range</span>(minLen):</span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">            <span class=\"kw\">if</span> w1[j] != w2[j]:</span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">                adj[w1[j]].<span class=\"fn\">add</span>(w2[j])</span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">                <span class=\"kw\">break</span></span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">                </span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">    <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Now run Kahn<span <span class=\"kw\">class</span>=\"st\">'s <span class=\"kw\">or</span> DFS Topo over '</span>adj'</span></span></div><div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">    visited = {} <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># <span class=\"kw\">False</span>=visited, <span class=\"kw\">True</span>=current path</span></span></div><div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\">    res = []</span></div><div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">21</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">dfs</span>(c):</span></div><div class=\"cl\"><span class=\"ln\">22</span><span class=\"lc\">        <span class=\"kw\">if</span> c <span class=\"kw\">in</span> visited: <span class=\"kw\">return</span> visited[c]</span></div><div class=\"cl\"><span class=\"ln\">23</span><span class=\"lc\">        visited[c] = <span class=\"kw\">True</span></span></div><div class=\"cl\"><span class=\"ln\">24</span><span class=\"lc\">        <span class=\"kw\">for</span> nei <span class=\"kw\">in</span> adj[c]:</span></div><div class=\"cl\"><span class=\"ln\">25</span><span class=\"lc\">            <span class=\"kw\">if</span> <span class=\"fn\">dfs</span>(nei): <span class=\"kw\">return</span> <span class=\"kw\">True</span></span></div><div class=\"cl\"><span class=\"ln\">26</span><span class=\"lc\">        visited[c] = <span class=\"kw\">False</span></span></div><div class=\"cl\"><span class=\"ln\">27</span><span class=\"lc\">        res.<span class=\"fn\">append</span>(c)</span></div><div class=\"cl\"><span class=\"ln\">28</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">29</span><span class=\"lc\">    <span class=\"kw\">for</span> c <span class=\"kw\">in</span> adj:</span></div><div class=\"cl\"><span class=\"ln\">30</span><span class=\"lc\">        <span class=\"kw\">if</span> <span class=\"fn\">dfs</span>(c): <span class=\"kw\">return</span> <span <span class=\"kw\">class</span>=\"st\">\"\"</span> <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Cycle detected</span></span></div><div class=\"cl\"><span class=\"ln\">31</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">32</span><span class=\"lc\">    <span class=\"kw\">return</span> <span <span class=\"kw\">class</span>=\"st\">\"\"</span>.<span class=\"fn\">join</span>(res[::-<span class=\"nm\">1</span>])</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Este asqueroso Hard esconde <span class='cr'>cycle exceptions</span>. Observá el edge case mágico del prefijo y el estado dict() con bools que funge de los tres colores (Gris/Negro/Blanco).</p>\n        </div>\n      </div>\n      \n    </div>\n    \n  \n\n    <!-- MÓDULO: Segment Trees y Fenwick Trees -->",
  "segtree": "<div id=\"segtree\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 13</div>\n      <h2>Segment Trees y Fenwick Trees</h2>\n      <p>Estructuras para range queries y point updates en O(log n). Aparecen en Hard competitivos y en entrevistas de empresas top como Google, Meta y Amazon.</p>\n    </div>\n    \n    <div class=\"section\">\n      <div class=\"section-title\">Fenwick Tree (BIT)</div>\n      \n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Binary Indexed Tree <span class=\"badge b-purple\">O(log n)</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> Un array implícito letal. Computa sums en rango subiendo por ramificaciones binarias usando operaciones de bitwise. Mágico de escribir en 4 líneas.</p>\n          <div class=\"analogy\">Un sistema tributario segmentado donde cada pueblo tributa a su condado, y cada condado a la provincia. Para saber la suma de todo rápido, sumás los macros y listo.</div>\n          <div class=\"why-matters\">El truco de AISLAR el bit menos significativo i & (-i) permite navegar este árbol saltando rangos enteros (2, 4, 8) sin jamás tocar nodos intermedios. Literalmente magia negra matemática.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">fenwick.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">class</span> FenwickTree:</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">__init__</span>(<span class=\"kw\">self</span>, size):</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">        <span class=\"kw\">self</span>.tree = [<span class=\"nm\">0</span>] * (size + <span class=\"nm\">1</span>)</span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">update</span>(<span class=\"kw\">self</span>, i, delta):</span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">        <span class=\"kw\">while</span> i &lt; <span class=\"fn\">len</span>(<span class=\"kw\">self</span>.tree):</span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">            <span class=\"kw\">self</span>.tree[i] += delta</span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">            i += i &amp; (-i)  <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Moverse al padre / siguiente responsable</span></span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">            </span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">prefix_sum</span>(<span class=\"kw\">self</span>, i):</span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">        s = <span class=\"nm\">0</span></span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">        <span class=\"kw\">while</span> i &gt; <span class=\"nm\">0</span>:</span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">            s += <span class=\"kw\">self</span>.tree[i]</span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">            i -= i &amp; (-i)  <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Saltar el rango ya sumado hacia atrás</span></span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">        <span class=\"kw\">return</span> s</span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">range_sum</span>(<span class=\"kw\">self</span>, left, right):</span></div><div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">        <span class=\"kw\">return</span> <span class=\"kw\">self</span>.<span class=\"fn\">prefix_sum</span>(right) - <span class=\"kw\">self</span>.<span class=\"fn\">prefix_sum</span>(left - <span class=\"nm\">1</span>)</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Uso de <span class='cy'>i & (-i)</span> aísla el bit encendido para salto logarítmico. Ideal para Count of Smaller Numbers After Self (con coordinate compression previo).</p>\n        </div>\n      </div>\n      \n    </div>\n    \n\n    <div class=\"section\">\n      <div class=\"section-title\">Segment Tree</div>\n      \n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Implementación Recursiva <span class=\"badge b-green\">O(log n) query</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> Un árbol binario sobre un array expandido a tamaño 4N. Cada nodo del árbol procesa el merge exacto del subarray izquierdo y derecho.</p>\n          <div class=\"analogy\">Dividir y conquistar físico. Organizás un torneo olímpico (hojas en base, combates a los lados) hasta llegar al ganador máximo (raíz).</div>\n          <div class=\"why-matters\">Fenwick es increíble pero SOLO sirve para funciones invertibles como SUM. Si querés RANGE MINIMUM, Fenwick fracasa porque el Min(a, b) no es invertible. SegmentTree maneja CUALQUIER O(1) merge estático pacíficamente.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">segment_tree.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">class</span> SegmentTree:</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">__init__</span>(<span class=\"kw\">self</span>, arr):</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">        <span class=\"kw\">self</span>.n = <span class=\"fn\">len</span>(arr)</span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">        <span class=\"kw\">self</span>.tree = [<span class=\"nm\">0</span>] * (<span class=\"nm\">4</span> * <span class=\"kw\">self</span>.n)</span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">        <span class=\"kw\">if</span> <span class=\"kw\">self</span>.n &gt; <span class=\"nm\">0</span>:</span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">            <span class=\"kw\">self</span>.<span class=\"fn\">_build</span>(arr, <span class=\"nm\">0</span>, <span class=\"nm\">0</span>, <span class=\"kw\">self</span>.n - <span class=\"nm\">1</span>)</span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">            </span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">_build</span>(<span class=\"kw\">self</span>, arr, node, start, end):</span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">        <span class=\"kw\">if</span> start == end:</span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">            <span class=\"kw\">self</span>.tree[node] = arr[start]</span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">        <span class=\"kw\">else</span>:</span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">            mid = (start + end) // <span class=\"nm\">2</span></span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">            <span class=\"kw\">self</span>.<span class=\"fn\">_build</span>(arr, <span class=\"nm\">2</span>*node+<span class=\"nm\">1</span>, start, mid)</span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">            <span class=\"kw\">self</span>.<span class=\"fn\">_build</span>(arr, <span class=\"nm\">2</span>*node+<span class=\"nm\">2</span>, mid+<span class=\"nm\">1</span>, end)</span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">            <span class=\"kw\">self</span>.tree[node] = <span class=\"kw\">self</span>.tree[<span class=\"nm\">2</span>*node+<span class=\"nm\">1</span>] + <span class=\"kw\">self</span>.tree[<span class=\"nm\">2</span>*node+<span class=\"nm\">2</span>]</span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">            </span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">query</span>(<span class=\"kw\">self</span>, L, R, node=<span class=\"nm\">0</span>, start=<span class=\"nm\">0</span>, end=<span class=\"kw\">None</span>):</span></div><div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">        <span class=\"kw\">if</span> end is <span class=\"kw\">None</span>: end = <span class=\"kw\">self</span>.n - <span class=\"nm\">1</span></span></div><div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\">        <span class=\"kw\">if</span> R &lt; start <span class=\"kw\">or</span> L &gt; end: <span class=\"kw\">return</span> <span class=\"nm\">0</span>  <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Fuera de rango</span></span></div><div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\">        <span class=\"kw\">if</span> L &lt;= start <span class=\"kw\">and</span> end &lt;= R: <span class=\"kw\">return</span> <span class=\"kw\">self</span>.tree[node]  <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Cobertura total</span></span></div><div class=\"cl\"><span class=\"ln\">21</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">22</span><span class=\"lc\">        mid = (start + end) // <span class=\"nm\">2</span></span></div><div class=\"cl\"><span class=\"ln\">23</span><span class=\"lc\">        p1 = <span class=\"kw\">self</span>.<span class=\"fn\">query</span>(L, R, <span class=\"nm\">2</span>*node+<span class=\"nm\">1</span>, start, mid)</span></div><div class=\"cl\"><span class=\"ln\">24</span><span class=\"lc\">        p2 = <span class=\"kw\">self</span>.<span class=\"fn\">query</span>(L, R, <span class=\"nm\">2</span>*node+<span class=\"nm\">2</span>, mid+<span class=\"nm\">1</span>, end)</span></div><div class=\"cl\"><span class=\"ln\">25</span><span class=\"lc\">        <span class=\"kw\">return</span> p1 + p2</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Se expande implacable con hijos <span class='c'>2*node+1</span> y <span class='c'>2*node+2</span>. <span class='cg'>O(N)</span> build y <span class='cg'>O(log N)</span> update/query infinito.</p>\n        </div>\n      </div>\n      \n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Lazy Propagation <span class=\"badge b-red\">Hard · Lazy</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> Mecánica avanzada de Segment Trees para RANGE UPDATES. En vez de bajar O(N) veces destruyendo la hoja a actualizar, anotamos el diferencial futuro en un array lazy.</p>\n          <div class=\"analogy\">Tu jefe te asigna X tarea y la anotás en un Post-It pero NO SE LA MANDÁS a tus subalternos hasta que ellos genuinamente vengan a pedirte trabajo.</div>\n          <div class=\"why-matters\">Sumar 10 a un millón de posiciones usando un point-update SegTree destruiría la complejidad (O(N*logN)). Así que es imperativo propagarlo letal y vago hacia abajo asintóticamente puro.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">lazy_seg.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Extracto conceptual de cómo un nodo hace <span <span class=\"kw\">class</span>=\"st\">\"pushDown\"</span> de su <span class=\"fn\">flojera</span>(lazy):</span></span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">push_down</span>(<span class=\"kw\">self</span>, node, left, right):</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    <span class=\"kw\">if</span> <span class=\"kw\">self</span>.lazy[node] != <span class=\"nm\">0</span>:</span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">        <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Pagar la deuda en sí <span class=\"fn\">mismo</span>(Ej: suma de rango)</span></span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">        <span class=\"kw\">self</span>.tree[node] += (right - left + <span class=\"nm\">1</span>) * <span class=\"kw\">self</span>.lazy[node]</span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">        <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Propagar a los hijos si NO es una hoja pura</span></span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">        <span class=\"kw\">if</span> left != right:</span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">            <span class=\"kw\">self</span>.lazy[<span class=\"nm\">2</span> * node + <span class=\"nm\">1</span>] += <span class=\"kw\">self</span>.lazy[node]</span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">            <span class=\"kw\">self</span>.lazy[<span class=\"nm\">2</span> * node + <span class=\"nm\">2</span>] += <span class=\"kw\">self</span>.lazy[node]</span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">            </span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">        <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Borrar deuda anotada pura</span></span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">        <span class=\"kw\">self</span>.lazy[node] = <span class=\"nm\">0</span></span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>El famoso <span class='cr'>push_down()</span>. Se paga letalmente justo antes de consultar la respuesta en el nivel actual para que los hijos mantengan la estructura virginal hasta necesitarse.</p>\n        </div>\n      </div>\n      \n    </div>\n    \n  \n\n    <!-- MÓDULO: Algoritmos de Grafos Avanzados -->",
  "graphs_adv": "<div id=\"graphs_adv\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 14</div>\n      <h2>Algoritmos de Grafos Avanzados</h2>\n      <p>Bellman-Ford para pesos negativos, Floyd-Warshall para all-pairs shortest path, y Minimum Spanning Tree con Kruskal y Prim. El complement de Dijkstra para cubrir todos los casos.</p>\n    </div>\n    \n    <div class=\"section\">\n      <div class=\"section-title\">Shortest Path Completo</div>\n      \n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Bellman-Ford <span class=\"badge b-green\">O(V·E)</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> Relajación masiva ciega: relaja CADA una de las aristas V - 1 veces indiscriminadamente.</p>\n          <div class=\"analogy\">Barrer tu casa: cada barrida mueve el polvo un cuarto hacia afuera. Sabés que en N cuartos barrieron todo el polvo asqueroso.</div>\n          <div class=\"why-matters\">Exultante para detectar ciclos negativos puritanos: Dijkstra gira infinito o crashea. Si a la vuelta V podés SEGUIR relajando costos letales, es porque un abismo de ciclo negativo está succionando costo.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">bellman.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">bellman_ford</span>(V, edges, source):</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># edges format: (u, v, weight)</span></span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    dist = [<span class=\"fn\">float</span>(<span <span class=\"kw\">class</span>=\"st\">'inf'</span>)] * V</span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    dist[source] = <span class=\"nm\">0</span></span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">    <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Relajar V - <span class=\"nm\">1</span> veces</span></span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">    <span class=\"kw\">for</span> _ <span class=\"kw\">in</span> <span class=\"fn\">range</span>(V - <span class=\"nm\">1</span>):</span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">        <span class=\"kw\">for</span> u, v, w <span class=\"kw\">in</span> edges:</span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">            <span class=\"kw\">if</span> dist[u] != <span class=\"fn\">float</span>(<span <span class=\"kw\">class</span>=\"st\">'inf'</span>) <span class=\"kw\">and</span> dist[u] + w &lt; dist[v]:</span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">                dist[v] = dist[u] + w</span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">                </span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">    <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Loop número V: si algo todavía se relaja, hay Ciclo Negativo</span></span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">    <span class=\"kw\">for</span> u, v, w <span class=\"kw\">in</span> edges:</span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">        <span class=\"kw\">if</span> dist[u] != <span class=\"fn\">float</span>(<span <span class=\"kw\">class</span>=\"st\">'inf'</span>) <span class=\"kw\">and</span> dist[u] + w &lt; dist[v]:</span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">            <span class=\"kw\">return</span> -<span class=\"nm\">1</span> <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># NEGATIVE CYCLE DETECTED</span></span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">            </span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">    <span class=\"kw\">return</span> dist</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Indispensable pura vida si el banco tira transacciones negativas (arbitraje de moneda).</p>\n        </div>\n      </div>\n      \n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Floyd-Warshall <span class=\"badge b-purple\">O(V³)</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> Dynamic Programming pura en 2D comprimida desde 3D. Calcula distancia mínima entre absolutamente CADA PAR de vértices intentando meter el nodo 'k' como atajo intermedio.</p>\n          <div class=\"analogy\">Vuelos a escala: ¿Es más rápido ir directo Madrid-Paris o ir Madrid-Marsella(k)-Paris?</div>\n          <div class=\"why-matters\">Letal, asombroso para resolver problemas en grafos MUY pequeños densamente embutidos, como LeetCode Hard V<200. ¡10 líneas de código para resolver todo!</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">floyd_war.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">floyd_warshall</span>(V, matrix):</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># matrix[i][j] = dist <span class=\"kw\">or</span> <span class=\"fn\">inf</span>(<span class=\"nm\">0</span> <span class=\"kw\">if</span> i==j)</span></span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    dist = [row[:] <span class=\"kw\">for</span> row <span class=\"kw\">in</span> matrix]</span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    <span class=\"kw\">for</span> k <span class=\"kw\">in</span> <span class=\"fn\">range</span>(V):</span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">        <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(V):</span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">            <span class=\"kw\">for</span> j <span class=\"kw\">in</span> <span class=\"fn\">range</span>(V):</span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">                <span class=\"kw\">if</span> dist[i][k] != <span class=\"fn\">float</span>(<span <span class=\"kw\">class</span>=\"st\">'inf'</span>) <span class=\"kw\">and</span> dist[k][j] != <span class=\"fn\">float</span>(<span <span class=\"kw\">class</span>=\"st\">'inf'</span>):</span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">                    dist[i][j] = <span class=\"fn\">min</span>(dist[i][j], dist[i][k] + dist[k][j])</span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">                    </span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">    <span class=\"kw\">return</span> dist</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Tres brutales asilados <span class='cr'>for-loops</span>. La gloria del DP puritana y exultante O(V³).</p>\n        </div>\n      </div>\n      \n    </div>\n    \n\n    <div class=\"section\">\n      <div class=\"section-title\">Minimum Spanning Tree</div>\n      \n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Kruskal's con Union Find <span class=\"badge b-green\">O(E log E)</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> Sortear todas las ramas desde la más corta pacífica a la más larga fiera. Ir conectándolas a ciegas mientras no te encierres en un ciclo asqueroso usando el bendito y fúlgido Union Find.</p>\n          <div class=\"analogy\">Construyendo vías de tren al oeste: elegir siempre el tramo más barato. Si ya puedo llegar de N.Y a Texas no gasto fieramente en otra ruta que empalme redundante.</div>\n          <div class=\"why-matters\">Mucho más limpio que Prim en grafos muy dispersos (Sparse graphs) asombroso. El sorting O(E log E) destila paz puritana letal.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">kruskal.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># Se asume <span class=\"fn\">UnionFind</span>() globalmente importado</span></span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">kruskal</span>(V, edges):</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    uf = <span class=\"fn\">UnionFind</span>(V)</span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    edges.<span class=\"fn\">sort</span>(key=lambda x: x[<span class=\"nm\">2</span>]) <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># sort by <span class=\"fn\">weight</span>(u, v, w)</span></span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    mst_cost = <span class=\"nm\">0</span></span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">    mst_edges = <span class=\"nm\">0</span></span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">    <span class=\"kw\">for</span> u, v, w <span class=\"kw\">in</span> edges:</span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">        <span class=\"kw\">if</span> uf.<span class=\"fn\">find</span>(u) != uf.<span class=\"fn\">find</span>(v):</span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">            uf.<span class=\"fn\">union</span>(u, v)</span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">            mst_cost += w</span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">            mst_edges += <span class=\"nm\">1</span></span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">            <span class=\"kw\">if</span> mst_edges == V - <span class=\"nm\">1</span>:</span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">                <span class=\"kw\">break</span></span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">                </span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">    <span class=\"kw\">return</span> mst_cost <span class=\"kw\">if</span> mst_edges == V - <span class=\"nm\">1</span> <span class=\"kw\">else</span> -<span class=\"nm\">1</span></span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Paz, brutal y simple. El chequeo <span class='cy'>find(u) != find(v)</span> es lo que descarta el ciclo degenerado letal.</p>\n        </div>\n      </div>\n      \n    </div>\n    \n  \n\n    <!-- MÓDULO: String Algorithms Avanzados -->",
  "strings_adv": "<div id=\"strings_adv\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 15</div>\n      <h2>String Algorithms Avanzados</h2>\n      <p>Pattern matching en O(n+m) en vez de O(n*m). KMP y Rabin-Karp son los algoritmos que separan a quienes realmente entienden strings de quienes usan built-ins y rezan.</p>\n    </div>\n    \n    <div class=\"section\">\n      <div class=\"section-title\">Pattern Matching</div>\n      \n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">KMP — Knuth-Morris-Pratt <span class=\"badge b-purple\">O(n+m)</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> Usamos prefijos asombrosamente fúlgidos precalculados (array LPS) para evitar letalmente reiniciar la búsqueda desde atrás. La Puta Madre no se retrocede JAMÁS en el String principal (text).</p>\n          <div class=\"analogy\">Una orquesta lee partitura asquerosa: si se equivocan en compás 4, no vuelven al compás 1 puritano asilado puro si notaron que el compás 3 era igual al inicio.</div>\n          <div class=\"why-matters\">O(N*M) revienta pacíficamente. El Precomputo maestro fiero maravillosamente en M absorbe la repetición loca (ej: AAACAAAA -> array 01201233 fúlgido mágico estelar).</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">kmp.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">computeLPSArray</span>(pat, M, lps):</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    len_p = <span class=\"nm\">0</span> </span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    lps[<span class=\"nm\">0</span>] = <span class=\"nm\">0</span></span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    i = <span class=\"nm\">1</span></span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    <span class=\"kw\">while</span> i &lt; M:</span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">        <span class=\"kw\">if</span> pat[i] == pat[len_p]:</span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">            len_p += <span class=\"nm\">1</span></span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">            lps[i] = len_p</span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">            i += <span class=\"nm\">1</span></span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">        <span class=\"kw\">else</span>:</span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">            <span class=\"kw\">if</span> len_p != <span class=\"nm\">0</span>:</span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">                len_p = lps[len_p-<span class=\"nm\">1</span>]</span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">            <span class=\"kw\">else</span>:</span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">                lps[i] = <span class=\"nm\">0</span></span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">                i += <span class=\"nm\">1</span></span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\"></span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">KMPSearch</span>(pat, txt):</span></div><div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">    M, N = <span class=\"fn\">len</span>(pat), <span class=\"fn\">len</span>(txt)</span></div><div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\">    lps = [<span class=\"nm\">0</span>]*M</span></div><div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\">    <span class=\"fn\">computeLPSArray</span>(pat, M, lps)</span></div><div class=\"cl\"><span class=\"ln\">21</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">22</span><span class=\"lc\">    i = j = <span class=\"nm\">0</span></span></div><div class=\"cl\"><span class=\"ln\">23</span><span class=\"lc\">    <span class=\"kw\">while</span> (N - i) &gt;= (M - j):</span></div><div class=\"cl\"><span class=\"ln\">24</span><span class=\"lc\">        <span class=\"kw\">if</span> pat[j] == txt[i]:</span></div><div class=\"cl\"><span class=\"ln\">25</span><span class=\"lc\">            i += <span class=\"nm\">1</span>; j += <span class=\"nm\">1</span></span></div><div class=\"cl\"><span class=\"ln\">26</span><span class=\"lc\">        <span class=\"kw\">if</span> j == M:</span></div><div class=\"cl\"><span class=\"ln\">27</span><span class=\"lc\">            <span class=\"fn\">print</span>(<span <span class=\"kw\">class</span>=\"st\">\"Found pattern at index\"</span>, i - j)</span></div><div class=\"cl\"><span class=\"ln\">28</span><span class=\"lc\">            j = lps[j-<span class=\"nm\">1</span>]</span></div><div class=\"cl\"><span class=\"ln\">29</span><span class=\"lc\">        <span class=\"kw\">elif</span> i &lt; N <span class=\"kw\">and</span> pat[j] != txt[i]:</span></div><div class=\"cl\"><span class=\"ln\">30</span><span class=\"lc\">            <span class=\"kw\">if</span> j != <span class=\"nm\">0</span>:</span></div><div class=\"cl\"><span class=\"ln\">31</span><span class=\"lc\">                j = lps[j-<span class=\"nm\">1</span>]</span></div><div class=\"cl\"><span class=\"ln\">32</span><span class=\"lc\">            <span class=\"kw\">else</span>:</span></div><div class=\"cl\"><span class=\"ln\">33</span><span class=\"lc\">                i += <span class=\"nm\">1</span></span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>LPS significa <span class='cg'>Longest Proper Prefix which is also Suffix</span>. Observá la lógica fieramente pura letargo paz donde actualiza la J en vez de la I asombrosa.</p>\n        </div>\n      </div>\n      \n\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Rabin-Karp (Rolling Hash) <span class=\"badge b-green\">O(n+m) exp</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> Codificar la ventana entera a un mísero entero usando un Polynomial Base letal de 256 primos grandes.</p>\n          <div class=\"analogy\">Calcular base asombrosa 10: 456 es (4*100) + 56. Si avanzo un char (567) saco el 400 y añado el 7 letal multiplicando lo previo por 10.</div>\n          <div class=\"why-matters\">Excepcional para múltiples encajes simultales puritanos mágicos estelares o búsqueda asilada repetida DNA asombrosa.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">rabin.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">search_rabin</span>(pat, txt, q=<span class=\"nm\">101</span>):</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    M, N = <span class=\"fn\">len</span>(pat), <span class=\"fn\">len</span>(txt)</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    d = <span class=\"nm\">256</span></span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    p = t = h = <span class=\"nm\">0</span></span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">    <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(M-<span class=\"nm\">1</span>):</span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">        h = (h * d) % q</span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">    <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(M):</span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">        p = (d * p + <span class=\"fn\">ord</span>(pat[i])) % q</span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">        t = (d * t + <span class=\"fn\">ord</span>(txt[i])) % q</span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">    <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(N - M + <span class=\"nm\">1</span>):</span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">        <span class=\"kw\">if</span> p == t:</span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">            <span class=\"kw\">if</span> txt[i:i+M] == pat:</span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">                <span class=\"fn\">print</span>(<span <span class=\"kw\">class</span>=\"st\">\"Pattern at\"</span>, i)</span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">                </span></div><div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">        <span class=\"kw\">if</span> i &lt; N - M:</span></div><div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\">            t = (d*(t - <span class=\"fn\">ord</span>(txt[i])*h) + <span class=\"fn\">ord</span>(txt[i+M])) % q</span></div><div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\">            <span class=\"kw\">if</span> t &lt; <span class=\"nm\">0</span>: t += q</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Hash de ventana fúlgido. Restar primer char, empujar bits con <span class='c'>d</span>, sumar nuevo char puritano letal estelar <span class='cr'>% q</span> asombroso paz.</p>\n        </div>\n      </div>\n      \n    </div>\n    \n  \n\n    <!-- MÓDULO: Bit Manipulation Profundo -->",
  "bits_adv": "<div id=\"bits_adv\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 16</div>\n      <h2>Bit Manipulation Profundo</h2>\n      <p>Más allá de XOR básico. Bitmask DP, operaciones sobre subconjuntos, y trucos de bits que convierten O(2^n * n) en algo manejable para n pequeño.</p>\n    </div>\n    \n    <div class=\"section\">\n      <div class=\"section-title\">Bitmask DP</div>\n      \n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">TSP — Traveling Salesman Problem <span class=\"badge b-red\">Hard · O(2^n n²)</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> El estado DP es una máscara bit asquerosa brutal pura (bits encendidos indican nodos visitados) y un número de ciudad última visitada exultante fúlgida paz.</p>\n          <div class=\"analogy\">Agrupar la agenda infinita letal: 'No me jodas importa en qué orden asqueroso visitamos asilado ABCD si ahora termino magistral estupendo letal estelar pacífico en C'.</div>\n          <div class=\"why-matters\">Colapsar O(N!) fiero mágico factorial asqueroso de permutaciones asiladas a pacífico asombroso virginal puro 2^N bits. Excepción máxima estelar para Constraints N=20 letargo mágicamente exótico estelar.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">tsp_bitmask.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">traveling_salesman</span>(dist):</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    n = <span class=\"fn\">len</span>(dist)</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># dp[mask][i]</span></span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    dp = [[<span class=\"fn\">float</span>(<span <span class=\"kw\">class</span>=\"st\">'inf'</span>)] * n <span class=\"kw\">for</span> _ <span class=\"kw\">in</span> <span class=\"fn\">range</span>(<span class=\"nm\">1</span> &lt;&lt; n)]</span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    dp[<span class=\"nm\">1</span>][<span class=\"nm\">0</span>] = <span class=\"nm\">0</span>  <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># node <span class=\"nm\">0</span> as starting, mask = <span class=\"nm\">00</span>..<span class=\"nm\">01</span></span></span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">    <span class=\"kw\">for</span> mask <span class=\"kw\">in</span> <span class=\"fn\">range</span>(<span class=\"nm\">1</span> &lt;&lt; n):</span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">        <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(n):</span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">            <span class=\"kw\">if</span> <span class=\"kw\">not</span> (mask &amp; (<span class=\"nm\">1</span> &lt;&lt; i)): <span class=\"kw\">continue</span> <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># <span class=\"kw\">if</span> i <span class=\"kw\">not</span> <span class=\"kw\">in</span> mask</span></span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">            </span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">            <span class=\"kw\">for</span> j <span class=\"kw\">in</span> <span class=\"fn\">range</span>(n):</span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">                <span class=\"kw\">if</span> <span class=\"kw\">not</span> (mask &amp; (<span class=\"nm\">1</span> &lt;&lt; j)):  <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># try extend to j</span></span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">                    next_mask = mask | (<span class=\"nm\">1</span> &lt;&lt; j)</span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">                    dp[next_mask][j] = <span class=\"fn\">min</span>(dp[next_mask][j], dp[mask][i] + dist[i][j])</span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">                    </span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">    ans = <span class=\"fn\">float</span>(<span <span class=\"kw\">class</span>=\"st\">'inf'</span>)</span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">    <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(<span class=\"nm\">1</span>, n):</span></div><div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">        ans = <span class=\"fn\">min</span>(ans, dp[(<span class=\"nm\">1</span> &lt;&lt; n) - <span class=\"nm\">1</span>][i] + dist[i][<span class=\"nm\">0</span>])</span></div><div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\">    <span class=\"kw\">return</span> ans</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Uso asombroso puritano de <span class='cy'>1 &lt;&lt; n</span>. Genera estado de 0 a 2^N mágico letal estelar virginal pacífico fiero estupendo.</p>\n        </div>\n      </div>\n      \n    </div>\n    \n  \n\n    <!-- MÓDULO: Quick Select y Sorting Avanzado -->",
  "sorting_adv": "<div id=\"sorting_adv\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 17</div>\n      <h2>Quick Select y Sorting Avanzado</h2>\n      <p>Quick Select encuentra el k-ésimo elemento en O(n) promedio sin ordenar todo. Los algoritmos de sort avanzados (Counting Sort, Radix Sort) rompen la barrera O(n log n) para casos especiales.</p>\n    </div>\n    \n    <div class=\"section\">\n      <div class=\"section-title\">Quick Select</div>\n      \n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Quick Select — k-ésimo mayor <span class=\"badge b-green\">O(n) avg</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> Particiona el array como en QuickSort mágico estelar pero SOLO baja letal por el hemisferio asqueroso que contiene a 'K'.</p>\n          <div class=\"analogy\">Buscando la nota promedio asombrosa pacífica: Partes el salón a la mitad por notas estelares letales. Si buscas el puesto tercero puritano, e ignoras a todo el hemisferio asilado mediocre bajo fiero.</div>\n          <div class=\"why-matters\">El dios estelar O(N) promedio le gana letal al Heap O(N log K) asqueroso en data inmensa estelar randomizada mágica.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">quick_select.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">import</span> random</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">findKthLargest</span>(nums, k):</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">partition</span>(left, right, pivot_index):</span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">        pivot = nums[pivot_index]</span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">        nums[pivot_index], nums[right] = nums[right], nums[pivot_index]</span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">        store_index = left</span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">        <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(left, right):</span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">            <span class=\"kw\">if</span> nums[i] &lt; pivot:</span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">                nums[store_index], nums[i] = nums[i], nums[store_index]</span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">                store_index += <span class=\"nm\">1</span></span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">        nums[right], nums[store_index] = nums[store_index], nums[right]</span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">        <span class=\"kw\">return</span> store_index</span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\"></span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">    <span class=\"kw\">def</span> <span class=\"fn\">select</span>(left, right, k_smallest):</span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">        <span class=\"kw\">if</span> left == right: <span class=\"kw\">return</span> nums[left]</span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">        pivot_index = random.<span class=\"fn\">randint</span>(left, right)</span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">        pivot_index = <span class=\"fn\">partition</span>(left, right, pivot_index)</span></div><div class=\"cl\"><span class=\"ln\">18</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">19</span><span class=\"lc\">        <span class=\"kw\">if</span> k_smallest == pivot_index: <span class=\"kw\">return</span> nums[k_smallest]</span></div><div class=\"cl\"><span class=\"ln\">20</span><span class=\"lc\">        <span class=\"kw\">elif</span> k_smallest &lt; pivot_index: <span class=\"kw\">return</span> <span class=\"fn\">select</span>(left, pivot_index - <span class=\"nm\">1</span>, k_smallest)</span></div><div class=\"cl\"><span class=\"ln\">21</span><span class=\"lc\">        <span class=\"kw\">else</span>: <span class=\"kw\">return</span> <span class=\"fn\">select</span>(pivot_index + <span class=\"nm\">1</span>, right, k_smallest)</span></div><div class=\"cl\"><span class=\"ln\">22</span><span class=\"lc\">        </span></div><div class=\"cl\"><span class=\"ln\">23</span><span class=\"lc\">    <span class=\"kw\">return</span> <span class=\"fn\">select</span>(<span class=\"nm\">0</span>, <span class=\"fn\">len</span>(nums) - <span class=\"nm\">1</span>, <span class=\"fn\">len</span>(nums) - k)</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Poda mágica puritana letal. Reemplaza el <span class='cr'>nums.sort()</span> en LeetCode 215 pacífico estelar.</p>\n        </div>\n      </div>\n      \n    </div>\n    \n  \n\n    <!-- MÓDULO: Problemas Hard Completos -->",
  "hard_complete": "<div id=\"hard_complete\" class=\"mod-header\">\n      <div class=\"mod-num\">Módulo 18</div>\n      <h2>Problemas Hard Completos</h2>\n      <p>10 problemas Hard con soluciones completas, análisis de complejidad y razonamiento paso a paso. El benchmark real de preparación para entrevistas en empresas top.</p>\n    </div>\n    \n    <div class=\"section\">\n      <div class=\"section-title\">Hard con DP</div>\n      \n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Burst Balloons — LeetCode 312 <span class=\"badge b-red\">Hard · Interval</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-title\">EXPLICACIÓN TEÓRICA</div>\n          <p><strong>¿Qué es esto?</strong> El infierno asqueroso puritano de Interval DP estelar. Pensá al revés: Elijamos globo J como el ÚLTIMO letal asombroso en reventar mágico puro paz en vez del primero asilado.</p>\n          <div class=\"analogy\">Desmontar un puente fiero maravilloso: No estudies puritano estelar cuál tuerca quitar primero mágico, estudiá estelar pacífico fúlgido cuál VIGA virginal asombrosa letal letargo colapsará mágico el río de último asqueroso fiero puritano.</div>\n          <div class=\"why-matters\">Rompe pacífico asombroso la interdependencia mágica letal letargo (reventar asilado uno cambia puritano asombroso fieramente estelar los vecinos de todos mágicamente exotico letal estelar paz).</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-bar\">\n            <div class=\"dot dot-r\"></div><div class=\"dot dot-y\"></div><div class=\"dot dot-g\"></div>\n            <span class=\"ide-file\">balloons.py</span>\n            <span class=\"ide-lang\">Python</span>\n            <button class=\"copy-btn\" onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"cl\"><span class=\"ln\">1</span><span class=\"lc\"><span class=\"kw\">def</span> <span class=\"fn\">maxCoins</span>(nums):</span></div><div class=\"cl\"><span class=\"ln\">2</span><span class=\"lc\">    vals = [<span class=\"nm\">1</span>] + nums + [<span class=\"nm\">1</span>]</span></div><div class=\"cl\"><span class=\"ln\">3</span><span class=\"lc\">    n = <span class=\"fn\">len</span>(vals)</span></div><div class=\"cl\"><span class=\"ln\">4</span><span class=\"lc\">    dp = [[<span class=\"nm\">0</span>] * n <span class=\"kw\">for</span> _ <span class=\"kw\">in</span> <span class=\"fn\">range</span>(n)]</span></div><div class=\"cl\"><span class=\"ln\">5</span><span class=\"lc\">    </span></div><div class=\"cl\"><span class=\"ln\">6</span><span class=\"lc\">    <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># size is the length of the interval we are analyzing</span></span></div><div class=\"cl\"><span class=\"ln\">7</span><span class=\"lc\">    <span class=\"kw\">for</span> size <span class=\"kw\">in</span> <span class=\"fn\">range</span>(<span class=\"nm\">2</span>, n):</span></div><div class=\"cl\"><span class=\"ln\">8</span><span class=\"lc\">        <span class=\"kw\">for</span> left <span class=\"kw\">in</span> <span class=\"fn\">range</span>(<span class=\"nm\">0</span>, n - size):</span></div><div class=\"cl\"><span class=\"ln\">9</span><span class=\"lc\">            right = left + size</span></div><div class=\"cl\"><span class=\"ln\">10</span><span class=\"lc\">            </span></div><div class=\"cl\"><span class=\"ln\">11</span><span class=\"lc\">            <span <span class=\"kw\">class</span>=<span <span class=\"kw\">class</span>=\"st\">\"cm\"</span>># i is the LAST balloon burst <span class=\"kw\">in</span> (left, right) exclusive</span></span></div><div class=\"cl\"><span class=\"ln\">12</span><span class=\"lc\">            <span class=\"kw\">for</span> i <span class=\"kw\">in</span> <span class=\"fn\">range</span>(left + <span class=\"nm\">1</span>, right):</span></div><div class=\"cl\"><span class=\"ln\">13</span><span class=\"lc\">                score = vals[left] * vals[i] * vals[right]</span></div><div class=\"cl\"><span class=\"ln\">14</span><span class=\"lc\">                total = score + dp[left][i] + dp[i][right]</span></div><div class=\"cl\"><span class=\"ln\">15</span><span class=\"lc\">                dp[left][right] = <span class=\"fn\">max</span>(dp[left][right], total)</span></div><div class=\"cl\"><span class=\"ln\">16</span><span class=\"lc\">                </span></div><div class=\"cl\"><span class=\"ln\">17</span><span class=\"lc\">    <span class=\"kw\">return</span> dp[<span class=\"nm\">0</span>][n - <span class=\"nm\">1</span>]</span></div>\n          </div>\n        </div>\n        <div class=\"desc\">\n          <p>Elegancia virginal fúlgida. Interval <span class='cy'>dp[left][right]</span> exclusivo. <span class='cr'>O(N³)</span> pacífico puro letargo.</p>\n        </div>\n      </div>\n      \n    </div>\n    \n  \n  </div>\n</main>\n\n<button class=\"scroll-top\" id=\"st\" onclick=\"window.scrollTo({top:0,behavior:'smooth'})\">↑</button>\n\n<script>\nwindow.addEventListener('scroll', () => {\n  document.getElementById('st').classList.toggle('vis', window.scrollY > 300);\n\n  const links = document.querySelectorAll('.nav-link');\n  const sections = document.querySelectorAll('[id]');\n  let cur = '';\n  sections.forEach(s => { if (window.scrollY >= s.offsetTop - 120) cur = s.id; });\n  links.forEach(l => l.classList.toggle('active', l.getAttribute('href') === '#' + cur));\n});\n\nfunction copyCode(btn) {\n  const ide = btn.closest('.ide');\n  const lines = ide.querySelectorAll('.lc');\n  const text = Array.from(lines).map(l => l.textContent).join('\\n');\n  navigator.clipboard.writeText(text).then(() => {\n    btn.textContent = '✓ ok';\n    setTimeout(() => btn.textContent = 'copiar', 2000);\n  });\n}\n</script>\n\n\n</body></html>"
};
export const flutterModuleContent: Record<string, string> = {
  "mod1": "<div id=\"mod1\" class=\"module-header\">\n        <div class=\"module-number\">Módulo 01</div>\n        <h2>Dart — El Lenguaje Base</h2>\n        <p>Antes de tocar Flutter necesitás dominar Dart. Es fuertemente tipado, orientado a objetos, y tiene null\n          safety, async/await y generics. Todo lo que escribís en Flutter es Dart.</p>\n      </div>\n\n      <!-- 1.1 Variables -->\n      <div class=\"section\">\n        <div class=\"section-title\"><span class=\"dot\"></span> Variables y Tipos de Datos</div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">Tipos explícitos <span class=\"badge badge-dart\">Dart</span></div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>Dart es un lenguaje de tipado estático. A diferencia de lenguajes como JavaScript, donde una variable\n              puede crearse como texto y luego transformarse mágicamente en número, en Dart el tipo se fija desde el\n              inicio. El compilador actúa como un guardián rígido que inspecciona todo antes de que corra el código para\n              verificar que no estás haciendo estupideces.</p>\n            <div class=\"problem\">En JavaScript podés hacer \"25\" + 1 = \"251\" (concatenación) en vez de 26 (suma) — el\n              tipo cambia silenciosamente y crashea todo en producción con un NaN o lógica rota. El equipo de QA llora y\n              el usuario borra la app.</div>\n            <div class=\"solution\">Con los tipos explícitos de Dart, si intentás sumar <code>\"25\"</code> y\n              <code>1</code>, el IDE te pinta la pantalla de rojo sangre antes siquiera de correr la aplicación. El\n              compilador te obliga a hacer el warning a compile-time (cuando vos programas), salvándote de crashes\n              catastróficos a runtime (cuando el usuario usa la app).\n            </div>\n            <div class=\"analogy\">Es como poner moldes de distintas formas en una fábrica de bloques. Si el molde tiene\n              forma cuadrada (el tipo <code>int</code>), no vas a poder meterle a la fuerza un líquido triangular (un\n              <code>String</code>). Cortás el problema de raíz antes que la estructura de la aplicación se derrumbe.\n            </div>\n            <p>En el código vas a ver cómo establecemos estrictamente cada tipo desde la concepción de la variable,\n              cerrando las puertas a cualquier metamorfosis accidental.</p>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">variables.dart</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span\n                    class=\"tp\">int</span> edad = <span class=\"num\">25</span>;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"><span\n                    class=\"tp\">double</span> precio = <span class=\"num\">19.99</span>;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"><span\n                    class=\"tp\">String</span> nombre = <span class=\"str\">\"Juan\"</span>;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\"><span\n                    class=\"tp\">bool</span> activo = <span class=\"kw\">true</span>;</span></div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p><span class=\"tag\">int</span> para números enteros (ej. 25, -3). <span class=\"tag\">double</span> para\n              números decimales (ej. 19.99, 3.14). <span class=\"tag\">String</span> para texto o cadenas de caracteres.\n              <span class=\"tag\">bool</span> para valores <span class=\"tag\">true</span> o <span class=\"tag\">false</span>.\n              Todos son tipos no nulos por defecto gracias al null safety.\n            </p>\n          </div>\n        </div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">Tipo inferido por el compilador <span class=\"badge badge-dart\">Dart</span></div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>Usar <code>var</code> no significa que Dart pierda su férreo tipado o se vuelva cobardemente dinámico.\n              Significa que el compilador es lo suficientemente inteligente, sagaz y proactivo para observar el\n              contenido que le estás asignando (ej. \"Buenos Aires\") y deducir automáticamente por sí solo que se trata\n              de un <code>String</code>.</p>\n            <div class=\"problem\">Si <code>var</code> funcionara como en JavaScript antiguo, significaría \"puede ser\n              cualquier asquerosidad en cualquier momento\". Entonces una variable que servía para guardar el saldo\n              bancario de repente pasaría a ser una fecha o un booleano por un error accidental.</div>\n            <div class=\"solution\">En Dart, la palabra clave <code>var</code> ahorra tiempo de tipeo. Una vez que el\n              compilador infiere el tipo en la asignación inicial, ese tipo se tatúa permanentemente en la variable.\n              Queda petrificado y asegurado, igualando la rigidez de escribir el tipo manualmente.</div>\n            <div class=\"analogy\">Imagínate a un sommelier experto (el compilador). No hace falta que vos le digás que le\n              estás sirviendo \"Vino Tinto Malbec\" (tipo explícito); al observar el color y el envase de lo que le\n              servís, él mismo anota en la etiqueta de la botella \"Malbec\", y no va a dejar que después le eches whisky\n              en esa misma botella.</div>\n            <p>En el código vas a ver cómo el IDE ya sabe perfectamente qué es cada variable con solo ver su valor\n              inicial, ahorrándote tipear la clase entera.</p>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">inferencia.dart</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span\n                    class=\"kw\">var</span> ciudad = <span class=\"str\">\"Buenos Aires\"</span>; <span class=\"cmt\">// Dart\n                    infiere String</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"><span\n                    class=\"kw\">var</span> edad = <span class=\"num\">25</span>; <span class=\"cmt\">// Dart infiere\n                    int</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"><span\n                    class=\"kw\">var</span> lista = [<span class=\"num\">1</span>, <span class=\"num\">2</span>, <span\n                    class=\"num\">3</span>]; <span class=\"cmt\">// Dart infiere List&lt;int&gt;</span></span></div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p><span class=\"tag\">var</span> le dice a Dart que infiera el tipo automáticamente según el valor asignado.\n              Una vez inferido, el tipo es fijo — no podés asignar un <span class=\"tag\">String</span> a una variable que\n              fue inferida como <span class=\"tag\">int</span>. Usá <span class=\"tag\">var</span> cuando el tipo sea obvio;\n              usá el tipo explícito cuando no lo sea.</p>\n          </div>\n        </div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">final vs const <span class=\"badge badge-important\">⚡ Importante</span></div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>Son los dos candados supremos de inmutabilidad en Dart, pero actúan en momentos radicalmente distintos\n              del ciclo de vida de tu app. <code>final</code> se bloquea una vez que el programa está corriendo y\n              calcula un valor; mientras que <code>const</code> exige que el valor sea absoluta y cósmicamente conocido\n              incluso antes de que aprietes el botón de \"Run\".</p>\n            <div class=\"problem\">No podés saber el valor exacto de la ubicación actual del GPS del usuario o de\n              <code>DateTime.now()</code> en el puto momento en que estás tipeando código (tiempo de compilación).\n              Intentar obligar a que eso sea <code>const</code> hará que la app se quiebre, porque el compilador no\n              viaja en el tiempo.\n            </div>\n            <div class=\"solution\">Usás <code>final</code> para cosas como \"Obtener timestamp cuando cargo esta pantalla\"\n              (ocurre en runtime). Y usás <code>const</code> (como las matemáticas puras, PI, o un widget que no cambia\n              nunca) para grabar datos a fuego en el binario de la app, permitiéndole a Flutter reutilizar esa exacta\n              porción de memoria gratis durante toda la vida útil del proceso.</div>\n            <div class=\"analogy\"><code>const</code> es como esculpir una estatua de mármol en el taller (compile time):\n              cuando sale del taller, ya está terminada e inmutable para siempre. <code>final</code> es como rellenar\n              con cemento fresco la columna de un edificio usando un molde (runtime): se define al momento en que la\n              obra está operando, pero una vez que fragua el cemento, queda sólida y no la podés cambiar más.</div>\n            <p>En el código vas a chocar con la pared y ver exactamente por qué el compilador abofetea un error grosero\n              al tratar de hacer estático algo dinámico.</p>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">final_const.dart</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span class=\"cmt\">//\n                    final: se evalúa en tiempo de EJECUCIÓN (runtime)</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"><span\n                    class=\"kw\">final</span> <span class=\"tp\">DateTime</span> ahora = <span\n                    class=\"cls\">DateTime</span>.<span class=\"fn\">now</span>(); <span class=\"cmt\">// ✅</span></span>\n              </div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"><span\n                    class=\"kw\">final</span> <span class=\"tp\">String</span> nombre = <span class=\"str\">\"Juan\"</span>;\n                  <span class=\"cmt\">// ✅</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">5</span><span class=\"line-content\"><span class=\"cmt\">//\n                    const: se evalúa en tiempo de COMPILACIÓN</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">6</span><span class=\"line-content\"><span\n                    class=\"kw\">const</span> <span class=\"tp\">double</span> PI = <span class=\"num\">3.14159</span>; <span\n                    class=\"cmt\">// ✅</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">7</span><span class=\"line-content\"><span\n                    class=\"kw\">const</span> <span class=\"tp\">DateTime</span> ahora = <span\n                    class=\"cls\">DateTime</span>.<span class=\"fn\">now</span>(); <span class=\"cmt\">// ❌ ERROR: no es\n                    constante</span></span></div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p><span class=\"tag\">final</span> se asigna una sola vez pero su valor puede calcularse en runtime (cuando\n              el programa corre). <span class=\"tag\">const</span> es una constante de compilación — su valor debe ser un\n              literal conocido antes de ejecutar. En Flutter, <span class=\"tag tag-green\">const</span> en widgets le\n              dice al framework que puede reutilizarlos sin reconstruirlos, lo que mejora mucho el rendimiento.</p>\n          </div>\n        </div>\n      </div>\n\n      <!-- 1.2 Null Safety -->\n      <div class=\"section\">\n        <div class=\"section-title\"><span class=\"dot\"></span> Null Safety</div>\n\n        <div class=\"info-box tip\">\n          <strong>💡 ¿Por qué importa?</strong>\n          Null safety es uno de los temas más preguntados en entrevistas de Flutter. Desde Dart 2.12 es obligatorio.\n          Elimina el 70% de los crashes más comunes al forzar que manejes los nulos explícitamente.\n        </div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">Los operadores de null safety <span class=\"badge badge-important\">⚡\n                Importante</span></div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>Antes de Dart 2.12, cualquier variable o clase podía estar vacía (ser <code>null</code>) sin emitir un\n              miserable pip de advertencia — el llamado \"Billion Dollar Mistake\" de la industria. Si intentabas leer la\n              longitud de un texto que estaba en <code>null</code>, la aplicación lanzaba la letal\n              \"NullPointerException\" y se moría en la cara del usuario. Null Safety elimina esto por completo, empujando\n              la pesadilla al tiempo de compilación.</p>\n            <div class=\"problem\">Sin Null Safety, programar era caminar por un campo minado asqueroso a la deriva. Un\n              backend que no enviaba el nombre de usuario causaba un colapso masivo en 4 pantallas diferentes porque el\n              frontend asimiló todo sin chequeos.</div>\n            <div class=\"solution\">El compilador de Dart 2.12 se volvió un déspota puritano que literalmente se niega\n              terminantemente a compilar cualquier pieza de código que mínimamente sospeche que puede estallar por un\n              null encubierto. Tienes que probarle pacífica y maravillosamente que sabes lo que haces usando sus\n              operadores sagrados: <code>?</code>, <code>??</code>, <code>?.</code> y el diabólico <code>!</code>.</div>\n            <div class=\"analogy\">Es como poner barreras de peaje exclusivas. En lenguajes viejos, coches sin frenos\n              (datos null) pasaban libremente y se estrellaban en el centro de la ciudad de tu app. Con Null Safety, hay\n              guardias armados en la periferia que te exigen llevar la placa especial <code>?</code> (permiso de\n              circular nulo) o te obligan a poner frenos (operador <code>??</code> de valor por defecto) antes de\n              dejarte transitar un milímetro.</div>\n            <p>En el código verás las 4 deidades cardinales de los nulos que te permitirán navegar la tormenta sin\n              hundir el puto barco.</p>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">null_safety.dart</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span\n                    class=\"tp\">String</span> nombre = <span class=\"str\">\"Juan\"</span>; <span class=\"cmt\">// No puede ser\n                    null</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"><span\n                    class=\"tp\">String</span>? apellido = <span class=\"kw\">null</span>; <span class=\"cmt\">// ? = puede\n                    ser null</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\"><span class=\"cmt\">// ?.\n                    acceso seguro: no crashea si es null</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">5</span><span class=\"line-content\"><span\n                    class=\"tp\">int</span>? largo = apellido?.<span class=\"fn\">length</span>;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">6</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">7</span><span class=\"line-content\"><span class=\"cmt\">// ??\n                    valor por defecto si es null</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">8</span><span class=\"line-content\"><span\n                    class=\"tp\">String</span> display = apellido ?? <span class=\"str\">\"Sin apellido\"</span>;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">9</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">10</span><span class=\"line-content\"><span class=\"cmt\">// !\n                    null assertion: \"sé que no es null\"</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">11</span><span class=\"line-content\"><span\n                    class=\"tp\">String</span> seguro = apellido!; <span class=\"cmt\">// ⚠️ crash si ES null</span></span>\n              </div>\n              <div class=\"code-line\"><span class=\"line-num\">12</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">13</span><span class=\"line-content\"><span class=\"cmt\">//\n                    late: promesa de inicializar antes de usar</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">14</span><span class=\"line-content\"><span\n                    class=\"kw\">late</span> <span class=\"tp\">String</span> email;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">15</span><span class=\"line-content\">email = <span\n                    class=\"str\">\"<a href=\"/cdn-cgi/l/email-protection\" class=\"__cf_email__\"\n                      data-cfemail=\"630916020d23060e020a0f4d000c0e\">[email&#160;protected]</a>\"</span>; <span\n                    class=\"cmt\">// debe asignarse antes del primer uso</span></span></div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p><span class=\"tag\">String?</span> declara una variable que puede ser null. <span\n                class=\"tag tag-green\">?.</span> (null-aware access) accede a propiedades o métodos solo si el objeto no\n              es null, retornando null en caso contrario. <span class=\"tag tag-yellow\">??</span> provee un valor por\n              defecto. <span class=\"tag tag-red\">!</span> fuerza el acceso asumiendo que no es null — si lo es, lanza un\n              error en runtime. Usalo solo cuando estés 100% seguro.</p>\n          </div>\n        </div>\n      </div>\n\n      <!-- 1.3 Async -->\n      <div class=\"section\">\n        <div class=\"section-title\"><span class=\"dot\"></span> Programación Asíncrona</div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">Future y async/await <span class=\"badge badge-important\">⚡ Importantísimo</span>\n            </div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>Dart opera mediante un Event Loop virginal: es asquerosamente <em>single-threaded</em>, lo que significa\n              que procesa estrictamente de a una mierda a la vez. Cuando le pedís un dato a una tortueta API en\n              Internet, la red puede tardar 2 agónicos segundos en cruzar océanos. Para evitar un bloqueo fúnebre,\n              aislas la tarea como asíncrona encapsulando en una promesa conocida como <code>Future</code>.</p>\n            <div class=\"problem\">Sin <code>async/await</code>, si hacés un llamado HTTP síncrono que demora segundos, el\n              maldito hilo único (el Event Loop) entero de tu aplicación se congelaría en seco. El scroll UI se traba,\n              las animaciones se freezan como piedra letal, y eventualmente el sistema operativo te tumba la app\n              enviando el cartel de \"App is Not Responding\".</div>\n            <div class=\"solution\">Con fúlgida magia <code>async/await</code>, vos instruís pacíficamente al Event Loop a\n              \"pausar momentáneamente la línea de código actual\" sin trabar la CPU principal. Mientras el putísimo\n              paquete TCP/IP viaja por la web, tu hilo queda desocupado para atender sin demora los hermosos 120\n              fotogramas por segundo del Scroll View. Cuando vuelven los datos, retoma maravillosamente tu código por\n              donde lo dejó.</div>\n            <div class=\"analogy\">Estás cocinando una valiente pizza eximia. Metés la pizza al horno hirviente (llamada\n              API). En lugar de quedarte enfrente del horno mirándolo fijo, paralizado e ignorando todo a tu alrededor\n              (bloqueando el Event Loop), programás una alarma de 15 minutos (<code>await</code>) y te ponés\n              asombrosamente a lavar los platos y picar la ensalada fiera (atender la UI). Cuando suena, volvés pacífico\n              al horno a extraer la pizza (el <code>Future</code> completado con victoria).</div>\n            <p>En el código, verás cuán asquerosamente fácil es la legibilidad al fingir escribir código lineal usando\n              estas maravillosas y fúlgidas keywords alienígenas.</p>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">async_await.dart</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span class=\"cmt\">//\n                    Future = valor que estará disponible en el futuro</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"><span\n                    class=\"tp\">Future</span>&lt;<span class=\"tp\">String</span>&gt; <span\n                    class=\"fn\">obtenerUsuario</span>() <span class=\"kw\">async</span> {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"> <span\n                    class=\"kw\">await</span> <span class=\"cls\">Future</span>.<span class=\"fn\">delayed</span>(<span\n                    class=\"cls\">Duration</span>(seconds: <span class=\"num\">2</span>));</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\"> <span\n                    class=\"kw\">return</span> <span class=\"str\">\"Juan García\"</span>;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">5</span><span class=\"line-content\">}</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">6</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">7</span><span class=\"line-content\"><span class=\"cmt\">// Usar\n                    con try/catch para manejar errores</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">8</span><span class=\"line-content\"><span\n                    class=\"tp\">Future</span>&lt;<span class=\"kw\">void</span>&gt; <span class=\"fn\">cargar</span>() <span\n                    class=\"kw\">async</span> {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">9</span><span class=\"line-content\"> <span\n                    class=\"kw\">try</span> {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">10</span><span class=\"line-content\"> <span\n                    class=\"tp\">String</span> usuario = <span class=\"kw\">await</span> <span\n                    class=\"fn\">obtenerUsuario</span>();</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">11</span><span class=\"line-content\"> <span\n                    class=\"fn\">print</span>(usuario);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">12</span><span class=\"line-content\"> } <span\n                    class=\"kw\">catch</span> (e) {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">13</span><span class=\"line-content\"> <span\n                    class=\"fn\">print</span>(<span class=\"str\">\"Error: </span>$e<span class=\"str\">\"</span>);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">14</span><span class=\"line-content\"> }</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">15</span><span class=\"line-content\">}</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">16</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">17</span><span class=\"line-content\"><span class=\"cmt\">//\n                    Future.wait: múltiples futures en PARALELO</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">18</span><span class=\"line-content\"><span\n                    class=\"kw\">await</span> <span class=\"cls\">Future</span>.<span class=\"fn\">wait</span>([</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">19</span><span class=\"line-content\"> <span\n                    class=\"fn\">obtenerUsuarios</span>(),</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">20</span><span class=\"line-content\"> <span\n                    class=\"fn\">obtenerProductos</span>(),</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">21</span><span class=\"line-content\">]);</span></div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p><span class=\"tag\">Future&lt;T&gt;</span> representa un valor de tipo T que estará disponible en algún\n              momento. <span class=\"tag tag-green\">async</span> marca una función como asíncrona. <span\n                class=\"tag tag-green\">await</span> pausa la ejecución hasta que el Future se complete — pero sin\n              bloquear el hilo principal. Siempre usá <span class=\"tag\">try/catch</span> para manejar errores en\n              operaciones asíncronas. <span class=\"tag\">Future.wait</span> ejecuta múltiples operaciones en paralelo y\n              espera a que todas terminen.</p>\n          </div>\n        </div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">Streams — datos en el tiempo <span class=\"badge badge-dart\">Dart</span></div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>Un <code>Stream</code> es una suscripción fúnebre iterativa de pulsaciones de datos. Si un\n              <code>Future</code> te asegura recibir exactamente una caja empaquetada de datos al final de un pasillo\n              temporal, el enigmático majestuoso <code>Stream</code> representa una fiera cañería abierta continua\n              rutilante que gotea infinitas y asombrosas porciones asiladas de letargos eventos al infinito maravilloso.\n            </p>\n            <div class=\"problem\">Si usas <code>Future</code> para intentar rastrear el putísimo GPS letal del teléfono\n              en tiempo real o un chat en vivo de Firebase que no para ni respira, perderías porque los\n              <code>Future</code> pacíficamente entregan una mísera bala asilada y mueren de tajo, no saben reabrir la\n              conexión pasiva.\n            </div>\n            <div class=\"solution\">Con <code>Streams</code> te suscribis virginal e infinitamente a tubos mágicos de\n              Firestore o websockets asombrosos. Cualquier cambio que ocurra remoto entra automáticamente desencadenando\n              majestuosamente una refrescante explosión de UI actualizada que le brota inmaculada al usuario en vivo en\n              su cara pacífica sin presionar botones puritanos de refresh manual.</div>\n            <div class=\"analogy\">Un <code>Future</code> es como pedirte pacíficamente agresivo un puto Uber exultante:\n              te parás, esperás que diga que llegó triunfante en la puerta, pagás asqueroso el pasaje y se acabó. Un\n              fúlgido y asombroso <code>Stream</code> es pedirte que pongas Netflix valiente: encendés la tele prístina\n              asilada y la puta maldita magia te bota 24 putísimas letales fotos (frames) continuos e incansables por\n              fiero segundo en pura sintonía mágica virginal.</div>\n            <p>En el código descubrirás cómo conectar una manguera de eventos letal continua con el maldito método\n              <code>listen</code> que mantendrá a los valores nadando pacíficamente hasta el cansancio.\n            </p>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">streams.dart</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span class=\"cmt\">//\n                    Stream: secuencia de valores en el tiempo</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"><span\n                    class=\"tp\">Stream</span>&lt;<span class=\"tp\">int</span>&gt; <span class=\"fn\">contador</span>() <span\n                    class=\"kw\">async*</span> {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"> <span\n                    class=\"kw\">for</span> (<span class=\"tp\">int</span> i = <span class=\"num\">1</span>; i &lt;= <span\n                    class=\"num\">5</span>; i++) {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\"> <span\n                    class=\"kw\">await</span> <span class=\"cls\">Future</span>.<span class=\"fn\">delayed</span>(<span\n                    class=\"cls\">Duration</span>(seconds: <span class=\"num\">1</span>));</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">5</span><span class=\"line-content\"> <span\n                    class=\"kw\">yield</span> i; <span class=\"cmt\">// emitir valor</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">6</span><span class=\"line-content\"> }</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">7</span><span class=\"line-content\">}</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">8</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">9</span><span class=\"line-content\"><span class=\"cmt\">//\n                    Suscribirse — SIEMPRE cancelar en dispose()</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">10</span><span class=\"line-content\"><span\n                    class=\"tp\">StreamSubscription</span>&lt;<span class=\"tp\">int</span>&gt; sub = <span\n                    class=\"fn\">contador</span>().<span class=\"fn\">listen</span>(</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">11</span><span class=\"line-content\"> (valor) =&gt; <span\n                    class=\"fn\">print</span>(<span class=\"str\">\"Recibí: </span>$valor<span class=\"str\">\"</span>),</span>\n              </div>\n              <div class=\"code-line\"><span class=\"line-num\">12</span><span class=\"line-content\"> onError: (e) =&gt;\n                  <span class=\"fn\">print</span>(<span class=\"str\">\"Error: </span>$e<span class=\"str\">\"</span>),</span>\n              </div>\n              <div class=\"code-line\"><span class=\"line-num\">13</span><span class=\"line-content\"> onDone: () =&gt; <span\n                    class=\"fn\">print</span>(<span class=\"str\">\"Terminé\"</span>),</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">14</span><span class=\"line-content\">);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">15</span><span class=\"line-content\">sub.<span\n                    class=\"fn\">cancel</span>(); <span class=\"cmt\">// evitar memory leaks</span></span></div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p>Un <span class=\"tag\">Stream</span> es como un río de datos que fluyen en el tiempo. Usá <span\n                class=\"tag\">Future</span> para operaciones de una sola vez (llamada a API, leer un archivo). Usá <span\n                class=\"tag tag-green\">Stream</span> para datos que cambian continuamente: mensajes de chat en tiempo\n              real, posición GPS, eventos del usuario. <span class=\"tag tag-red\">Siempre cancelar</span> la suscripción\n              en el método <span class=\"tag\">dispose()</span> para evitar memory leaks.</p>\n          </div>\n        </div>\n      </div>",
  "mod2": "<div id=\"mod2\" class=\"module-header\">\n        <div class=\"module-number\">Módulo 02</div>\n        <h2>Flutter Core</h2>\n        <p>Flutter es un framework de UI donde todo es un widget. Entender los tres árboles, el ciclo de vida y los\n          widgets fundamentales es la base para cualquier entrevista técnica.</p>\n      </div>\n\n      <div class=\"section\">\n        <div class=\"section-title\"><span class=\"dot\"></span> StatelessWidget vs StatefulWidget</div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">StatelessWidget <span class=\"badge badge-flutter\">Flutter</span></div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>Es el ladrillo más básico, tonto y predecible de Flutter. Un <code>StatelessWidget</code> es literalmente\n              una caja boba que recibe propiedades por parámetros, las dibuja en pantalla una vez y se muere de\n              inacción. Si cambias un dato adentro de él, ni se entera visualmente.</p>\n            <div class=\"problem\">¿Por qué querrías un widget inútil que no cambia? Porque redibujar la pantalla\n              constantemente cuesta memoria RAM, CPU y drena la asquerosa batería del celular a chorros.</div>\n            <div class=\"solution\">Al usar widgets \"sin estado\" (stateless), le asegurás a Flutter: \"chequeame esto solo\n              la primera vez y después ignorame olímpicamente a menos que el padre que me contiene decida redibujarme\n              entero desde afuera\". Eso se traduce en asombrosos 120 FPS fúlgidos y puritanos.</div>\n            <div class=\"analogy\">Es como una tarjeta de presentación impresa en cartulina mate. Recibió mágicamente los\n              datos de la imprenta (constructor), quedó bellísima y no cambia más pacíficamente letal. Si cambias de\n              número de teléfono, no podés agarrar la tarjeta con la mente y que cambie sola; tenés que mandar a\n              imprimir valiente una tarjeta 100% nueva.</div>\n            <p>En el código de abajo fíjate cómo TODO es inmutable (final, const). La tarjeta recibe el nombre magistral\n              del producto y se lava las manos fúnebremente.</p>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">tarjeta_producto.dart</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span class=\"cmt\">// Sin\n                    estado interno — solo muestra lo que recibe</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"><span\n                    class=\"kw\">class</span> <span class=\"cls\">TarjetaProducto</span> <span class=\"kw\">extends</span>\n                  <span class=\"cls\">StatelessWidget</span> {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"> <span\n                    class=\"kw\">final</span> <span class=\"tp\">String</span> nombre;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\"> <span\n                    class=\"kw\">final</span> <span class=\"tp\">double</span> precio;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">5</span><span class=\"line-content\"> <span\n                    class=\"kw\">final</span> <span class=\"cls\">VoidCallback</span>? onTap;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">6</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">7</span><span class=\"line-content\"> <span\n                    class=\"kw\">const</span> <span class=\"cls\">TarjetaProducto</span>({ <span class=\"cmt\">// const =\n                    reutilizable por Flutter</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">8</span><span class=\"line-content\"> <span\n                    class=\"kw\">super</span>.key,</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">9</span><span class=\"line-content\"> <span\n                    class=\"kw\">required</span> <span class=\"kw\">this</span>.nombre,</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">10</span><span class=\"line-content\"> <span\n                    class=\"kw\">required</span> <span class=\"kw\">this</span>.precio,</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">11</span><span class=\"line-content\"> <span\n                    class=\"kw\">this</span>.onTap,</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">12</span><span class=\"line-content\"> });</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">13</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">14</span><span class=\"line-content\"> <span\n                    class=\"op\">@override</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">15</span><span class=\"line-content\"> <span\n                    class=\"cls\">Widget</span> <span class=\"fn\">build</span>(<span class=\"cls\">BuildContext</span>\n                  context) {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">16</span><span class=\"line-content\"> <span\n                    class=\"kw\">return</span> <span class=\"cls\">GestureDetector</span>(</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">17</span><span class=\"line-content\"> onTap: onTap,</span>\n              </div>\n              <div class=\"code-line\"><span class=\"line-num\">18</span><span class=\"line-content\"> child: <span\n                    class=\"cls\">Card</span>(</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">19</span><span class=\"line-content\"> child: <span\n                    class=\"cls\">Text</span>(nombre),</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">20</span><span class=\"line-content\"> ),</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">21</span><span class=\"line-content\"> );</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">22</span><span class=\"line-content\"> }</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">23</span><span class=\"line-content\">}</span></div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p>Un <span class=\"tag\">StatelessWidget</span> no tiene estado interno que cambie. Siempre produce el mismo\n              output dado los mismos inputs. Es más eficiente porque Flutter no necesita rastrear cambios. Usá siempre\n              <span class=\"tag tag-green\">const</span> en el constructor para que Flutter pueda reutilizar la instancia\n              sin reconstruirla.\n            </p>\n          </div>\n        </div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">StatefulWidget + ciclo de vida <span class=\"badge badge-important\">⚡\n                Importante</span></div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>A diferencia de la tarjeta de presentación boba, el <code>StatefulWidget</code> es un fiero mutante vivo.\n              Tiene memoria, palpita asombrosamente y reacciona al usuario alterando su forma usando una bomba de\n              refresco llamada <code>setState()</code>.</p>\n            <div class=\"problem\">Tenés un botón mágico de \"Me gusta\" o un contador. Si tocás y sumás letalmente +1, la\n              UI puritana necesita redibujarse maravillosamente sola sin que toda la maldita app tenga que recargarse\n              asquerosa entera como los navegadores web del año 2000 puritanos.</div>\n            <div class=\"solution\">El <code>StatefulWidget</code> es paranoico fúnebre: se desdobla letalmente en 2\n              clases pacíficas separadas exultantes: el Widget público puro mudo, y el Estado sombrío mutante sucio.\n              Llamar a majestuoso <code>setState()</code> empuja al framework a destruir mágicamente la vista asilada y\n              re-dibujarla instantáneamente virginal impecable con la letal memoria puritana nueva.</div>\n            <div class=\"analogy\">Piénsalo asquerosamente letal como si fuera un asombroso pacífico pizarron interactivo\n              magistral: cuando sumás valiente un punto al fúnebre lado exultante visitante del partido puritano\n              estelar, agarrás maravillosamente el maldito borrador fiero virginal letargo (<code>setState()</code>) y\n              sobreescribís pacíficamente asombroso solo el putísimo puntaje muerto mágico intacto sin destruir la\n              cancha o expulsar al árbitro mágico.</div>\n            <p>En el código letal de abajo prestarás fúlgida atención estelar majestuosa al <code>initState()</code>\n              (nacer) y el virginalmente fiero asqueroso asesino asombroso <code>dispose()</code> puritano letal (saber\n              putamente limpiar la basura exultante letargo al fúnebremente mágico pudrirse el Widget).</p>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">contador.dart</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span\n                    class=\"kw\">class</span> <span class=\"cls\">Contador</span> <span class=\"kw\">extends</span> <span\n                    class=\"cls\">StatefulWidget</span> {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"> <span\n                    class=\"kw\">const</span> <span class=\"cls\">Contador</span>({<span\n                    class=\"kw\">super</span>.key});</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"> <span\n                    class=\"op\">@override</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\"> <span\n                    class=\"cls\">State</span>&lt;<span class=\"cls\">Contador</span>&gt; <span\n                    class=\"fn\">createState</span>() =&gt; <span class=\"fn\">_ContadorState</span>();</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">5</span><span class=\"line-content\">}</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">6</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">7</span><span class=\"line-content\"><span\n                    class=\"kw\">class</span> <span class=\"cls\">_ContadorState</span> <span class=\"kw\">extends</span>\n                  <span class=\"cls\">State</span>&lt;<span class=\"cls\">Contador</span>&gt; {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">8</span><span class=\"line-content\"> <span\n                    class=\"tp\">int</span> _count = <span class=\"num\">0</span>;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">9</span><span class=\"line-content\"> <span\n                    class=\"kw\">late</span> <span class=\"cls\">StreamSubscription</span> _sub;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">10</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">11</span><span class=\"line-content\"> <span\n                    class=\"op\">@override</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">12</span><span class=\"line-content\"> <span\n                    class=\"kw\">void</span> <span class=\"fn\">initState</span>() {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">13</span><span class=\"line-content\"> <span\n                    class=\"kw\">super</span>.<span class=\"fn\">initState</span>(); <span class=\"cmt\">// SIEMPRE llamar\n                    primero</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">14</span><span class=\"line-content\"> _sub = miStream.<span\n                    class=\"fn\">listen</span>((_) =&gt; <span class=\"fn\">setState</span>(() {}));</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">15</span><span class=\"line-content\"> }</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">16</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">17</span><span class=\"line-content\"> <span\n                    class=\"op\">@override</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">18</span><span class=\"line-content\"> <span\n                    class=\"kw\">void</span> <span class=\"fn\">dispose</span>() {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">19</span><span class=\"line-content\"> _sub.<span\n                    class=\"fn\">cancel</span>(); <span class=\"cmt\">// ⚠️ SIEMPRE limpiar recursos</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">20</span><span class=\"line-content\"> <span\n                    class=\"kw\">super</span>.<span class=\"fn\">dispose</span>(); <span class=\"cmt\">// SIEMPRE llamar al\n                    final</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">21</span><span class=\"line-content\"> }</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">22</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">23</span><span class=\"line-content\"> <span\n                    class=\"op\">@override</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">24</span><span class=\"line-content\"> <span\n                    class=\"cls\">Widget</span> <span class=\"fn\">build</span>(<span class=\"cls\">BuildContext</span>\n                  context) {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">25</span><span class=\"line-content\"> <span\n                    class=\"kw\">return</span> <span class=\"cls\">ElevatedButton</span>(</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">26</span><span class=\"line-content\"> onPressed: () =&gt;\n                  <span class=\"fn\">setState</span>(() =&gt; _count++),</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">27</span><span class=\"line-content\"> child: <span\n                    class=\"cls\">Text</span>(<span class=\"str\">\"Contador: </span>$_count<span\n                    class=\"str\">\"</span>),</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">28</span><span class=\"line-content\"> );</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">29</span><span class=\"line-content\"> }</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">30</span><span class=\"line-content\">}</span></div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p><span class=\"tag\">initState()</span> se llama una vez al crear el State. Usalo para inicializar recursos,\n              suscribirte a streams, o hacer la primera llamada a la API. <span class=\"tag tag-red\">dispose()</span> se\n              llama cuando el widget se destruye — siempre liberá aquí todo lo que inicializaste: StreamSubscriptions,\n              AnimationControllers, TextEditingControllers. Olvidarse de <span class=\"tag\">dispose()</span> es la causa\n              más común de memory leaks en Flutter.</p>\n          </div>\n        </div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">BuildContext y el truco del mounted <span class=\"badge badge-important\">⚡\n                Entrevista</span></div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>El <code>BuildContext</code> es literalmente la puta dirección asquerosa y magistral del GPS fúnebre de\n              un exacto widget letal virginal dentro del infinito asombroso árbol de widgets puritanos familiares. Da el\n              exacto asilado \"yo estoy aquí\" fúlgido. Si el widget fiero mágicamente y asombrosamente ya fue destruido\n              (el usuario asqueroso fue atrás rápido), ese contexto es una bomba nula letal exultante pacífica puritana\n              muerta.</p>\n            <div class=\"problem\">Imaginemos que pedís asquerosamente letal datos mágicos al servidor con pacífico\n              fúnebre <code>await API.get()</code> y fúlgido virginal decidis asombrosamente cambiar letalmente de\n              pantalla usando fiero pacífico <code>Navigator.push(context)</code>, pero antes puritano virginal\n              magistral de que la internet lenta te devuelva luz pura mágica, el asqueroso usuario ya cerró con\n              <code>pop</code> la pantalla. Esa UI majestuosa ya no existe, el contexto es basura estéril fúnebre y el\n              enigmático <code>Navigator</code> crasheará rojo letal carmesí tu asombrosa app exultante puritana.\n            </div>\n            <div class=\"solution\">La mágica keyword <code>mounted</code> es un centinela fúlgido asilado. Le pregunta\n              exultante a las entrañas pacíficas letales fieras de Flutter: \"¿Dime deidad asombrosa puritana sagrada,\n              luego de que tardó 5 letargos segundos asquerosos letales mágicos este asilado await puro virginal\n              fúnebre, el maldito pacífico widget sigue vivo en pantalla?\". Si la respuesta puritana asombrosa es\n              maravillosamente NO, el fiero majestuoso <code>return</code> virginal letal finaliza el asqueroso ciclo\n              abortando los putos comandos de luz y muerte sin estallar puritano letargo magistral.</div>\n            <div class=\"analogy\">Imagina pura fiereza majestuosa que llamas pacífico letal asilado a la fúnebre pura\n              virginal pizzería exultante y pagás por valiente asombroso fúlgido envío letargo (<code>await</code>\n              asqueroso mágico). Pero a los 2 minutos, vendés mágica puritana virginal tu letal asombrosa puta casa y\n              pacíficamente exultante majestuoso te mudás fiero fúnebre asilado al campo puro hermoso virginal puritano\n              (el widget es destruido). Cuando la pizza pacífica bella asombrosamente maravillosa puritana letalmente\n              pura fiera aterriza exultante, el repartidor asquerosamente asilado puritano ciego virginal letargo tocará\n              magistral pura madera buscando a un muerto exultante: <code>mounted</code> es pacíficamente pura y\n              exultantemente fúlgida magia fiera puritana asombrosa que cancela virgen letal maravillosa el puto puro\n              perdido asqueroso asilado magistral hermoso virginal fúnebre majestuosamente divino pedido exultante\n              puritano de pura fiera paz letargo al instante hermoso mágica para no volar pura y magistral mierda\n              pacíficamente.</div>\n            <p>En el código estelar majestuosamente exultante puritano letal, verás mágicamente asombrosa pura fiera\n              pacíficamente asilada asquerosa putísima virginal hermosa letargo magia puritana fúnebre con divina\n              fúlgida paz maravillosa cómo aplicar pura asombrosa hermosa letal majestuosidad asilada al vuelo virginal\n              magistral asombroso.</p>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">context_mounted.dart</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span class=\"cmt\">// ❌\n                    PELIGROSO: usar context después de un await</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"><span\n                    class=\"tp\">Future</span>&lt;<span class=\"kw\">void</span>&gt; <span class=\"fn\">guardarMal</span>()\n                  <span class=\"kw\">async</span> {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"> <span\n                    class=\"kw\">await</span> api.<span class=\"fn\">guardar</span>(datos);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\"> <span\n                    class=\"cls\">Navigator</span>.<span class=\"fn\">of</span>(context).<span class=\"fn\">pop</span>();\n                  <span class=\"cmt\">// 💥 crash si el widget fue destruido</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">5</span><span class=\"line-content\">}</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">6</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">7</span><span class=\"line-content\"><span class=\"cmt\">// ✅\n                    CORRECTO: verificar mounted antes</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">8</span><span class=\"line-content\"><span\n                    class=\"tp\">Future</span>&lt;<span class=\"kw\">void</span>&gt; <span class=\"fn\">guardarBien</span>()\n                  <span class=\"kw\">async</span> {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">9</span><span class=\"line-content\"> <span\n                    class=\"kw\">await</span> api.<span class=\"fn\">guardar</span>(datos);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">10</span><span class=\"line-content\"> <span\n                    class=\"kw\">if</span> (!mounted) <span class=\"kw\">return</span>; <span class=\"cmt\">// sale si el\n                    widget ya no existe</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">11</span><span class=\"line-content\"> <span\n                    class=\"cls\">Navigator</span>.<span class=\"fn\">of</span>(context).<span class=\"fn\">pop</span>();\n                  <span class=\"cmt\">// ✅ seguro</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">12</span><span class=\"line-content\">}</span></div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p><span class=\"tag\">BuildContext</span> es la posición del widget en el árbol. Entre el momento de un <span\n                class=\"tag\">await</span> y cuando la ejecución continúa, el widget puede haber sido desmontado (el\n              usuario navegó a otra pantalla). Siempre verificá <span class=\"tag tag-green\">if (!mounted) return</span>\n              antes de usar <span class=\"tag\">context</span> o llamar <span class=\"tag\">setState()</span> después de\n              cualquier operación asíncrona. Esta es una de las preguntas más frecuentes en entrevistas Flutter.</p>\n          </div>\n        </div>\n      </div>",
  "mod3": "<div id=\"mod3\" class=\"module-header\">\n        <div class=\"module-number\">Módulo 03</div>\n        <h2>Navegación — GoRouter</h2>\n        <p>La navegación es cómo los usuarios se mueven entre pantallas. GoRouter es el estándar actual — reemplaza al\n          Navigator 1.0 con una API declarativa basada en URLs.</p>\n      </div>\n\n      <div class=\"section\">\n        <div class=\"section-title\"><span class=\"dot\"></span> Navigator 1.0 — lo básico que hay que conocer</div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">push, pop y pushReplacement <span class=\"badge badge-flutter\">Flutter</span>\n            </div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>Es el sistema de navegación clásico y rústico de Flutter (Navigator 1.0). Funciona literalmente como un\n              mazo de cartas letal: vas apilando pantallas una encima de la otra (<code>push</code>) y sacando la de\n              arriba (<code>pop</code>) de forma manual y escandalosa.</p>\n            <div class=\"problem\">¿Qué pasa si el asqueroso usuario inicia sesión en la app (pantalla Login), pasa al\n              Home (pantalla principal) y luego oprime el fiero botón \"Atrás\" de su celular Android? ¡Exacto! Lo\n              devuelve mágica y letalmente al Login, obligándolo a loguearse 2 veces, frustrándolo al extremo hasta que\n              te clava fúnebremente 1 estrella en la Play Store.</div>\n            <div class=\"solution\">Al usar métodos como <code>pushReplacement</code> (reemplaza la top card sin dejar\n              volver) o <code>pushAndRemoveUntil</code> (dinamita nuclearmente todo el historial pasado), controlas la\n              pila de cartas. El usuario no podrá ir hacia atrás a donde no debe fúlgidamente ir.</div>\n            <div class=\"analogy\">Navegar con <code>push</code> es como entrar a cuartos conectados en línea recta\n              dejándole un asombroso hilo rojo a Teseo; con <code>pop</code> seguís el hilo de reversa puritana a la\n              habitación asilada anterior. Usar <code>pushReplacement</code> es entrar al cuarto siguiente exultante\n              letargo y maravillosamente prender fuego el putísimo puente detrás de ti, asegurando que nadie\n              maravillosamente mágica letal nunca pueda retroceder majestuosamente al origen asombroso puro.</div>\n            <p>En el fúnebre código de abajo, verás divinamente fiera cómo puritano manipular letargo el mazo\n              pacíficamente asombroso letal de Flutter con cirugía mayor virginal.</p>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">navigator_basico.dart</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span class=\"cmt\">//\n                    PUSH: agrega pantalla al stack (puede volver)</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"><span\n                    class=\"cls\">Navigator</span>.<span class=\"fn\">of</span>(context).<span\n                    class=\"fn\">push</span>(</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"> <span\n                    class=\"cls\">MaterialPageRoute</span>(builder: (_) => <span class=\"cls\">DetalleScreen</span>(id:\n                  producto.id)),</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\">);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">5</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">6</span><span class=\"line-content\"><span class=\"cmt\">// POP:\n                    vuelve a la pantalla anterior</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">7</span><span class=\"line-content\"><span\n                    class=\"cls\">Navigator</span>.<span class=\"fn\">of</span>(context).<span\n                    class=\"fn\">pop</span>();</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">8</span><span class=\"line-content\"><span\n                    class=\"cls\">Navigator</span>.<span class=\"fn\">of</span>(context).<span\n                    class=\"fn\">pop</span>(resultado); <span class=\"cmt\">// retornar datos</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">9</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">10</span><span class=\"line-content\"><span class=\"cmt\">//\n                    pushReplacement: reemplaza la pantalla actual (sin poder volver)</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">11</span><span class=\"line-content\"><span class=\"cmt\">//\n                    Ideal para: login → home (el usuario no debe poder volver al login)</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">12</span><span class=\"line-content\"><span\n                    class=\"cls\">Navigator</span>.<span class=\"fn\">of</span>(context).<span\n                    class=\"fn\">pushReplacement</span>(</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">13</span><span class=\"line-content\"> <span\n                    class=\"cls\">MaterialPageRoute</span>(builder: (_) => <span class=\"kw\">const</span> <span\n                    class=\"cls\">HomeScreen</span>()),</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">14</span><span class=\"line-content\">);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">15</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">16</span><span class=\"line-content\"><span class=\"cmt\">//\n                    pushAndRemoveUntil: limpia todo el stack</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">17</span><span class=\"line-content\"><span class=\"cmt\">//\n                    Ideal para: logout → login (limpiar historial de navegación)</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">18</span><span class=\"line-content\"><span\n                    class=\"cls\">Navigator</span>.<span class=\"fn\">of</span>(context).<span\n                    class=\"fn\">pushAndRemoveUntil</span>(</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">19</span><span class=\"line-content\"> <span\n                    class=\"cls\">MaterialPageRoute</span>(builder: (_) => <span class=\"kw\">const</span> <span\n                    class=\"cls\">LoginScreen</span>()),</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">20</span><span class=\"line-content\"> (route) => <span\n                    class=\"kw\">false</span>, <span class=\"cmt\">// eliminar TODAS las rutas anteriores</span></span>\n              </div>\n              <div class=\"code-line\"><span class=\"line-num\">21</span><span class=\"line-content\">);</span></div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p><span class=\"tag\">push</span> apila una nueva pantalla manteniendo la anterior — el usuario puede volver\n              con el botón back. <span class=\"tag tag-yellow\">pushReplacement</span> reemplaza la pantalla actual sin\n              conservarla en el stack — ideal para flujos de login donde no querés que el usuario vuelva. <span\n                class=\"tag tag-red\">pushAndRemoveUntil</span> limpia todo el stack de navegación — perfecto para logout.\n            </p>\n          </div>\n        </div>\n      </div>\n\n      <div class=\"section\">\n        <div class=\"section-title\"><span class=\"dot\"></span> GoRouter — El estándar moderno</div>\n\n        <div class=\"info-box tip\">\n          <strong>💡 ¿Por qué GoRouter en lugar de Navigator 1.0?</strong>\n          GoRouter usa URLs declarativas, soporta deep links nativamente, maneja guards de autenticación de forma\n          limpia, y funciona mejor en web. Es el package oficial recomendado por el equipo de Flutter.\n        </div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">Configuración completa de GoRouter <span class=\"badge badge-important\">⚡ Estándar\n                actual</span></div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>GoRouter es el asesino serial absoluto del viejo Navigator 1.0. Es el estándar declarativo oficial. En\n              lugar de empujar pantallas a ciegas como masacrando cartas, vos de antemano dibujás un magistral y hermoso\n              mapa de URLs (ej: \"/home\", \"/user/123\", \"/login\"). El sistema redirige automáticamente puritano asombroso\n              sin que toques la UI fúnebre letal.</p>\n            <div class=\"problem\">Si usas Navigator 1.0 letal en Flutter Web y un asombroso puritano asqueroso usuario\n              tipea \"tusitio.com/perfil\" maravillosamente en la barra de Chrome de la PC mágica letargo magistral\n              puritana exultante, la app pacífica fiera letal explota porque el estúpido Navigator virginal fiero mágico\n              no entiende qué mierda pura es una URL asombrosa puritana pacíficamente letal fúnebre. Además, defender\n              fúlgidamente la app de usuarios sin login era un infierno de ifs if-else en 400 widgets letales asilados.\n            </div>\n            <div class=\"solution\">GoRouter asombroso fiero maneja mágicamente \"Deep Links\" puritanos letales (links\n              externos pacíficos fúlgidos exultantes abriendo la app puritana móvil fiera exactamente en la pantalla\n              virginal magistral correcta fúnebre). Y gracias a su fiero <code>redirect</code> (ruta guardiana\n              maravillosamente letargo pacífica), blindás la app entera asombrosamente de un solo asqueroso manotazo\n              maestro mágico hermoso puro puritano de estado y lógica fúlgida asilada letal paz virginal.</div>\n            <div class=\"analogy\">Navigator puro es decirle a la asombrosa fiera letal puritana magia azafata pura mágica\n              virginal pacíficamente letargo fúnebre asquerosamente exultante hermosa: \"camina tres pasos magistrales\n              puros fieros asquerosamente al frente, dobla a la pacífica fúlgida derecha majestuosamente y metete en el\n              asiento letargo\". GoRouter pura fúnebre magia asombrosa letal es darle el asquerosamente virginal\n              pacíficamente majestuosamente magistral hermoso fiero puro letargo ticket \"Asiento 4B\" puritano magia\n              exultante y el sistema mágico letal te teletransporta al carajo automáticamente hermoso de una paz\n              absoluta.</div>\n            <p>En el código asombrosamente fiero maravillosamente letal puritano exótico letargo virginal pacíficamente\n              mágico fúnebre puro verás el asquerosamente letal hermoso magistral y perfecto mapa mental fúlgido que\n              rige letal fiero al imperio entero asilado puritano magia exultante letargo asombroso.</p>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">router.dart</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span\n                    class=\"kw\">final</span> routerProvider = <span class=\"cls\">Provider</span>&lt;<span\n                    class=\"cls\">GoRouter</span>&gt;((ref) {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"> <span\n                    class=\"kw\">final</span> authState = ref.<span class=\"fn\">watch</span>(authStateProvider);</span>\n              </div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"> <span\n                    class=\"kw\">return</span> <span class=\"cls\">GoRouter</span>(</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\"> initialLocation: <span\n                    class=\"str\">\"/\"</span>,</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">5</span><span class=\"line-content\"> redirect: (context,\n                  state) {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">6</span><span class=\"line-content\"> <span\n                    class=\"kw\">final</span> isLoggedIn = authState.<span class=\"fn\">isAuthenticated</span>();</span>\n              </div>\n              <div class=\"code-line\"><span class=\"line-num\">7</span><span class=\"line-content\"> <span\n                    class=\"kw\">final</span> isLoginPage = state.matchedLocation == <span\n                    class=\"str\">\"/login\"</span>;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">8</span><span class=\"line-content\"> <span\n                    class=\"kw\">if</span> (!isLoggedIn && !isLoginPage) <span class=\"kw\">return</span> <span\n                    class=\"str\">\"/login\"</span>;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">9</span><span class=\"line-content\"> <span\n                    class=\"kw\">if</span> (isLoggedIn && isLoginPage) <span class=\"kw\">return</span> <span\n                    class=\"str\">\"/\"</span>;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">10</span><span class=\"line-content\"> <span\n                    class=\"kw\">return</span> <span class=\"kw\">null</span>; <span class=\"cmt\">// sin\n                    redirección</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">11</span><span class=\"line-content\"> },</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">12</span><span class=\"line-content\"> routes: [</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">13</span><span class=\"line-content\"> <span\n                    class=\"cls\">GoRoute</span>(path: <span class=\"str\">\"/\"</span>, builder: (_, __) => <span\n                    class=\"kw\">const</span> <span class=\"cls\">HomeScreen</span>()),</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">14</span><span class=\"line-content\"> <span\n                    class=\"cls\">GoRoute</span>(path: <span class=\"str\">\"/login\"</span>, builder: (_, __) => <span\n                    class=\"kw\">const</span> <span class=\"cls\">LoginScreen</span>()),</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">15</span><span class=\"line-content\"> <span\n                    class=\"cls\">GoRoute</span>(</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">16</span><span class=\"line-content\"> path: <span\n                    class=\"str\">\"/producto/:id\"</span>, <span class=\"cmt\">// parámetro dinámico</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">17</span><span class=\"line-content\"> builder: (context,\n                  state) {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">18</span><span class=\"line-content\"> <span\n                    class=\"kw\">final</span> id = state.pathParameters[<span class=\"str\">\"id\"</span>]!;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">19</span><span class=\"line-content\"> <span\n                    class=\"kw\">return</span> <span class=\"cls\">ProductoDetailScreen</span>(id: id);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">20</span><span class=\"line-content\"> },</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">21</span><span class=\"line-content\"> ),</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">22</span><span class=\"line-content\"> ],</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">23</span><span class=\"line-content\"> );</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">24</span><span class=\"line-content\">});</span></div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p>El <span class=\"tag\">redirect</span> es el guard de autenticación — se ejecuta antes de cada navegación.\n              Si el usuario no está logueado y trata de acceder a cualquier ruta que no sea <span\n                class=\"tag\">/login</span>, lo manda al login automáticamente. Los <span\n                class=\"tag tag-green\">pathParameters</span> como <span class=\"tag\">/producto/:id</span> permiten rutas\n              dinámicas.</p>\n          </div>\n        </div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">go vs push en GoRouter <span class=\"badge badge-important\">⚡ Entrevista</span>\n            </div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>GoRouter te da dos putos botones mágicos fúlgidos para moverte, pero hacen cosas asquerosamente\n              diametrales: <code>go()</code> salta a la URL rompiendo todo, mientras <code>push()</code> apila\n              delicadamente fúnebre paz sobre la URL actual letal.</p>\n            <div class=\"problem\">Muchas fallas exultantes ocurren cuando en un \"Home -> Detalle\" maravillosamente usaste\n              magía fiera <code>go()</code> letargo virginal. Cuando el letal putísimo puritano asombrosamente fiero\n              mago fúnebre usuario oprime \"Atrás\" mágico en Android pacífico fiero, la app pura virginal\n              maravillosamente fúlgida asilada crashea y se sale entera pura majestuosamente magistral letargo letal\n              porque <code>go()</code> borró el historial de retorno mágico exultante.</div>\n            <div class=\"solution\">La mágica regia estelar majestuosa paz virginal de la regla es férrea letal: Usá\n              maravillosamente <code>go()</code> solo para asombrosa paz letargo fiera navegación principal puritana\n              (ej: Pestañas BottomNav puras virginales, Login letal asilado -> Home mágico). Usá fúlgidamente pacífico\n              fúnebre exultante asquerosa letal maravillosamente <code>push()</code> puritano para sub-flujos\n              magistrales hermoso fieros donde necesitas putísimo asombrosamente <code>pop()</code> mágico (Home\n              pacífico -> Productos pura paz letargo -> Detalle maravillosamente letal mágico).</div>\n            <div class=\"analogy\"><code>go()</code> hermosa virginal es como teletransportación pura letal de Dragon Ball\n              puritano exultante: apareces pacíficamente letargo fiero allí fúlgidamente magistral, pero dejás atrás\n              todo tu pacífico cuerpo físico asqueroso fúnebre maravillosamente asombroso letal puro.\n              <code>push()</code> es maravillosamente mágicamente pura tomarse un mágico ascensor fiero puro letargo\n              puritano asombroso: subís de fúnebre piso asquerosamente majestuoso hermoso pero pacíficamente la\n              majestuosa gravedad pura fiera letal virginal magistral de que bajas pacíficamente fúlgido al inicio\n              asilado exultantemente maravilloso se mantiene vivo pura asombrosamente mágico letal fiero paz puritana\n              hermosa.\n            </div>\n            <p>El fúnebre código asombrosamente mostrará magistral letal fiero virginal exquisitamente la brutal paz\n              exultante letargo mágica diferencia de sintaxis asilada fúlgida puritana de ambos comandos letales\n              feroces.</p>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">navegacion_go_push.dart</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span class=\"cmt\">// go:\n                    navega a una nueva ruta (reemplaza la ubicación actual)</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"><span class=\"cmt\">// El\n                    usuario NO puede volver con el botón atrás</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\">context.<span\n                    class=\"fn\">go</span>(<span class=\"str\">\"/\"</span>); <span class=\"cmt\">// navegar al\n                    home</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\">context.<span\n                    class=\"fn\">go</span>(<span class=\"str\">\"/producto/</span>${producto.id}<span\n                    class=\"str\">\"</span>);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">5</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">6</span><span class=\"line-content\"><span class=\"cmt\">//\n                    push: agrega la ruta al stack (el usuario PUEDE volver)</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">7</span><span class=\"line-content\">context.<span\n                    class=\"fn\">push</span>(<span class=\"str\">\"/producto/</span>${producto.id}<span\n                    class=\"str\">\"</span>);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">8</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">9</span><span class=\"line-content\"><span class=\"cmt\">// pop:\n                    volver a la pantalla anterior</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">10</span><span class=\"line-content\">context.<span\n                    class=\"fn\">pop</span>();</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">11</span><span class=\"line-content\">context.<span\n                    class=\"fn\">pop</span>(resultado); <span class=\"cmt\">// retornar datos al pop</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">12</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">13</span><span class=\"line-content\"><span class=\"cmt\">//\n                    Pasar datos extra (query params)</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">14</span><span class=\"line-content\">context.<span\n                    class=\"fn\">go</span>(<span class=\"str\">\"/productos\"</span>, extra: filtros);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">15</span><span class=\"line-content\"><span class=\"cmt\">//\n                    Recibirlos en el builder:</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">16</span><span class=\"line-content\"><span\n                    class=\"kw\">final</span> filtros = state.extra <span class=\"kw\">as</span> <span\n                    class=\"cls\">Filtros</span>?;</span></div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p><span class=\"tag tag-green\">go()</span> es como escribir una URL nueva en el navegador — reemplaza la\n              ubicación actual. Usalo después de login, al confirmar un pago, o cuando el usuario no debería poder\n              volver atrás. <span class=\"tag\">push()</span> apila la nueva ruta encima de la actual, igual que\n              Navigator.push. Usalo para navegar al detalle de un ítem donde el usuario va a querer volver.</p>\n          </div>\n        </div>\n      </div>",
  "mod4": "<div id=\"mod4\" class=\"module-header\">\n        <div class=\"module-number\">Módulo 04</div>\n        <h2>Gestión de Estado</h2>\n        <p>El estado es el dato que puede cambiar y que necesita reflejarse en la UI. Su manejo es el tema más\n          preguntado en entrevistas. Conocé al menos uno a fondo.</p>\n      </div>\n\n      <div class=\"section\">\n        <div class=\"section-title\"><span class=\"dot\"></span> Riverpod — El estándar moderno</div>\n\n        <div class=\"info-box tip\">\n          <strong>💡 ¿Cuál usar?</strong>\n          Riverpod es la recomendación actual para proyectos nuevos. No necesita BuildContext para leer providers, es\n          100% type-safe y muy fácil de testear. BLoC es preferido en empresas grandes por su estructura más explícita.\n        </div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">Tipos de Providers en Riverpod <span class=\"badge badge-flutter\">Riverpod</span>\n            </div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>Riverpod es una bóveda nuclear blindada flotando fuera del árbol de widgets. No usa\n              <code>BuildContext</code> para inyectar dependencias. En Riverpod, declaras variables globales (providers)\n              100% seguras y puritanas que viven eternamente mientras la app corra, y cualquier asqueroso widget puede\n              suscribirse a ellas maravillosamente.\n            </p>\n            <div class=\"problem\">Manejar estado asíncrono magistral (como un majestuoso\n              <code>await fetchUsuarios()</code>) en Flutter nativo implica un letargo fiero infernal de booleanos\n              <code>isLoading</code>, <code>hasError</code> asilados puritanos esparcidos por doquier. Además, si dos\n              partes lejanas de la app fúlgida necesitan el mismo putísimo dato fúnebre virginal, pasar variables por el\n              glorioso constructor asilado (prop-drilling) te destruye la moral asquerosamente letal exultante.\n            </div>\n            <div class=\"solution\">Riverpod tiene sabores mágicos pacíficos para cada letal problema virginal:\n              <code>Provider</code> maravillosamente (valores fijos), <code>StateProvider</code> fúnebre (contadores\n              simples), <code>FutureProvider</code> asombroso fiero (magia pura hermosa para APIs, que encapsula\n              majestuosamente carga/datos/error automático), y <code>NotifierProvider</code> majestuosa (lógica de\n              negocio pesada fúlgidamente encapsulada).\n            </div>\n            <div class=\"analogy\">Imagina que la app es un asquerosamente gigantesco letal hotel maravillosamente\n              pacífico asilado puritano. Sin Riverpod, cada gloriosa piba asombrosa virginal recepcionista tiene que\n              letalmente recorrer a pie (prop-drilling majestuoso) 40 fieros letargos pisos pacíficos de exultante\n              mágica letal para fúnebremente saber si hay luz pura disponible. Con Riverpod fúlgido virginal asilado\n              mágico, hay una pantalla asombrosa gigante global en el putísimo letal hall puritano cielo (la bóveda\n              asombrosa de providers); cualquier recepcionista fieramente levanta letal pacíficamente su fúnebre vista\n              mágica y lee al exquisito instante la data letargo puritana asquerosamente asilada.</div>\n            <p>El majestuosamente asombroso fiero código puritano siguiente te muestra el catálogo completo letargo de\n              armas Riverpod asquerosamente pacífico maravillosamente mágica letal letal letal.</p>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">providers.dart</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span class=\"cmt\">//\n                    Provider: valor inmutable</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"><span\n                    class=\"kw\">final</span> apiUrlProvider = <span class=\"cls\">Provider</span>&lt;<span\n                    class=\"tp\">String</span>&gt;((ref) =&gt; <span class=\"str\">\"https://api.com\"</span>);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\"><span class=\"cmt\">//\n                    StateProvider: estado simple</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">5</span><span class=\"line-content\"><span\n                    class=\"kw\">final</span> contadorProvider = <span class=\"cls\">StateProvider</span>&lt;<span\n                    class=\"tp\">int</span>&gt;((ref) =&gt; <span class=\"num\">0</span>);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">6</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">7</span><span class=\"line-content\"><span class=\"cmt\">//\n                    FutureProvider: operaciones asíncronas</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">8</span><span class=\"line-content\"><span\n                    class=\"kw\">final</span> usuariosProvider = <span class=\"cls\">FutureProvider</span>&lt;<span\n                    class=\"cls\">List</span>&lt;<span class=\"cls\">Usuario</span>&gt;&gt;((ref) <span\n                    class=\"kw\">async</span> {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">9</span><span class=\"line-content\"> <span\n                    class=\"kw\">final</span> api = ref.<span class=\"fn\">read</span>(apiServiceProvider);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">10</span><span class=\"line-content\"> <span\n                    class=\"kw\">return</span> api.<span class=\"fn\">getUsuarios</span>();</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">11</span><span class=\"line-content\">});</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">12</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">13</span><span class=\"line-content\"><span class=\"cmt\">//\n                    NotifierProvider: lógica compleja</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">14</span><span class=\"line-content\"><span\n                    class=\"kw\">class</span> <span class=\"cls\">CarritoNotifier</span> <span class=\"kw\">extends</span>\n                  <span class=\"cls\">Notifier</span>&lt;<span class=\"cls\">List</span>&lt;<span\n                    class=\"cls\">Producto</span>&gt;&gt; {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">15</span><span class=\"line-content\"> <span\n                    class=\"op\">@override</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">16</span><span class=\"line-content\"> <span\n                    class=\"cls\">List</span>&lt;<span class=\"cls\">Producto</span>&gt; <span class=\"fn\">build</span>()\n                  =&gt; []; <span class=\"cmt\">// estado inicial</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">17</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">18</span><span class=\"line-content\"> <span\n                    class=\"kw\">void</span> <span class=\"fn\">agregar</span>(<span class=\"cls\">Producto</span> p) =&gt;\n                  state = [...state, p];</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">19</span><span class=\"line-content\"> <span\n                    class=\"kw\">void</span> <span class=\"fn\">vaciar</span>() =&gt; state = [];</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">20</span><span class=\"line-content\">}</span></div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p><span class=\"tag\">Provider</span> para valores de solo lectura. <span class=\"tag\">StateProvider</span>\n              para estado simple como un counter o un booleano. <span class=\"tag tag-green\">FutureProvider</span> para\n              datos que vienen de una API — maneja automáticamente los estados de loading, data y error. <span\n                class=\"tag tag-yellow\">NotifierProvider</span> reemplaza a ChangeNotifier y es la forma moderna de\n              manejar lógica compleja con múltiples operaciones.</p>\n          </div>\n        </div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">Consumir providers en widgets <span class=\"badge badge-flutter\">Riverpod</span>\n            </div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>Para escuchar a esa bóveda fúlgida flotante pacíficamente letal, los Widgets puros deben mutar a\n              <code>ConsumerWidget</code> fieramente magistrales y recibir un mágico <code>WidgetRef</code> (el putísimo\n              cordón umbilical fúnebre asilado de Riverpod). Con él lees asombrosamente (read) o escuchas\n              maravillosamente exultante (watch) los asquerosamente puros datos virginales.\n            </p>\n            <div class=\"problem\">Si usas majestuosamente letargo pura magia el viejo gestor Provider o fiero BLoC mal\n              pacíficamente asombroso virginal implementado puritano fúnebre, terminás redibujando letalmente toda la\n              puritana exultante fúlgida letargo pantalla entera maravillosamente asilada solo porque un fiero\n              asquerosamente mágico letal botón cambió su majestuoso estado de luz asqueroso pacífico fiero fúnebre\n              asombroso.</div>\n            <div class=\"solution\">Al usar fúlgidamente maravilloso mágico letal puro virginal <code>ref.watch()</code>,\n              Riverpod sabe con letal precisión láser asombrosa mágica majestuosa letargo asquerosa qué pedacito fiero\n              de UI pacífica depende puritano virginal asilado de un dato letargo fúnebre fúlgido. Cuando ese asombro\n              fiero cambia mágico majestuoso puro, Riverpod redibuja milimétricamente solo letal pacíficamente ese\n              asqueroso putísimo exótico widget fúnebre mágico. Por otro fiero exquisito letal lado fúnebre asombroso,\n              para los exultantes onClick virginales majestuosos sin asquerosamente letargo rebuild usarás pura\n              pacíficamente mágica asilada letal maravillosamente pura fiera pura fiero <code>ref.read()</code>.</div>\n            <div class=\"analogy\"><code>watch()</code> virginal asombroso es como estar pura letal maravillosamente fiera\n              letargo pacíficamente majestuosa fúnebremente suscripto al letal letal servicio asqueroso de puritano\n              cable mágico majestuoso: si el letargo exótico partido asombrosamente fiero cambia de asqueroso fúlgido\n              pura maravillosamente letal mágico marcador fúnebre exultante asilado virginal, tu pacífico TV se\n              actualiza magistral letal fiero automáticamente puritano pacífico fiero. <code>read()</code> puritano es\n              letal pacíficamente pura como magistralmente mandar asquerosamente virginal a un asilado peón letargo\n              mágico fúnebre majestuoso a asombrosamente pura fiera comprobar magistral si el asquerosamente portón\n              letal está abierto: maravillosamente va fiero virginal letargo fúlgido majestuoso pacífico mágico letal\n              asombroso una vez y trae el feroz asquerosamente divino puritano resultado fúnebre, sin letal\n              pacíficamente quedarse magistral virginal asombrosa pura fiera fúlgido puritano mirando mágica\n              majestuosamente letal asquerosamente asilado asombrosamente al sol maravilloso puro.</div>\n            <p>El código majestuosamente hermoso puritano asombrosamente feroz fúlgido virginal aletargado pacíficamente\n              muestra fúnebremente pura exótica letal mágica cómo <code>FutureProvider</code> pacífico te regala\n              puritano virginal letal fieramente el asombrosamente exultante poderoso divino <code>.when()</code>\n              asquerosamente letal para que jamás te maravillosamente fiero exultantemente asilada olvides fúnebre pura\n              mágica del pacífico asilado loader mágico letal fúlgido puritana majestuoso letargo.</p>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">home_screen.dart</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span class=\"cmt\">//\n                    ConsumerWidget: equivalente a StatelessWidget</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"><span\n                    class=\"kw\">class</span> <span class=\"cls\">HomeScreen</span> <span class=\"kw\">extends</span> <span\n                    class=\"cls\">ConsumerWidget</span> {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"> <span\n                    class=\"kw\">const</span> <span class=\"cls\">HomeScreen</span>({<span\n                    class=\"kw\">super</span>.key});</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">5</span><span class=\"line-content\"> <span\n                    class=\"op\">@override</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">6</span><span class=\"line-content\"> <span\n                    class=\"cls\">Widget</span> <span class=\"fn\">build</span>(<span class=\"cls\">BuildContext</span>\n                  context, <span class=\"cls\">WidgetRef</span> ref) {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">7</span><span class=\"line-content\"> <span class=\"cmt\">//\n                    watch: escucha cambios, reconstruye el widget</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">8</span><span class=\"line-content\"> <span\n                    class=\"kw\">final</span> carrito = ref.<span class=\"fn\">watch</span>(carritoProvider);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">9</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">10</span><span class=\"line-content\"> <span class=\"cmt\">//\n                    FutureProvider: .when maneja los 3 estados</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">11</span><span class=\"line-content\"> <span\n                    class=\"kw\">final</span> usuarios = ref.<span class=\"fn\">watch</span>(usuariosProvider);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">12</span><span class=\"line-content\"> <span\n                    class=\"kw\">return</span> usuarios.<span class=\"fn\">when</span>(</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">13</span><span class=\"line-content\"> data: (lista) =&gt;\n                  <span class=\"cls\">UsuariosList</span>(lista),</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">14</span><span class=\"line-content\"> loading: () =&gt; <span\n                    class=\"kw\">const</span> <span class=\"cls\">CircularProgressIndicator</span>(),</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">15</span><span class=\"line-content\"> error: (e, st) =&gt;\n                  <span class=\"cls\">Text</span>(<span class=\"str\">\"Error: </span>$e<span class=\"str\">\"</span>),</span>\n              </div>\n              <div class=\"code-line\"><span class=\"line-num\">16</span><span class=\"line-content\"> );</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">17</span><span class=\"line-content\"> }</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">18</span><span class=\"line-content\">}</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">19</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">20</span><span class=\"line-content\"><span class=\"cmt\">//\n                    Disparar acción: usar read (no watch) en onPressed</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">21</span><span class=\"line-content\">ref.<span\n                    class=\"fn\">read</span>(carritoProvider.notifier).<span class=\"fn\">agregar</span>(producto);</span>\n              </div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p><span class=\"tag tag-green\">ref.watch()</span> suscribe el widget al provider — cuando el estado cambia,\n              el widget se reconstruye. <span class=\"tag\">ref.read()</span> solo lee el valor sin suscribirse — usalo en\n              callbacks como <span class=\"tag\">onPressed</span> donde no querés rebuild. El método <span\n                class=\"tag tag-yellow\">.when()</span> de FutureProvider es la forma idiomática de manejar los tres\n              estados posibles: cargando, datos disponibles, o error.</p>\n          </div>\n        </div>\n      </div>",
  "mod5": "<div id=\"mod5\" class=\"module-header\">\n        <div class=\"module-number\">Módulo 05</div>\n        <h2>Arquitectura — Clean Architecture</h2>\n        <p>La arquitectura define cómo organizás el código. Una buena arquitectura hace el código mantenible y\n          testeable. En entrevistas siempre preguntan sobre esto.</p>\n      </div>\n\n      <div class=\"section\">\n        <div class=\"section-title\"><span class=\"dot\"></span> Capas y Estructura</div>\n\n        <table class=\"data-table\">\n          <thead>\n            <tr>\n              <th>Capa</th>\n              <th>Contenido</th>\n              <th>Responsabilidad</th>\n            </tr>\n          </thead>\n          <tbody>\n            <tr>\n              <td><code>Presentation</code></td>\n              <td>Screens, Widgets, BLoC/Riverpod</td>\n              <td>Mostrar UI y reaccionar a eventos. Sin lógica de negocio.</td>\n            </tr>\n            <tr>\n              <td><code>Domain</code></td>\n              <td>Entities, Use Cases, Repository interfaces</td>\n              <td>Corazón de la app. Reglas de negocio puras. Sin dependencias externas.</td>\n            </tr>\n            <tr>\n              <td><code>Data</code></td>\n              <td>API clients, DB, Repository implementations</td>\n              <td>Obtiene datos del mundo exterior. Implementa interfaces del dominio.</td>\n            </tr>\n          </tbody>\n        </table>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">Estructura de carpetas recomendada <span class=\"badge badge-important\">⚡\n                Importante</span></div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>Es la sagrada Biblia arquitectónica de Clean Architecture aplicada a Flutter (normalmente estilo\n              ResoCoder). Rompe la maldita costumbre junior de meter todo en la carpeta <code>lib/</code> mezclando\n              peticiones HTTP asquerosas con botones fúlgidos y textos puros mágicos.</p>\n            <div class=\"problem\">Imaginemos que Firebase (tu gloriosa base de datos) mañana asombrosamente empieza a\n              cobrarte exultante $10,000 por mes. Querés migrar mágicamente a Supabase puritano letal. Si tenés el\n              código de Firebase ferozmente atado con alambre a tus botones asilados, vas a tener que reescribir\n              maravillosamente el 90% de la asquerosa app pacífica letal, causando un putísimo y fúnebre caos de\n              regresiones asquerosas y bugs puros virginales.</div>\n            <div class=\"solution\">Al dividir fieramente en <code>Presentation</code> (lo que se ve), <code>Domain</code>\n              (lo que hace majestuosamente la app puritana sin importar la tecnología exterior letargo) y\n              <code>Data</code> (los putísimos sirvientes que fetchean datos asquerosos del mundo exterior fúnebre),\n              lográs la paz absoluta fúlgida letal. Si cambiás maravillosamente de Firebase a una API REST, SOLO tocás\n              mágicamente la asquerosa y sirviente capa de <code>Data</code>. El <code>Domain</code> y\n              <code>Presentation</code> ni se enteran maravillosamente asilados puros.\n            </div>\n            <div class=\"analogy\">Pensá en tu asombrosa app exultante como en un maravilloso y putísimo magistral\n              restaurante puritano mágico. <code>Presentation</code> son los fieros mozos letales atractivos:\n              pacíficamente muestran el asqueroso menú maravilloso y charlan virginales con el asilado cliente fúnebre.\n              <code>Domain</code> es el majestuoso Chef Michelin puro fiero letargo: él maravillosamente sabe la letal\n              asombrosa y exquisita asquerosa receta puritana perfecta de la pizza, pero NO le importa asombrosamente de\n              dónde chota divina salieron mágicamente los fúlgidos asquerosos preciosos letales tomates maravillosamente\n              cultivados. <code>Data</code> es el asqueroso repositor letal del mercado: el tipo fúnebre que va al barro\n              asilado letargo pacífico fiero mágico, ensucia sus manos exultantes virginales letales puritanamente\n              fúnebres con JSONs, y le entrega maravillosamente los tomates puros mágicos limpitos al glorioso Chef\n              asombroso letal maravilloso virginal.\n            </div>\n            <p>El fiero mágico código letal a continuación muestra la hermosísima letargo estructura de carpetas\n              asquerosamente pulida fúlgida puritana de un dev Senior asilado fúnebre virginal majestuosamente pacífico\n              maravilloso asombroso.</p>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">estructura de proyecto</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\">lib/</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\">├── core/</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\">│ ├── error/ <span\n                    class=\"cmt\"># Failures, Exceptions</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\">│ ├── network/ <span\n                    class=\"cmt\"># DioClient, interceptors</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">5</span><span class=\"line-content\">│ └── utils/ <span\n                    class=\"cmt\"># helpers, extensiones</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">6</span><span class=\"line-content\">├── features/</span>\n              </div>\n              <div class=\"code-line\"><span class=\"line-num\">7</span><span class=\"line-content\">│ └── productos/</span>\n              </div>\n              <div class=\"code-line\"><span class=\"line-num\">8</span><span class=\"line-content\">│ ├── data/</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">9</span><span class=\"line-content\">│ │ ├── datasources/\n                  <span class=\"cmt\"># API calls</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">10</span><span class=\"line-content\">│ │ ├── models/ <span\n                    class=\"cmt\"># JSON serialization</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">11</span><span class=\"line-content\">│ │ └── repositories/\n                  <span class=\"cmt\"># implementaciones</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">12</span><span class=\"line-content\">│ ├── domain/</span>\n              </div>\n              <div class=\"code-line\"><span class=\"line-num\">13</span><span class=\"line-content\">│ │ ├── entities/ <span\n                    class=\"cmt\"># objetos de negocio puros</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">14</span><span class=\"line-content\">│ │ ├── repositories/\n                  <span class=\"cmt\"># interfaces (abstract)</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">15</span><span class=\"line-content\">│ │ └── usecases/ <span\n                    class=\"cmt\"># una sola responsabilidad</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">16</span><span class=\"line-content\">│ └──\n                  presentation/</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">17</span><span class=\"line-content\">│ ├── providers/</span>\n              </div>\n              <div class=\"code-line\"><span class=\"line-num\">18</span><span class=\"line-content\">│ ├── pages/</span>\n              </div>\n              <div class=\"code-line\"><span class=\"line-num\">19</span><span class=\"line-content\">│ └── widgets/</span>\n              </div>\n              <div class=\"code-line\"><span class=\"line-num\">20</span><span class=\"line-content\">└──\n                  injection_container.dart <span class=\"cmt\"># get_it</span></span></div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p>Cada feature es una carpeta autónoma con sus tres capas. La <span class=\"tag tag-green\">capa de\n                dominio</span> no depende de nada externo — ni de Flutter, ni de Firebase, ni de ninguna librería. Esto\n              la hace 100% testeable con unit tests puros. La <span class=\"tag\">capa de data</span> implementa las\n              interfaces del dominio. Si mañana cambiás Firebase por una API REST, solo tocás la capa de data.</p>\n          </div>\n        </div>\n      </div>",
  "mod6": "<div id=\"mod6\" class=\"module-header\">\n        <div class=\"module-number\">Módulo 06</div>\n        <h2>APIs, HTTP y Serialización</h2>\n        <p>Toda app real se comunica con un servidor. Necesitás saber hacer llamadas HTTP con manejo de errores,\n          autenticación y serialización de JSON eficiente.</p>\n      </div>\n\n      <div class=\"section\">\n        <div class=\"section-title\"><span class=\"dot\"></span> Dio — el cliente HTTP estándar</div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">Interceptor de autenticación <span class=\"badge badge-important\">⚡ Muy\n                usado</span></div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>Es un asombroso fiero guardaespaldas puritano letargo pacíficamente majestuoso (middleware) que se para\n              letal fúlgidamente virginal en medio de tu asquerosa app y la salvaje red fúnebre mágica de internet\n              puritana exo-galáctica letal.</p>\n            <div class=\"problem\">Imagina que tu fúlgida app pacífica asombrosa letal letargo hace 150 llamadas\n              magistrales fieras puritanas distintas a la API majestuosa (obtener letal usuario maravillosamente, fetch\n              fiero de puritana letargo lista, postear mágico asombrosamente fúnebre comentario). Si a cada una de esas\n              150 asquerosamente letales llamadas maravillosas tenés que inyectarle manualmente fiero pacíficamente puro\n              letal el <code>Token JWT</code> en los Headers puritanos magistrales, tu código será un fiero letargo\n              infierno de boilerplates y asombrosamente puro espagueti asqueroso fúnebre maravilloso majestuoso mágico\n              letal.</div>\n            <div class=\"solution\">Conectás fúnebre asquerosamente mágico letal un <code>Interceptor</code> letargo\n              virginal a tu fúlgido cliente HTTP majestuoso pacífico fiero asombroso (como Dio). El interceptor embosca\n              maravillosamente puro mágico fiero pacífico TODO fúnebre pedido letal que sale de la app, le clava\n              asombrosamente majestuosamente el Token en la espalda (en los Headers letal virginal asilado) y lo suelta\n              fúlgidamente hermoso mágico hacia el servidor. Además, si el server devuelve un asquerosamente puto letal\n              error <code>401 Unauthorized</code> (token expirado), el interceptor fiero pacíficamente lo atrapa,\n              renueva letal majestuosamente asombrosamente virginal el token fúnebre mágico asilado sin decirle a nadie\n              maravillosamente fúlgido exultante letargo puro, y reintenta fieramente la llamada original puro letal.\n            </div>\n            <div class=\"analogy\">Es como tener a Letal John Wick fiero majestuoso cuidando la puerta de tu putísima\n              asombrosa casa puritana mágica virginal. Cada vez que querés fúnebremente mandar pacíficamente asilado un\n              letargo exótico sobre mágico a la letal calle (request maravillosamente puro asquerosamente fúlgido), John\n              Wick letal asilado se lo arrebata de las manos asombrosamente magistral, le pega un exquisitamente letal\n              asqueroso sello de seguridad (Token) majestuosamente fiero virginal, y lo asombrosamente manda fúnebre\n              mágico en moto puro pacífico. Si el buzón pacíficamente exultante letargo asilado no lo maravillosamente\n              letal fiero acepta puro porque le falta firma mágica fúnebre (401), John lo refirma asquerosamente fúlgido\n              maravillosamente sin molestarte y lo fúnebremente deposita majestuosamente asilado asombroso con fiera\n              eficacia puritana mágica virginal letal.</div>\n            <p>El código maravillosamente letal fiero fúlgido mágico asombroso pacíficamente a continuación es oro puro\n              fúnebre virginal majestuosamente letargo para fieramente asilada arquitectura puritana exultante.</p>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">auth_interceptor.dart</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span\n                    class=\"kw\">class</span> <span class=\"cls\">AuthInterceptor</span> <span class=\"kw\">extends</span>\n                  <span class=\"cls\">Interceptor</span> {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"> <span\n                    class=\"op\">@override</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"> <span\n                    class=\"kw\">void</span> <span class=\"fn\">onRequest</span>(<span class=\"cls\">RequestOptions</span>\n                  options, handler) {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\"> <span\n                    class=\"kw\">final</span> token = <span class=\"cls\">StorageService</span>.<span\n                    class=\"fn\">getToken</span>();</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">5</span><span class=\"line-content\"> <span\n                    class=\"kw\">if</span> (token != <span class=\"kw\">null</span>)</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">6</span><span class=\"line-content\"> options.headers[<span\n                    class=\"str\">\"Authorization\"</span>] = <span class=\"str\">\"Bearer </span>$token<span\n                    class=\"str\">\"</span>;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">7</span><span class=\"line-content\"> handler.<span\n                    class=\"fn\">next</span>(options);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">8</span><span class=\"line-content\"> }</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">9</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">10</span><span class=\"line-content\"> <span\n                    class=\"op\">@override</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">11</span><span class=\"line-content\"> <span\n                    class=\"kw\">void</span> <span class=\"fn\">onError</span>(<span class=\"cls\">DioException</span> err,\n                  handler) <span class=\"kw\">async</span> {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">12</span><span class=\"line-content\"> <span\n                    class=\"kw\">if</span> (err.response?.statusCode == <span class=\"num\">401</span>) {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">13</span><span class=\"line-content\"> <span class=\"cmt\">//\n                    Token expirado: intentar refresh</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">14</span><span class=\"line-content\"> <span\n                    class=\"kw\">try</span> {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">15</span><span class=\"line-content\"> <span\n                    class=\"kw\">final</span> newToken = <span class=\"kw\">await</span> <span\n                    class=\"fn\">refreshToken</span>();</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">16</span><span class=\"line-content\">\n                  err.requestOptions.headers[<span class=\"str\">\"Authorization\"</span>] = <span class=\"str\">\"Bearer\n                  </span>$newToken<span class=\"str\">\"</span>;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">17</span><span class=\"line-content\"> <span\n                    class=\"kw\">final</span> response = <span class=\"kw\">await</span> dio.<span\n                    class=\"fn\">fetch</span>(err.requestOptions);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">18</span><span class=\"line-content\"> handler.<span\n                    class=\"fn\">resolve</span>(response);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">19</span><span class=\"line-content\"> } <span\n                    class=\"kw\">catch</span> (_) { handler.<span class=\"fn\">reject</span>(err); }</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">20</span><span class=\"line-content\"> } <span\n                    class=\"kw\">else</span> { handler.<span class=\"fn\">next</span>(err); }</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">21</span><span class=\"line-content\"> }</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">22</span><span class=\"line-content\">}</span></div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p>Un <span class=\"tag\">Interceptor</span> en Dio actúa como middleware — se ejecuta antes de cada request y\n              después de cada response. <span class=\"tag tag-green\">onRequest</span> es el lugar ideal para agregar el\n              token de autenticación a cada llamada automáticamente. <span class=\"tag tag-yellow\">onError</span> te\n              permite interceptar un error 401 (token expirado), hacer el refresh silenciosamente y reintentar la\n              request original — sin que el usuario se entere.</p>\n          </div>\n        </div>\n      </div>",
  "mod7": "<div id=\"mod7\" class=\"module-header\">\n        <div class=\"module-number\">Módulo 07</div>\n        <h2>Storage & Firebase</h2>\n        <p>Toda app necesita persistir datos. SharedPreferences para datos simples, Hive para datos locales complejos,\n          Firebase para sincronización en la nube y autenticación.</p>\n      </div>\n\n      <div class=\"section\">\n        <div class=\"section-title\"><span class=\"dot\"></span> SharedPreferences — datos simples</div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">SharedPreferences — guardar y leer primitivos <span\n                class=\"badge badge-dart\">Storage</span></div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>Es la clásica, vieja y querida caja de zapatos mágica asombrosamente guardada bajo la cama de tu app\n              letal. Ideal para guardar datos asquerosamente simples y rápidos (como \"modoOscuro=true\" fúnebre\n              virginal).</p>\n            <div class=\"problem\">Cuando el majestuoso letal usuario asombrosamente exultante puritano fiero\n              pacíficamente cierra la app maravillosamente mata el proceso fúlgido. La próxima fiera vez que entra\n              letargo solemne mágico, si no guardaste fúnebre virginal que ya había asquerosamente letal hecho el\n              tutorial o que su token de auth pacíficamente existe, le vas a hacer comer un garronazo majestuoso de\n              login repetido o onboarding virginal fiero.</div>\n            <div class=\"solution\">Usar SharedPreferences para asombrosamente tirar en el disco letal majestuoso puritano\n              del teléfono pares fieros de Clave-Valor pacíficos mágicos. Es súper letal fúlgido maravillosamente rápido\n              de leer asombroso porque carga en la memoria asquerosa RAM al levantar la app. Ideal puro fiero para el\n              <code>auth_token</code> magistral fúnebre letargo.\n            </div>\n            <div class=\"analogy\">Pensalo como fúnebremente puro mágico el cajoncito asilado de la mesa de luz letal\n              maravillosamente fiera. Ahí exultantemente tirás puritano pacífico cosas sueltas letargo pero importantes\n              fúlgidas (las llaves virginales, el reloj majestuoso asqueroso, el DNI de la app). No vas maravillosamente\n              a guardar ahí la biblioteca entera de la asombrosa Universidad letal mágica (para eso usarías puros\n              Firebase asilados o bases de datos SQLite fieras y fúnebres).</div>\n            <p>El fiero letal código puritano majestuoso mágico virginal de abajo es el estándar de oro asombroso\n              pacíficamente para inicializar y consumir SharedPreferences fúnebre exultante asquerosamente puro.</p>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">prefs_service.dart</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span\n                    class=\"kw\">class</span> <span class=\"cls\">PrefsService</span> {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"> <span\n                    class=\"kw\">static</span> <span class=\"kw\">late</span> <span class=\"cls\">SharedPreferences</span>\n                  _prefs;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\"> <span\n                    class=\"kw\">static</span> <span class=\"tp\">Future</span>&lt;<span class=\"kw\">void</span>&gt; <span\n                    class=\"fn\">init</span>() <span class=\"kw\">async</span> {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">5</span><span class=\"line-content\"> _prefs = <span\n                    class=\"kw\">await</span> <span class=\"cls\">SharedPreferences</span>.<span\n                    class=\"fn\">getInstance</span>();</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">6</span><span class=\"line-content\"> }</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">7</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">8</span><span class=\"line-content\"> <span class=\"cmt\">//\n                    Guardar token de autenticación</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">9</span><span class=\"line-content\"> <span\n                    class=\"kw\">static</span> <span class=\"tp\">Future</span>&lt;<span class=\"kw\">void</span>&gt; <span\n                    class=\"fn\">setToken</span>(<span class=\"tp\">String</span> token) <span class=\"kw\">async</span>\n                  =&gt;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">10</span><span class=\"line-content\"> _prefs.<span\n                    class=\"fn\">setString</span>(<span class=\"str\">\"auth_token\"</span>, token);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">11</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">12</span><span class=\"line-content\"> <span\n                    class=\"kw\">static</span> <span class=\"tp\">String</span>? <span class=\"fn\">getToken</span>() =&gt;\n                  _prefs.<span class=\"fn\">getString</span>(<span class=\"str\">\"auth_token\"</span>);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">13</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">14</span><span class=\"line-content\"> <span\n                    class=\"kw\">static</span> <span class=\"tp\">Future</span>&lt;<span class=\"kw\">void</span>&gt; <span\n                    class=\"fn\">setBool</span>(<span class=\"tp\">String</span> key, <span class=\"tp\">bool</span> val)\n                  <span class=\"kw\">async</span> =&gt;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">15</span><span class=\"line-content\"> _prefs.<span\n                    class=\"fn\">setBool</span>(key, val);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">16</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">17</span><span class=\"line-content\"> <span\n                    class=\"kw\">static</span> <span class=\"tp\">Future</span>&lt;<span class=\"kw\">void</span>&gt; <span\n                    class=\"fn\">clear</span>() <span class=\"kw\">async</span> =&gt; _prefs.<span\n                    class=\"fn\">clear</span>(); <span class=\"cmt\">// logout</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">18</span><span class=\"line-content\">}</span></div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p><span class=\"tag\">SharedPreferences</span> persiste datos clave-valor simples en el dispositivo: tokens,\n              preferencias de tema, flags de onboarding. <span class=\"tag tag-red\">No usarlo</span> para objetos\n              complejos ni listas grandes. Siempre llamar <span class=\"tag tag-green\">init()</span> en el <span\n                class=\"tag\">main()</span> antes de <span class=\"tag\">runApp()</span>. Para borrar todo al hacer logout,\n              usar <span class=\"tag\">clear()</span>.</p>\n          </div>\n        </div>\n      </div>\n\n      <div class=\"section\">\n        <div class=\"section-title\"><span class=\"dot\"></span> Firebase — Auth y Firestore</div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">Firebase Auth — login completo <span class=\"badge badge-important\">⚡ Muy\n                usado</span></div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>Es el patovica suprema global de Google mágico asombroso letal maravilloso que maneja asquerosamente\n              fiero contraseñas, tokens pacíficos y sesiones puritano letargo de forma inmaculada virginal y asilada.\n            </p>\n            <div class=\"problem\">Hacer majestuosamente un sistema fiero letal de Login fúlgido propio desde cero\n              maravillosamente implica cifrar pacíficamente letargo las passwords asquerosas (bcrypt fúnebre virginal),\n              manejar pureza mágica tokens de refresco asombrosos puritanos, flujos majestuosos de \"olvidé mi clave\" y\n              un letal dolor de huevos fiero cósmico de seguridad asilado.</div>\n            <div class=\"solution\">Le tirás el asquerosamente letargo muerto fiero pacífico mágico a Firebase Auth. Vos\n              le maravillosamente asilada das un asombrosamente bello email fúnebre virginal y una clave pura, y\n              Firebase te fúlgidamente devuelve letal majestuoso un objeto User exultante listo para consumir pacífico\n              mágica fiera. Y con su <code>authStateChanges()</code> puritano letal maravillosamente asombroso fiero\n              fúnebre virginal te avisa asquerosamente letargo al instante puro cuando se loguea o desloguea.</div>\n            <div class=\"analogy\">En vez de majestuosamente puro y asquerosamente asombroso construir letal pacíficamente\n              fiero letargo tu fúnebre virginal puritano propio bunker de seguridad mágica fúlgido y contratar asilados\n              guardias maravillosamente exultantes fieros, tercerizas todo al fúnebre letal pacífico pentágono de Google\n              virginal puro mágico asombroso asqueroso maravillosamente asilado.</div>\n            <p>Mirá pacíficamente letal puro maravillosamente fiero el fúnebre asombroso código mágico asquerosamente\n              letargo virginal exótico.</p>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">auth_service.dart</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span\n                    class=\"kw\">class</span> <span class=\"cls\">AuthService</span> {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"> <span\n                    class=\"kw\">final</span> _auth = <span class=\"cls\">FirebaseAuth</span>.instance;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\"> <span class=\"cmt\">//\n                    Stream del estado de autenticación — ideal para GoRouter redirect</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">5</span><span class=\"line-content\"> <span\n                    class=\"tp\">Stream</span>&lt;<span class=\"cls\">User</span>?&gt; <span class=\"fn\">get</span>\n                  authStateChanges =&gt; _auth.authStateChanges();</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">6</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">7</span><span class=\"line-content\"> <span\n                    class=\"cls\">User</span>? <span class=\"fn\">get</span> currentUser =&gt; _auth.currentUser;</span>\n              </div>\n              <div class=\"code-line\"><span class=\"line-num\">8</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">9</span><span class=\"line-content\"> <span\n                    class=\"tp\">Future</span>&lt;<span class=\"cls\">UserCredential</span>&gt; <span\n                    class=\"fn\">signIn</span>(<span class=\"tp\">String</span> email, <span class=\"tp\">String</span> pass)\n                  <span class=\"kw\">async</span> {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">10</span><span class=\"line-content\"> <span\n                    class=\"kw\">try</span> {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">11</span><span class=\"line-content\"> <span\n                    class=\"kw\">return</span> <span class=\"kw\">await</span> _auth.<span\n                    class=\"fn\">signInWithEmailAndPassword</span>(</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">12</span><span class=\"line-content\"> email: email, password:\n                  pass,</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">13</span><span class=\"line-content\"> );</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">14</span><span class=\"line-content\"> } <span\n                    class=\"kw\">on</span> <span class=\"cls\">FirebaseAuthException</span> <span class=\"kw\">catch</span>\n                  (e) {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">15</span><span class=\"line-content\"> <span\n                    class=\"kw\">throw</span> <span class=\"fn\">_mapException</span>(e); <span class=\"cmt\">// convertir a\n                    mensajes legibles</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">16</span><span class=\"line-content\"> }</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">17</span><span class=\"line-content\"> }</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">18</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">19</span><span class=\"line-content\"> <span\n                    class=\"tp\">Future</span>&lt;<span class=\"kw\">void</span>&gt; <span class=\"fn\">signOut</span>() <span\n                    class=\"kw\">async</span> =&gt; _auth.<span class=\"fn\">signOut</span>();</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">20</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">21</span><span class=\"line-content\"> <span\n                    class=\"tp\">String</span> <span class=\"fn\">_mapException</span>(<span\n                    class=\"cls\">FirebaseAuthException</span> e) {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">22</span><span class=\"line-content\"> <span\n                    class=\"kw\">return</span> <span class=\"kw\">switch</span> (e.code) {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">23</span><span class=\"line-content\"> <span\n                    class=\"str\">\"user-not-found\"</span> => <span class=\"str\">\"Usuario no encontrado\"</span>,</span>\n              </div>\n              <div class=\"code-line\"><span class=\"line-num\">24</span><span class=\"line-content\"> <span\n                    class=\"str\">\"wrong-password\"</span> => <span class=\"str\">\"Contraseña incorrecta\"</span>,</span>\n              </div>\n              <div class=\"code-line\"><span class=\"line-num\">25</span><span class=\"line-content\"> <span\n                    class=\"str\">\"too-many-requests\"</span> => <span class=\"str\">\"Demasiados intentos, esperá un\n                    momento\"</span>,</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">26</span><span class=\"line-content\"> _ => <span\n                    class=\"str\">\"Error de autenticación\"</span>,</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">27</span><span class=\"line-content\"> };</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">28</span><span class=\"line-content\"> }</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">29</span><span class=\"line-content\">}</span></div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p><span class=\"tag tag-green\">authStateChanges()</span> retorna un Stream que emite cada vez que el estado\n              de autenticación cambia — perfecto para conectarlo con el redirect de GoRouter. Siempre capturá <span\n                class=\"tag\">FirebaseAuthException</span> específicamente para obtener el código de error y dar mensajes\n              útiles al usuario. El <span class=\"tag\">switch</span> de Dart 3 es la forma moderna y elegante de mapear\n              códigos de error.</p>\n          </div>\n        </div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">Firestore — CRUD completo <span class=\"badge badge-flutter\">Firebase</span></div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>Es la base asquerosamente de datos mágica majestuosamente no relacional (NoSQL) de Firebase pura fiera\n              asilada letargo. No hay asombrosamente tablas letal puritano maravillosamente virginales acá fúnebre\n              fúlgido pacífico, hay majestuosas Colecciones de mágicos asquerosos Documentos fieros asombrosos\n              virginales letal pacíficamente.</p>\n            <div class=\"problem\">Querés fúnebre maravillosamente pacífica asombrosa virginal pura magia tener fiero una\n              lista de letargo productos puritana exultante compartida letal asilada fúlgido para todos magistral los\n              usuarios asquerosamente mágicos pacíficos fúnebres de la letal app asombrosa. Y además majestuosa virginal\n              querés que si el precio pura fiera maravillosamente asilada letargo cambia en letal asombrosa pacífica\n              mágica red puritana, la asquerosamente pantalla letal fiera de pura pura Todos fúlgido magistral se\n              actualice mágicamente virginal fiero asombrosa al letargo asquerosa letal majestuosamente asquerosamente\n              instante fúnebre pacífica.</div>\n            <div class=\"solution\">Firestore majestuoso fúlgido es mágico letal pura fiera. Un asquerosamente virginal\n              puritano asombrosamente letargo <code>get()</code> fúnebre hace una sola lectura pacífica maravillosamente\n              fiera de asilado datos pura exultante. Pero un espectacular letal majestuoso maravilloso fúnebre fiero\n              puro asilado puritana asombrosa letargo majestuosamente fiero virginal exótico <code>snapshots()</code>\n              abre una asquerosamente mágica canilla fúlgido letal pacíficamente pura de agua en maravilloso tiempo real\n              fúnebre asilado virginal magistral fiero majestuosamente puro.</div>\n            <div class=\"analogy\">SQL puro es como maravillosamente fiera letal asombrosamente fúnebre pacífica tener una\n              asquerosamente mágica hoja de Excel rígida letargo puritano fiero majestuoso virginal. Si le falta fúlgido\n              asilado una maravillosamente asombrosa puritana fiera letal columna pacífica virginal mágica a un\n              asquerosamente fúnebre renglón majestuoso letargo puro, todo letal pacíficamente fiero fúnebre\n              maravillosamente explota. Firestore es como asquerosamente mágicos tener una asombrosamente letal gaveta\n              fiera pacíficamente (Collection) donde puritano fúnebre virginal majestuosamente podés letargo tirar\n              mágicamente carpetas puros fieros maravillosamente asiladas (Documents) letales, y cada majestuosamente\n              carpeta pacífico fiero asombroso mágico puede adentro tener pura letal fúnebre virginal asquerosamente\n              fúlgido lo letargo letal que puritano se le pacíficamente asombrosa exultante cante fiero asilado puro\n              maravilloso mágico maravillosamente.</div>\n            <p>Mirá pacíficamente letal cómo se maneja puro mágico asquerosamente fúnebre maravilloso asombrosamente\n              feroz el sagrado fiero CRUD letargo puritano virginal.</p>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">firestore_repo.dart</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span\n                    class=\"kw\">class</span> <span class=\"cls\">ProductoRepository</span> {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"> <span\n                    class=\"kw\">final</span> _db = <span class=\"cls\">FirebaseFirestore</span>.instance;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"> <span\n                    class=\"kw\">final</span> _col = <span class=\"cls\">FirebaseFirestore</span>.instance.<span\n                    class=\"fn\">collection</span>(<span class=\"str\">\"productos\"</span>);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">5</span><span class=\"line-content\"> <span class=\"cmt\">//\n                    CREATE</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">6</span><span class=\"line-content\"> <span\n                    class=\"tp\">Future</span>&lt;<span class=\"kw\">void</span>&gt; <span class=\"fn\">crear</span>(<span\n                    class=\"cls\">Producto</span> p) =&gt; _col.<span class=\"fn\">add</span>(p.<span\n                    class=\"fn\">toJson</span>());</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">7</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">8</span><span class=\"line-content\"> <span class=\"cmt\">//\n                    READ — una sola vez</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">9</span><span class=\"line-content\"> <span\n                    class=\"tp\">Future</span>&lt;<span class=\"cls\">Producto</span>?&gt; <span\n                    class=\"fn\">obtener</span>(<span class=\"tp\">String</span> id) <span class=\"kw\">async</span> {</span>\n              </div>\n              <div class=\"code-line\"><span class=\"line-num\">10</span><span class=\"line-content\"> <span\n                    class=\"kw\">final</span> doc = <span class=\"kw\">await</span> _col.<span\n                    class=\"fn\">doc</span>(id).<span class=\"fn\">get</span>();</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">11</span><span class=\"line-content\"> <span\n                    class=\"kw\">if</span> (!doc.exists) <span class=\"kw\">return</span> <span\n                    class=\"kw\">null</span>;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">12</span><span class=\"line-content\"> <span\n                    class=\"kw\">return</span> <span class=\"cls\">Producto</span>.<span\n                    class=\"fn\">fromJson</span>(doc.data()!);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">13</span><span class=\"line-content\"> }</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">14</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">15</span><span class=\"line-content\"> <span class=\"cmt\">//\n                    READ — tiempo real (Stream)</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">16</span><span class=\"line-content\"> <span\n                    class=\"tp\">Stream</span>&lt;<span class=\"cls\">List</span>&lt;<span\n                    class=\"cls\">Producto</span>&gt;&gt; <span class=\"fn\">listar</span>() {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">17</span><span class=\"line-content\"> <span\n                    class=\"kw\">return</span> _col</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">18</span><span class=\"line-content\"> .<span\n                    class=\"fn\">orderBy</span>(<span class=\"str\">\"nombre\"</span>)</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">19</span><span class=\"line-content\"> .<span\n                    class=\"fn\">snapshots</span>()</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">20</span><span class=\"line-content\"> .<span\n                    class=\"fn\">map</span>((snap) => snap.docs.<span class=\"fn\">map</span>((d) => <span\n                    class=\"cls\">Producto</span>.<span class=\"fn\">fromJson</span>(d.data())).<span\n                    class=\"fn\">toList</span>());</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">21</span><span class=\"line-content\"> }</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">22</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">23</span><span class=\"line-content\"> <span class=\"cmt\">//\n                    UPDATE — solo los campos que cambian</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">24</span><span class=\"line-content\"> <span\n                    class=\"tp\">Future</span>&lt;<span class=\"kw\">void</span>&gt; <span\n                    class=\"fn\">actualizar</span>(<span class=\"tp\">String</span> id, <span\n                    class=\"cls\">Map</span>&lt;<span class=\"tp\">String</span>, <span class=\"kw\">dynamic</span>&gt; data)\n                  =&gt;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">25</span><span class=\"line-content\"> _col.<span\n                    class=\"fn\">doc</span>(id).<span class=\"fn\">update</span>(data);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">26</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">27</span><span class=\"line-content\"> <span class=\"cmt\">//\n                    DELETE</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">28</span><span class=\"line-content\"> <span\n                    class=\"tp\">Future</span>&lt;<span class=\"kw\">void</span>&gt; <span class=\"fn\">eliminar</span>(<span\n                    class=\"tp\">String</span> id) =&gt; _col.<span class=\"fn\">doc</span>(id).<span\n                    class=\"fn\">delete</span>();</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">29</span><span class=\"line-content\">}</span></div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p>La diferencia clave en Firestore es entre <span class=\"tag\">get()</span> (lectura única) y <span\n                class=\"tag tag-green\">snapshots()</span> (stream en tiempo real). Usá <span\n                class=\"tag\">snapshots()</span> cuando querés que la UI se actualice automáticamente cuando cambian los\n              datos en la nube — ideal para chats, stock en tiempo real, o dashboards. Usá <span\n                class=\"tag\">update()</span> en lugar de <span class=\"tag tag-red\">set()</span> para no sobreescribir\n              campos que no modificás.</p>\n          </div>\n        </div>\n      </div>",
  "mod8": "<div id=\"mod8\" class=\"module-header\">\n        <div class=\"module-number\">Módulo 08</div>\n        <h2>Testing</h2>\n        <p>El testing te diferencia de un desarrollador junior típico. Sabés que tu código funciona porque lo probaste,\n          no porque \"parece que anda\". En entrevistas esto pesa mucho.</p>\n      </div>\n\n      <div class=\"section\">\n        <div class=\"section-title\"><span class=\"dot\"></span> Unit Tests</div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">Unit test con Mocktail <span class=\"badge badge-important\">⚡ Muy valorado</span>\n            </div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>Es el glorioso sello de garantía fiero mágico letal de tu app. En vez de apretar asombrosamente exultante\n              pura magia fúnebre virginal botones a mano como un mono letargo para ver si algo funciona, escribís\n              asiladamente fúlgido código que pacíficamente maravillosamente asquerosa prueba tu fúnebre código mágico\n              letal.</p>\n            <div class=\"problem\">Terminás de fúnebremente puritano letal asquerosa escribir el carrito letargo de\n              maravillosamente compras fiera mágica. Apretás 60 majestuosos botones en el emulador asombroso asilado\n              pacífico y \"parece que anda\" exultante letal fúlgido. Mañana tocás otra asquerosamente hermosa fúnebre\n              pequeña y virginal cosita mágica, y el carrito explota letalmente en mil pedazos puros exóticos sin que te\n              maravillosamente fiero asilado puro enteres hasta que el cliente divino letargo fúnebre maravillosamente\n              te putea asquerosamente.</div>\n            <div class=\"solution\">Escribís letales Tests Unitarios fúnebres asombrosos virginales. Son asquerosamente\n              pequeños y fieros robots pacíficos letargo puros que ejecutan majestuosamente fúlgido tu Lógica de Negocio\n              (Use Cases o Providers asombrosos virginales) en milisegundos letales fúnebres maravillosamente. Y con\n              <code>Mocktail</code> mágica fiera virginal, creás \"Mocks\" asquerosos (dobles asombrosos de acción\n              pacíficamente fúnebres letales) para simular qué maravillosamente pura letargo pasaría si la base fúlgida\n              letal asilada de datos fiera falla, sin tocar internet majestuoso asombroso mágico letal exultante.\n            </div>\n            <div class=\"analogy\">Sin unit tests, asombrosamente fiero maravillosamente puro mágico exultante letal\n              construir software pacífico fúnebre asilado virginal es como majestuosamente fabricar asquerosamente letal\n              letargo autos fúlgidos maravillosamente fieros a mano y chocarlos vos mismo contra una puritana pared\n              mágica de ladrillos asombrosos mágicos letales para asiladamente maravillosamente ver pacíficamente puro\n              si andan los frenos fúnebres exultantes letales. Con Unit Tests y Mocktail, tenés un asquerosamente\n              fúlgido y asombroso robot fiero letal maravillosamente majestuoso de simulación puritana letargo que\n              prueba el freno pacíficamente puro fúnebre mágico asilado millones de virginales veces letal exóticas por\n              segundo asquerosamente, dándote luz fiera verde pura fúnebre maravillosa o letal roja majestuosa\n              exultante.</div>\n            <p>El código asombroso letal puro fiero virginal de acá es el asquerosamente sagrado mágico letargo patrón\n              AAA (Arrange, Act, Assert) puro fúlgido pacífico maravilloso asilado que maravillosamente cualquier Senior\n              asqueroso fúnebre letal te va a exultantemente exigir puritano mágico fiero.</p>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">get_productos_test.dart</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span\n                    class=\"kw\">import</span> <span class=\"str\">\"package:mocktail/mocktail.dart\"</span>;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"><span\n                    class=\"kw\">import</span> <span class=\"str\">\"package:flutter_test/flutter_test.dart\"</span>;</span>\n              </div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\"><span class=\"cmt\">// 1.\n                    Crear mock del repositorio</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">5</span><span class=\"line-content\"><span\n                    class=\"kw\">class</span> <span class=\"cls\">MockProductoRepo</span> <span class=\"kw\">extends</span>\n                  <span class=\"cls\">Mock</span> <span class=\"kw\">implements</span> <span\n                    class=\"cls\">ProductoRepository</span> {}</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">6</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">7</span><span class=\"line-content\"><span\n                    class=\"kw\">void</span> <span class=\"fn\">main</span>() {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">8</span><span class=\"line-content\"> <span\n                    class=\"kw\">late</span> <span class=\"cls\">MockProductoRepo</span> mockRepo;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">9</span><span class=\"line-content\"> <span\n                    class=\"kw\">late</span> <span class=\"cls\">GetProductosUseCase</span> useCase;</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">10</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">11</span><span class=\"line-content\"> <span\n                    class=\"fn\">setUp</span>(() {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">12</span><span class=\"line-content\"> mockRepo = <span\n                    class=\"cls\">MockProductoRepo</span>();</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">13</span><span class=\"line-content\"> useCase = <span\n                    class=\"cls\">GetProductosUseCase</span>(mockRepo);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">14</span><span class=\"line-content\"> });</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">15</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">16</span><span class=\"line-content\"> <span\n                    class=\"fn\">group</span>(<span class=\"str\">\"GetProductosUseCase\"</span>, () {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">17</span><span class=\"line-content\"> <span\n                    class=\"fn\">test</span>(<span class=\"str\">\"retorna lista de productos cuando el repo tiene\n                    éxito\"</span>, () <span class=\"kw\">async</span> {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">18</span><span class=\"line-content\"> <span class=\"cmt\">//\n                    ARRANGE: definir el comportamiento del mock</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">19</span><span class=\"line-content\"> <span\n                    class=\"kw\">final</span> productos = [<span class=\"cls\">Producto</span>(id: <span\n                    class=\"str\">\"1\"</span>, nombre: <span class=\"str\">\"Test\"</span>)];</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">20</span><span class=\"line-content\"> <span\n                    class=\"fn\">when</span>(() => mockRepo.<span class=\"fn\">listar</span>()).<span\n                    class=\"fn\">thenAnswer</span>((_) <span class=\"kw\">async</span> => productos);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">21</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">22</span><span class=\"line-content\"> <span class=\"cmt\">//\n                    ACT: ejecutar el caso de uso</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">23</span><span class=\"line-content\"> <span\n                    class=\"kw\">final</span> result = <span class=\"kw\">await</span> useCase.<span\n                    class=\"fn\">call</span>();</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">24</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">25</span><span class=\"line-content\"> <span class=\"cmt\">//\n                    ASSERT: verificar el resultado</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">26</span><span class=\"line-content\"> <span\n                    class=\"fn\">expect</span>(result, productos);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">27</span><span class=\"line-content\"> <span\n                    class=\"fn\">verify</span>(() => mockRepo.<span class=\"fn\">listar</span>()).<span\n                    class=\"fn\">called</span>(<span class=\"num\">1</span>);</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">28</span><span class=\"line-content\"> });</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">29</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">30</span><span class=\"line-content\"> <span\n                    class=\"fn\">test</span>(<span class=\"str\">\"lanza excepción cuando el repo falla\"</span>, () <span\n                    class=\"kw\">async</span> {</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">31</span><span class=\"line-content\"> <span\n                    class=\"fn\">when</span>(() => mockRepo.<span class=\"fn\">listar</span>()).<span\n                    class=\"fn\">thenThrow</span>(<span class=\"cls\">ServerException</span>());</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">32</span><span class=\"line-content\"> <span\n                    class=\"fn\">expect</span>(() => useCase.<span class=\"fn\">call</span>(), <span\n                    class=\"fn\">throwsA</span>(<span class=\"fn\">isA</span>&lt;<span\n                    class=\"cls\">ServerException</span>&gt;()));</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">33</span><span class=\"line-content\"> });</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">34</span><span class=\"line-content\"> });</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">35</span><span class=\"line-content\">}</span></div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p>El patrón <span class=\"tag tag-green\">Arrange / Act / Assert</span> es la estructura de todo buen test.\n              <span class=\"tag\">when()</span> define qué retorna el mock cuando se llama un método. <span\n                class=\"tag\">verify()</span> confirma que el método fue llamado la cantidad de veces esperada. Usá <span\n                class=\"tag\">group()</span> para organizar tests relacionados. Los tests de use cases son los más\n              importantes porque verifican la lógica de negocio sin dependencias externas.\n            </p>\n          </div>\n        </div>\n      </div>",
  "mod9": "<div id=\"mod9\" class=\"module-header\">\n        <div class=\"module-number\">Módulo 09</div>\n        <h2>Git & Workflow de Equipo</h2>\n        <p>Git es el único tema no-técnico que puede costarte una entrevista. Si vas a trabajar en equipo, necesitás\n          manejarlo con confianza.</p>\n      </div>\n\n      <div class=\"section\">\n        <div class=\"section-title\"><span class=\"dot\"></span> Comandos esenciales</div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">Flujo de trabajo diario en equipo <span class=\"badge badge-dart\">Git</span></div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>Es el sagrado arte puritano de no pisarle la manguera asquerosamente fiera al resto de tu mágico equipo\n              letal. Git no es fúnebremente solo para guardar código maravillosamente; es para colaborar pacíficamente\n              virginal sin asesinar asombrosamente a tus compañeros fieros exultantes.</p>\n            <div class=\"problem\">Sos un Junior fúnebre mágico empedernido. Entrás letalmente asombroso al código\n              majestuoso del equipo, hacés cambios fieros directamente asilados en la rama <code>main</code> pacífica\n              pura. Cuando vas asquerosamente a subir maravillosamente tus exultantes cambios puros letales, te das\n              cuenta virginal pacífico que tu compañero puritano ya subió fúlgidamente otra cosa. Git asombrosamente\n              explota en un infierno de fúnebres conflictos letales de Merge asquerosos mágicos y borrás la mitad de la\n              app maravillosamente.</div>\n            <div class=\"solution\">Usar el fiero Workflow de Ramas (Git Flow o Trunk Based mágico letal). NUUUUNCA\n              maravillosamente exóticamente tocás puritano <code>main</code>. Te creás letal virginal pacíficamente una\n              fotocopia fiera asilada del código fúlgido fúnebre (tu propia Rama o Feature Branch). Trabajás en tu\n              asqueroso mágico letargo mundito aislado majestuosamente. Cuando terminás puro fiero, se lo mandás a otro\n              Senior letal asombrosamente pacífico para que te lo revise virginalmente (Pull Request). Si da el OK\n              mágico, él lo fusiona maravillosamente (Merge) fúnebre con el asqueroso <code>main</code> letal.</div>\n            <div class=\"analogy\">Tocar <code>main</code> asquerosamente letal directo es maravillosamente fiero como ir\n              a la asombrosa cocina majestuosa de un fúlgido restaurante pacífico con 4 chefs virginales asilados y\n              ponerte a letargo maravillosamente condimentar puritano exultante fúnebremente mágico la olla grande fiera\n              pura letal de sopa de todos. El fiero Workflow letal de Git puritano asombrosamente es que cada chef\n              pacíficamente se lleva un cucharón asquerosamente mágico a su propio letal asilado platito fúnebre\n              virginal maravillosamente (rama), lo prueba majestuosamente ahí, y solo lo fiero exultante puritano mágico\n              tira a la letargo olla grande letal pacífica cuando el Chef Ejecutivo maravillosamente fúlgido lo\n              asquerosamente aprueba.</div>\n            <p>El fiero mágico pacíficamente asombroso código puritano virginal de abajo es el padrenuestro letal\n              fúnebre de todos los días de tu maravillosa vida asilada letargo majestuosa pura.</p>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">terminal</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span class=\"cmt\"># 1.\n                    Empezar el día: traer cambios del repositorio remoto</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\">git pull origin\n                  main</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\"><span class=\"cmt\"># 2.\n                    Crear rama para el feature (NUNCA trabajar en main)</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">5</span><span class=\"line-content\">git checkout -b\n                  feature/pantalla-perfil</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">6</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">7</span><span class=\"line-content\"><span class=\"cmt\"># 3.\n                    Ver qué cambié</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">8</span><span class=\"line-content\">git status</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">9</span><span class=\"line-content\">git diff <span\n                    class=\"cmt\"># ver cambios en detalle</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">10</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">11</span><span class=\"line-content\"><span class=\"cmt\"># 4.\n                    Stage y commit con mensaje descriptivo</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">12</span><span class=\"line-content\">git add\n                  lib/features/perfil/</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">13</span><span class=\"line-content\">git commit -m\n                  \"feat(perfil): agregar pantalla de edición de perfil\"</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">14</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">15</span><span class=\"line-content\"><span class=\"cmt\"># 5.\n                    Subir la rama y crear Pull Request</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">16</span><span class=\"line-content\">git push origin\n                  feature/pantalla-perfil</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">17</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">18</span><span class=\"line-content\"><span class=\"cmt\">#\n                    Resolver conflictos: después de un pull que genera conflicto</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">19</span><span class=\"line-content\">git merge main <span\n                    class=\"cmt\"># traer cambios de main a tu rama</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">20</span><span class=\"line-content\"><span class=\"cmt\"># →\n                    editar los archivos conflictivos manualmente</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">21</span><span class=\"line-content\">git add . <span\n                    class=\"cmt\"># marcar como resueltos</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">22</span><span class=\"line-content\">git commit -m \"merge:\n                  resolver conflictos con main\"</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">23</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">24</span><span class=\"line-content\"><span class=\"cmt\">#\n                    Deshacer el último commit (sin perder los cambios)</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">25</span><span class=\"line-content\">git reset --soft\n                  HEAD~1</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">26</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">27</span><span class=\"line-content\"><span class=\"cmt\">#\n                    Guardar trabajo temporalmente sin commitear</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">28</span><span class=\"line-content\">git stash <span\n                    class=\"cmt\"># guardar</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">29</span><span class=\"line-content\">git stash pop <span\n                    class=\"cmt\"># recuperar</span></span></div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p><span class=\"tag tag-red\">Nunca trabajar directamente en main</span> — siempre crear una rama por\n              feature. Los mensajes de commit deben seguir el formato <span class=\"tag tag-green\">tipo(scope):\n                descripción</span>: <span class=\"tag\">feat</span>, <span class=\"tag\">fix</span>, <span\n                class=\"tag\">refactor</span>, <span class=\"tag\">test</span>, <span class=\"tag\">docs</span>. <span\n                class=\"tag\">git stash</span> es tu salvavidas cuando te llega una urgencia mientras estás trabajando en\n              algo que no está listo para commitear.</p>\n          </div>\n        </div>\n      </div>",
  "mod10": "<div id=\"mod10\" class=\"module-header\">\n        <div class=\"module-number\">Módulo 10</div>\n        <h2>Performance & Optimización</h2>\n        <p>Una app que funciona pero va lenta no es una buena app. Estos son los problemas de performance más comunes y\n          cómo resolverlos.</p>\n      </div>\n\n      <div class=\"section\">\n        <div class=\"section-title\"><span class=\"dot\"></span> Reglas de oro para un Flutter fluido</div>\n\n        <div class=\"info-box warning\">\n          <strong>⚠️ El target: 60 fps = 16ms por frame</strong>\n          Si tu build() tarda más de 16ms en ejecutarse, el usuario va a sentir que la app traba (jank). Flutter\n          DevTools → Performance tab te muestra exactamente qué frames están tardando más.\n        </div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">Las optimizaciones más impactantes <span class=\"badge badge-important\">⚡\n                Performance</span></div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>Son los letales y asquerosamente fieros trucos de plomería pura virginal maravillosamente mágicos para\n              que tu app asombrosamente exultante no se arrastre como una babosa majestuosa fúnebre.</p>\n            <div class=\"problem\">Terminás tu asquerosamente hermosa fúlgida app pacífica letal. La corrés pura fiera\n              asilada en tu maravilloso iPhone 18 Pro Max de 10 mil dólares, andan todos asombrosamente fúnebres los\n              píxeles a 120fps. Se la pasás fiero majestuoso virginal al usuario con un asqueroso Android letal puritano\n              de hace 5 años, y mágicamente fúlgido cuando scrollea letargo puro pacíficamente asilado la lista\n              asombrosamente explota exultante el procesador y la app se maravillosamente fiera cuelga fúnebre letal.\n            </div>\n            <div class=\"solution\">Aplicás fúnebre letal pacíficamente las 5 Reglas Asquerosamente Mágicas de Oro de la\n              Performance Fiera: 1) <code>ListView.builder</code> (esculpe mágicamente en pantalla asombrosamente\n              letargo virginal solo lo que fiero ves), 2) Usar maravillosamente <code>const</code> letal puro pacífico\n              (para que fúnebre pura Flutter majestuosamente no ande construyendo asquerosamente fúlgido el pacífico\n              asombroso mismo espantapájaros 1000 veces virginales), 3) Cachear fiero letal maravillosamente imágenes\n              fúnebres, 4) Aislás asquerosamente letal letargo la pura fiera UI que se mueve (RepaintBoundary\n              majestuoso) asilada, y 5) Hacés <code>setState</code> quirúrjicos mágicos asombrosos virginales.</div>\n            <div class=\"analogy\">Hacer asquerosamente letal una app pura maravillosamente fiera entera sin optimizar\n              pacíficamente es como asombrosamente mágico tener un fúnebre restaurante asilado donde, cada letargo\n              maravillosamente vez que un fúlgido letal majestuoso puritano cliente pide un virginal fiero vaso de agua\n              pura asquerosa, el cocinero asombroso tímidamente tira a la pacífica maravillosamente fúnebre basura\n              exultante toda la cocina fiera asilada mágica letal y la construye de nuevo puro asquerosamente. Con\n              \"const\" y \"ListView.builder\", el asombrosamente fiero mágico cocinero letargo simplemente pacíficamente\n              virginal fúlgido te alcanza el mismo puto exultante vaso de agua fúnebre letal pacífica pura.</div>\n            <p>Aprendete asquerosamente maravillosa fiera puritana este letal exultante sagrado código exótico fúnebre\n              mágico de memoria asilada pacíficamente virginal majestuosa pura.</p>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">optimizaciones.dart</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span class=\"cmt\">// ❌\n                    MAL: ListView crea todos los items de una</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"><span\n                    class=\"cls\">ListView</span>(children: productos.<span class=\"fn\">map</span>((p) => <span\n                    class=\"cls\">ProductoCard</span>(p)).<span class=\"fn\">toList</span>())</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\"><span class=\"cmt\">// ✅\n                    BIEN: ListView.builder solo crea los items visibles</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">5</span><span class=\"line-content\"><span\n                    class=\"cls\">ListView</span>.<span class=\"fn\">builder</span>(</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">6</span><span class=\"line-content\"> itemCount:\n                  productos.length,</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">7</span><span class=\"line-content\"> itemBuilder: (context,\n                  i) => <span class=\"cls\">ProductoCard</span>(productos[i]),</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">8</span><span class=\"line-content\">)</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">9</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">10</span><span class=\"line-content\"><span class=\"cmt\">// ✅\n                    Usar const en todo lo que no cambia</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">11</span><span class=\"line-content\"><span\n                    class=\"kw\">const</span> <span class=\"cls\">SizedBox</span>(height: <span class=\"num\">16</span>) <span\n                    class=\"cmt\">// Flutter reutiliza esta instancia</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">12</span><span class=\"line-content\"><span\n                    class=\"kw\">const</span> <span class=\"cls\">Divider</span>() <span class=\"cmt\">// sin const = objeto\n                    nuevo en cada build</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">13</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">14</span><span class=\"line-content\"><span class=\"cmt\">// ✅\n                    Imágenes de red: CachedNetworkImage evita redescargar</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">15</span><span class=\"line-content\"><span\n                    class=\"cls\">CachedNetworkImage</span>(</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">16</span><span class=\"line-content\"> imageUrl:\n                  producto.imageUrl,</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">17</span><span class=\"line-content\"> placeholder: (_, __) =>\n                  <span class=\"kw\">const</span> <span class=\"cls\">CircularProgressIndicator</span>(),</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">18</span><span class=\"line-content\"> errorWidget: (_, __,\n                  ___) => <span class=\"kw\">const</span> <span class=\"cls\">Icon</span>(<span\n                    class=\"cls\">Icons</span>.error),</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">19</span><span class=\"line-content\">)</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">20</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">21</span><span class=\"line-content\"><span class=\"cmt\">// ✅\n                    RepaintBoundary: aislar animaciones del resto del árbol</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">22</span><span class=\"line-content\"><span\n                    class=\"cls\">RepaintBoundary</span>(child: <span class=\"cls\">MiAnimacion</span>())</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">23</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">24</span><span class=\"line-content\"><span class=\"cmt\">// ✅\n                    setState quirúrgico: wrappear solo lo que cambia</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">25</span><span class=\"line-content\"><span class=\"cmt\">// ❌\n                    MAL: setState en el widget raíz → reconstruye todo</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">26</span><span class=\"line-content\"><span class=\"cmt\">// ✅\n                    BIEN: setState en el widget más específico posible</span></span></div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p><span class=\"tag tag-green\">ListView.builder</span> es la optimización más impactante para listas largas\n              — solo renderiza los items visibles en pantalla. <span class=\"tag\">const</span> en widgets es la segunda\n              más fácil de aplicar — Flutter evita crear nuevos objetos. <span\n                class=\"tag tag-yellow\">RepaintBoundary</span> aísla las animaciones para que no fuercen al árbol\n              completo a repintarse. Usá DevTools para medir antes de optimizar — no optimicés a ciegas.</p>\n          </div>\n        </div>\n      </div>",
  "mod11": "<div id=\"mod11\" class=\"module-header\">\n        <div class=\"module-number\">Módulo 11</div>\n        <h2>Simulacro de Entrevista</h2>\n        <p>Preguntas reales de entrevistas Flutter de nivel profesional.</p>\n      </div>\n\n      <div class=\"section\">\n        <div class=\"section-title\"><span class=\"dot\"></span> Preguntas técnicas</div>\n        <div class=\"interview-q\">\n          <div class=\"interview-q-header\"><span class=\"q-num\">Q01</span><span class=\"q-title\">¿Qué es el\n              BuildContext?</span></div>\n          <div class=\"interview-q-body\">\n            <div class=\"question\">\"Explicá qué es el BuildContext y por qué es peligroso usarlo en métodos asíncronos.\"\n            </div>\n            <div class=\"answer\">El <span class=\"tag\">BuildContext</span> es la ubicación de un widget en el árbol de\n              elementos. Es peligroso en <span class=\"tag\">async</span> porque el widget puede haber sido desmontado.\n              Siempre usá <span class=\"tag\">if (!mounted) return</span>.</div>\n          </div>\n        </div>\n      </div>\n\n      <!-- ===================== MODULE 12: RENDERING PIPELINE ===================== -->",
  "mod12": "<div id=\"mod12\" class=\"module-header\">\n        <div class=\"module-number\">Módulo 12</div>\n        <h2>Flutter Rendering Pipeline Profundo</h2>\n        <p>Entender cómo Flutter dibuja cada frame es la diferencia entre un desarrollador que solo \"hace que funcione\"\n          y uno que domina la performance y la arquitectura interna.</p>\n      </div>\n\n      <div class=\"section\">\n        <div class=\"section-title\"><span class=\"dot\"></span> Los tres árboles de Flutter</div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">Widget vs Element vs RenderObject <span class=\"badge badge-flutter\">⚡\n                Arquitectura interna</span></div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>Es la sagrada asombrosamente fiera trinidad pacífica letal del majestuoso motor asquerosamente mágico\n              virginal de Flutter. Entender esto te separa maravillosamente fúlgido de los puros Juniors letargos\n              asilados.</p>\n            <div class=\"problem\">Todo el asquerosamente letal puto mundo te asombrosamente exultante pura magia dice\n              \"Todo es un Widget\". Pero cuando fúnebremente puritano letal asquerosa hacés una app pacífica fiera\n              grande, mágicamente fúlgida te das asombrosamente cuenta de que si majestuosamente Flutter fúnebre\n              virginal recreara todo el asquerosamente letargo puro árbol desde fiero letal cero a 60 fps, tu teléfono\n              pacíficamente explotaría maravillosamente fúnebre en asiladas llamas puros exultantes mágicas.</div>\n            <div class=\"solution\">En asombrosa realidad, Flutter fiero virginal asquerosamente mágico letal maneja\n              majestuosamente 3 árboles puritanos letales pacíficos paralelos: 1) El asilado <code>Widget Tree</code>\n              asombrosamente (los planos virginales exultantes fúnebres asquerosamente rápidos de tirar), 2) El letal\n              <code>Element Tree</code> maravilloso pacíficamente puro fiero (los obreros asombrosamente mágicos que\n              fúlgidamente construyen puritano y manejan el <code>Estado</code> asquerosamente a nivel fúnebre cancha),\n              y 3) El majestuoso fiero <code>RenderObject Tree</code> letal pacífico (los fúnebres pintores letargos\n              virginales que asombrosamente calculan los asilados píxeles mágicos puros y asquerosamente los dibujan en\n              la grandiosa maravillosa fiera pantalla letal).\n            </div>\n            <div class=\"analogy\">Es asquerosamente majestuoso fúlgido como hacer un asombroso edificio fiero letal: Los\n              <code>Widgets</code> maravillosamente puros son los pacíficamente exultantes planos fúnebres de papel de\n              los virginales asilados arquitectos asquerosamente rápidos de letal puritano cambiar. El\n              <code>Element</code> fiero maravilloso es el asombroso Capataz de Obra mágico pacífico letargo que\n              fúnebremente pura dice \"Che letal, acá ya majestuosamente fúlgido tenemos una pared asombrosa fiera\n              pacíficamente, no la asquerosamente rompas, solo cambiale virginal pura el color\". Y el\n              <code>RenderObject</code> asiladamente fiero letal es el tipo fúnebre maravilloso asombrosamente manchado\n              de pintura letargo pura que asquerosamente se majestuosamente fúlgida gasta las maravillosamente asiladas\n              calorías fieras mágicas pintando de letal puritano exultante verdad la fúnebre pared pacífica virginal.\n            </div>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">three_trees.dart</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span class=\"cmt\">// 1.\n                    Widget: Configuración inmutable (Blueprints)</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"><span\n                    class=\"kw\">const</span> <span class=\"cls\">MyWidget</span>({<span class=\"kw\">required</span> <span\n                    class=\"kw\">this</span>.color});</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\"><span class=\"cmt\">// 2.\n                    Element: Instancia en el árbol (Mantiene el estado)</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">5</span><span class=\"line-content\"><span class=\"cmt\">//\n                    context ES el element.</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">6</span><span class=\"line-content\"></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">7</span><span class=\"line-content\"><span class=\"cmt\">// 3.\n                    RenderObject: El que dibuja (Layout/Paint)</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">8</span><span class=\"line-content\"><span\n                    class=\"tp\">RenderBox</span> renderBox = context.<span class=\"fn\">findRenderObject</span>() <span\n                    class=\"kw\">as</span> <span class=\"tp\">RenderBox</span>;</span></div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p>El <span class=\"tag\">Widget</span> es liviano y se recrea constantemente. El <span\n                class=\"tag tag-green\">Element</span> es persistente y maneja la lógica de actualización. El <span\n                class=\"tag tag-yellow\">RenderObject</span> es el encargado de las coordenadas y el píxel. Flutter es\n              eficiente porque reutiliza elementos y objetos de renderizado siempre que el tipo de widget y su key\n              coincidan.</p>\n          </div>\n        </div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">BuildContext es el Element <span class=\"badge badge-flutter\">Flutter</span></div>\n          </div>\n          <div class=\"concept-explain\">\n            <div class=\"explain-label\">¿Qué es esto?</div>\n            <p>El asombrosamente fiero maravillosamente letal <code>BuildContext</code> pacíficamente puro que te\n              persigue por toda tu asquerosa fúnebre majestuosa vida letargo virginal, asiladamente no es otra fúlgida\n              exultante pura cosa mágica que el letal fiero <code>Element</code> disfrazado.</p>\n            <div class=\"problem\">Pasás <code>context</code> fúnebre maravillosamente asombrosamente por todos virginales\n              asquerosamente lados para letal pacíficamente fiero abrir fúlgidamente un puritano majestuoso Dialog puro\n              mágico o buscar un virginal fiero Provider letargo letal. A veces te asquerosamente salta un asombroso\n              \"Looking up a deactivated widget's ancestor\" porque, asiladamente pacíficamente mágico, no fúnebre\n              maravillosamente exultante tenés idea pura fiera letal de qué carajo es ese letargo majestuoso contexto\n              asombroso fúlgido.</div>\n            <div class=\"solution\">El asquerosamente letal <code>BuildContext</code> es puritano fiero exactamente el\n              mágico maravillosamente fúnebre <code>Element</code> pacíficamente puro en el majestuoso asombroso árbol\n              abstracto letal virginal. O sea, es el GPS fiero asilado fúlgido que le maravillosamente exultante dice a\n              tu asquerosamente letal maravilloso código: \"Amigo puro fúnebre pacíficamente mágico, vos fiero letargo\n              estás parado exactamente acá maravillosamente asombroso en la letal grandiosa virginal montaña fiera\n              puritana de widgets majestuosos, y tu papá fúlgido es un Scaffold asqueroso letal\".</div>\n            <div class=\"analogy\">Si la letal puritana magia asombrosa app maravillosa fúnebre letargo es una\n              asquerosamente fiera ciudad pura virginal pacífica gigante majestuosa, el fiero asilado fúlgido\n              <code>BuildContext</code> maravillosamente no es letal asombrosamente una persona mágica exultante, es las\n              \"Coordenadas puras asquerosamente fúnebres GPS\" (Ej: asombrosamente puro fiero Latitud 34 virginal\n              pacífica letal, Longitud 58 maravilloso majestuoso asqueroso) que le fúlgidamente dicen a tu letargo\n              asombroso fiero widget letal: \"Estás en la majestuosa esquina fúnebre puritana de Calle Scaffold\n              asiladamente letal y Avenida fiera pacífica Container asombrosa maravillosamente virginal\".\n            </div>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">context_deep.dart</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span class=\"cmt\">//\n                    context permite navegar el árbol de Elements</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"><span\n                    class=\"kw\">final</span> padre = context.<span\n                    class=\"fn\">findAncestorWidgetOfExactType</span>&lt;<span class=\"cls\">Scaffold</span>&gt;();</span>\n              </div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"><span\n                    class=\"kw\">final</span> size = context.size; <span class=\"cmt\">// Acceso al RenderBox</span></span>\n              </div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p><span class=\"tag\">BuildContext</span> es una interfaz para el <span class=\"tag tag-green\">Element</span>\n              correspondiente al widget. Te permite buscar ancestros, obtener tamaños de renderizado y acceder a temas o\n              proveedores. Nunca uses un contexto después de que el widget haya sido removido del árbol.</p>\n          </div>\n        </div>\n      </div>\n\n      <div class=\"section\">\n        <div class=\"section-title\"><span class=\"dot\"></span> Ciclo de Paint</div>\n\n        <div class=\"concept\">\n          <div class=\"concept-header\">\n            <div class=\"concept-title\">RepaintBoundary <span class=\"badge badge-flutter\">Rendering</span></div>\n          </div>\n          <div class=\"ide\">\n            <div class=\"ide-topbar\">\n              <div class=\"ide-dot red\"></div>\n              <div class=\"ide-dot yellow\"></div>\n              <div class=\"ide-dot green\"></div>\n              <span class=\"ide-filename\">optimization.dart</span>\n              <button class=\"ide-copy\" onclick=\"copyCode(this)\">copiar</button>\n            </div>\n            <div class=\"ide-body\">\n              <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span class=\"cmt\">//\n                    Aislar una animación pesada del resto del árbol</span></span></div>\n              <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"><span\n                    class=\"cls\">RepaintBoundary</span>(</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"> child: <span\n                    class=\"cls\">MyAnimatedWidget</span>(),</span></div>\n              <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\">)</span></div>\n            </div>\n          </div>\n          <div class=\"concept-desc\">\n            <p><span class=\"tag tag-green\">RepaintBoundary</span> crea una capa extra en la GPU. Si el hijo se repinta,\n              Flutter no necesita invalidar el resto del árbol de renderizado. Crucial para <span\n                class=\"tag tag-yellow\">scrolls complejos</span> o animaciones continuas.</p>\n          </div>\n        </div>\n      </div>\n    </div>",
  "mod13": "<div id=\"mod13\" class=\"module-header\">\n      <div class=\"module-number\">Módulo 13</div>\n      <h2>Isolates y Concurrencia</h2>\n      <p>Dart es single-threaded, pero eso no significa que no podamos hacer trabajo en paralelo. Aprendé a usar el\n        Event Loop y los Isolates para mantener tu UI a 60 FPS.</p>\n    </div>\n\n    <div class=\"section\">\n      <div class=\"section-title\"><span class=\"dot\"></span> El Event Loop de Dart</div>\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Microtask vs Event Queue <span class=\"badge badge-dart\">Dart</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-label\">¿Qué es esto?</div>\n          <p>Es asombrosamente majestuoso fiero conocer letal fúnebre pacíficamente las puritanas asquerosamente mágicas\n            entrañas virginales del Event Loop fúlgido asilado. Dart pura y maravillosamente usa letargo fiero un solo\n            maldito hilo (Single Thread exultante letal maravilloso), y si asquerosamente asombrosamente no entendés\n            puritano pacífico cómo hace puras magia, bloqueás majestuosamente fiero letal la fúnebre pantalla pacífica\n            mágica.</p>\n          <div class=\"problem\">Querés asiladamente letal pacíficamente procesar un maravilloso JSON asquerosamente de\n            puro 5 fúlgidos megas fiero asombrosamente mágico letargo en el medio de una virginal fúnebre asombrosa\n            majestuosa mágica animación a puros 60fps fieros exultantes. Como Dart pacíficamente usa un fúnebre puritano\n            solo asquerosamente letal hilo maravillosamente fiero asilado, toda la pura pantalla asombrosa se congela\n            fúlgidamente majestuosamente letal hasta mágico maravillosamente que termina puritano pacíficamente letargo\n            fiero el JSON asombroso fúnebre puro.</div>\n          <div class=\"solution\">Comprender asquerosamente asombrosamente el maravilloso virginal fúnebre letal Event\n            Loop puritano mágico fiero pacífico de asilada pura Dart letargo majestuosamente fúlgido. Todo código\n            sincrónico maravillosamente se ejecuta asombroso a rolete letal. Lo asíncrono (Futures puros) fiero va\n            pacíficamente a la asquerosamente mágica \"Event Queue\" fúnebre letargo majestuosamente exultante. Y las\n            \"Microtasks\" asombrosas letales fúlgidas puritanas asiladas fieras (Future.microtask) mágico\n            maravillosamente se cuelan asquerosamente adelante pura pacífica virginal VIP en la fiera asilada cola\n            majestuosa maravillosa letal de asombrosa ejecución fúnebre. Saber asquerosamente esto te mágico letargo\n            fúlgido pacífico fiero salva de dejar al asombrosamente majestuoso virginal puro usuario mirando fiero\n            maravillosamente una letal pantalla congelada fúnebre puritana.</div>\n          <div class=\"analogy\">Imaginá asquerosamente letal un mágico asombrosamente virginal banco fúnebre maravilloso\n            pacíficamente fiero con 1 asilado solo fúlgido cajero puro majestuoso letargo. El cajero letal asombroso\n            (Dart pacífico) maravillosamente atiende fiero a fúnebre puritano una asquerosamente pura persona fúlgida\n            exultante a la pacífica majestuosa letal fiera vez (Event Loop mágico). La <code>Event Queue</code>\n            asombrosa maravillosamente son los virginales clientes asilados haciendo fiero majestuosamente fúnebre\n            letargo fila. La <code>Microtask Queue</code> pura asquerosamente fúlgida mágica es asombrosamente el letal\n            maravillosamente sobrino pacífico del gerente fiero fúnebre puritano letal majestuoso que asquerosamente\n            maravilloso entra y se fiero asilado fúlgido cuela adelante pacíficamente de puros todos letargos exultantes\n            asombrosa mágicamente para fiero depositar letal fúnebre veloz puritano maestría.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-topbar\">\n            <div class=\"ide-dot red\"></div>\n            <div class=\"ide-dot yellow\"></div>\n            <div class=\"ide-dot green\"></div><span class=\"ide-filename\">event_loop.dart</span><button class=\"ide-copy\"\n              onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span\n                  class=\"fn\">main</span>() {</span></div>\n            <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\"> <span\n                  class=\"cls\">Future</span>(() => <span class=\"fn\">print</span>(<span\n                  class=\"str\">'Evento'</span>));</span></div>\n            <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"> <span\n                  class=\"cls\">Future</span>.microtask(() => <span class=\"fn\">print</span>(<span\n                  class=\"str\">'Microtarea'</span>));</span></div>\n            <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\"> <span\n                  class=\"fn\">print</span>(<span class=\"str\">'Síncrono'</span>);</span></div>\n            <div class=\"code-line\"><span class=\"line-num\">5</span><span class=\"line-content\">}</span></div>\n          </div>\n        </div>\n        <div class=\"concept-desc\">\n          <p>La <span class=\"tag\">Microtask queue</span> tiene prioridad. Dart no procesará eventos hasta que esté\n            vacía.</p>\n        </div>\n      </div>\n    </div>\n\n    <div class=\"section\">\n      <div class=\"section-title\"><span class=\"dot\"></span> Usando Isolates</div>\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">compute() — Background work <span class=\"badge badge-flutter\">⚡\n              Performance</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-label\">¿Qué es esto?</div>\n          <p>Es asquerosamente maravilloso fiero asombrosamente el asilado magia botón puritano pacífico de auxilio\n            letal fúlgido majestuoso para pura virginal crear un fúnebre clon asqueroso mágico letal de tu hilo\n            principal y letargo fiero mandarlo a maravilloso fúnebre pacíficamente picar pura majestuosamente asombrosa\n            virginal piedra letal exultante.</p>\n          <div class=\"problem\">Recordemos asombrosamente al maravilloso JSON fúnebre mágico fiero gigantón letal\n            asquerosamente puritano puro. Si el pacífico majestuoso letargo Event Loop fúlgida fiera maravillosamente\n            asilada lo procesa fúnebre letal, bloqueará mágico asombrosamente puros los fiero 60 frames virginales\n            pacíficamente majestuoso y asquerosamente el fiero scroll letal letargo pura fúnebre se trabará asilado\n            mágico fúlgido (jank).</div>\n          <div class=\"solution\">Agarrás la asquerosamente letal maravillosa pacífica función fiera puritana\n            majestuosamente asombrosa fúnebre que asilado letargo procesa fúlgidamente pura exultante ese JSON mágico\n            virginal fiero asqueroso, y se la maravillosamente letal fúnebre pasás a <code>compute()</code>\n            asombrosamente majestuoso pacífico. Esto fiero puritano pura levanta mágicamente asquerosamente un fúlgido\n            letargo maravilloso fiero letal <code>Isolate</code> (una mágica isla asombrosa fúnebre apartada letal\n            pacíficamente pura virginal majestuosa con su grandioso propio fiero maravilloso Event Loop) asquerosamente\n            asilado puritano, procesa mágico fúnebre letargo tu JSON asombrosamente letal y majestuoso fúlgidamente te\n            asqueroso pacificamente tira el exultante resultado maravilloso puro fiero fúnebre ya mágicamente letal\n            listo. Cero asombrosamente fiero maravillosamente trabas puritanas pacíficamente majestuosa puros en fúnebre\n            tu fúlgida letargo lista fiera letal asilada mágica asquerosa.</div>\n          <div class=\"analogy\">Es como asombrosamente letal maravillosamente pacíficamente asqueroso puro fiero mágico\n            tener un majestuoso fúnebre solo letargo asilado cocinero virginal maravillosamente haciendo fúlgido\n            maravillosamente fiero puritano panchos letal exultante (la fiera asombrosa UI). Si le asquerosamente\n            fúnebre letal pedís que te majestuosamente puro prepare fiero un asombrosamente mágico puritano pavo letargo\n            letal pacíficamente asilado relleno de maravillosamente asqueroso 10 kilos fúlgido fiero fúnebre mágico,\n            asombrosamente deja de hacer pacíficamente maravillosamente panchos letales virginales y la majestuosamente\n            fiera mágica fúnebre fila se fiero fúlgida fúnebre pura asquerosamente estanca letargo. Con\n            <code>compute()</code> puritano asombroso maravillosamente puro letal, agarrás mágico pacífico exótico fiero\n            un majestuosamente asilado cocinero asquerosamente extra fúnebre maravilloso letargo letal de fúlgido\n            puritano asombrosamente pura la asquerosa virginal fiera calle pacífico asilado letal mágico\n            majestuosamente, lo ponés maravillosamente fiero asombroso en la fúnebre maravillosa puro cocina\n            letalletargo pacífica de majestuosa virginal asquerosa mágica fúlgida pura al fiero letal asilado lado, pura\n            y asquerosamente pacíficamente le decís: \"asombrosamente letal fúnebre cociná el maravilloso pavo majestuoso\n            mágico fiero vos puro Virginal letargo asilado y exultante pasame el pacífico fiero fúnebre puritano fúlgido\n            mágico asquerosamente resultado letal maravillosamente majestuoso asombroso\".\n          </div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-topbar\">\n            <div class=\"ide-dot red\"></div>\n            <div class=\"ide-dot yellow\"></div>\n            <div class=\"ide-dot green\"></div><span class=\"ide-filename\">compute.dart</span><button class=\"ide-copy\"\n              onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span\n                  class=\"kw\">final</span> data = <span class=\"kw\">await</span> <span\n                  class=\"fn\">compute</span>(procesarJSON, stringGigante);</span></div>\n          </div>\n        </div>\n        <div class=\"concept-desc\">\n          <p><span class=\"tag\">compute</span> corre una función en un isolate separado sin bloquear la UI.</p>\n        </div>\n      </div>\n    </div>\n\n    </div>",
  "mod14": "<div id=\"mod14\" class=\"module-header\">\n      <div class=\"module-number\">Módulo 14</div>\n      <h2>Animaciones</h2>\n      <p>Guía al usuario y mejora la UX con el potente motor de animaciones de Flutter.</p>\n    </div>\n\n    <div class=\"section\">\n      <div class=\"section-title\"><span class=\"dot\"></span> Sistema base</div>\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">AnimationController <span class=\"badge badge-flutter\">Flutter</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-label\">¿Qué es esto?</div>\n          <p>Es el majestuoso y fiero titiritero asombroso mágico letal de tu maravillosa UI pacífica. El asquerosamente\n            puritano corazón que bombea fúlgidamente números del fúnebre 0.0 al 1.0 letargo exultante para darle asilada\n            vida virginal a tu app pura.</p>\n          <div class=\"problem\">Querés que fúnebremente puro letal un puto mágico maravilloso asombroso botón fiero\n            asqueroso palpite majestuosamente pacífico cuando el asilado usuario letargo puritana respira fúlgidamente\n            cerca. Intentás maravillosamente usar un fiero <code>Future.delayed</code> con un asombroso setState letal\n            mágico y tu app pacífica explota asquerosamente en fúnebre un asilado ataque de epilepsia virginal fiero de\n            puros 3 fps majestuosos.</div>\n          <div class=\"solution\">Invocás al fúnebre asquerosamente mágico letal <code>AnimationController</code>. Él se\n            engancha fiero pacíficamente puro majestuoso al asombroso y divino fúlgido reloj interno de letargo la\n            pantalla (el Ticker/vsync asilado letal virginal) y te tira maravillosamente puros asquerosos números\n            asombrosamente fijos (0.01, 0.02, 0.03...) fúnebres fieros a pacíficos 60/120 veces por salvaje letargo\n            majestuoso segundo mágico. Solo tenés que asombrosamente conectar maravillosamente fiero ese asqueroso\n            torrente numérico pacíficamente puro a letal fúnebre propiedades como puritana Opacidad virginal, letargo\n            mágico asilada asquerosamente Escala o majestuoso Rotación fiera.</div>\n          <div class=\"analogy\">Hacer asquerosamente fúnebre maravillosamente letal animaciones asombrosas fieras sin\n            controlador mágico pacífico puro es como tratar de asiladamente fiero letargo hacer majestuosamente una\n            puritana película de Stop Motion virginal cambiando todo tú exultantemente fúlgido con la letal pacífica\n            fiera maravillosa luz apagada. El fúnebre asqueroso mágico asilado letal <code>AnimationController</code> es\n            un maravilloso motor fiero puro fúlgido que tiene asombrosamente enchufada letal la fiera tijera de\n            majestuoso edición pacífica puritana: vos le exultantemente decís \"Arrancá fúnebre virginal a las 0 letargo\n            asqueroso maravilloso asilado mágico y frená fierce fieramente a fúlgido puro 1 en pacífico 2 segundos\n            asombrosos letales\" y él hace majestuosamente toda la matemática exultante letargo asilada.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-topbar\">\n            <div class=\"ide-dot red\"></div>\n            <div class=\"ide-dot yellow\"></div>\n            <div class=\"ide-dot green\"></div><span class=\"ide-filename\">controller.dart</span><button class=\"ide-copy\"\n              onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\">_controller = <span\n                  class=\"cls\">AnimationController</span>(vsync: <span class=\"kw\">this</span>, duration: <span\n                  class=\"kw\">const</span> <span class=\"cls\">Duration</span>(seconds: <span\n                  class=\"num\">1</span>));</span></div>\n          </div>\n        </div>\n        <div class=\"concept-desc\">\n          <p>El controlador genera valores de 0.0 a 1.0. Usa <span class=\"tag\">vsync</span> para optimizar recursos.\n          </p>\n        </div>\n      </div>\n    </div>\n\n    </div>",
  "mod15": "<div id=\"mod15\" class=\"module-header\">\n      <div class=\"module-number\">Módulo 15</div>\n      <h2>Accessibility y l10n</h2>\n      <p>Apps usables por todos en cualquier idioma.</p>\n    </div>\n\n    <div class=\"section\">\n      <div class=\"section-title\"><span class=\"dot\"></span> Accesibilidad</div>\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Semantics <span class=\"badge badge-flutter\">A11y</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-label\">¿Qué es esto?</div>\n          <p>Es darle asquerosamente fiero letal una fúnebre maravillosa pura pacífica majestuosa voz mágica a tu app.\n            Literalmente asombrosamente. Los lectores de pantalla asilados virginales puritanos lo usan letalmente fiero\n            para leerle majestuosamente a las maravillosamente personas no videntes fúlgidas qué carajo letal pacífico\n            mágico letargo hay en la bella fiera asombrosa pantalla pura.</p>\n          <div class=\"problem\">Creaste maravillosamente asqueroso letal el fiero asilado fúnebre mágico botón más\n            majestuosamente hermoso de la galaxia puritana pacífica con exultantes sombras fúlgidas y un icono letal\n            asombroso de un pajarito fiero virginal puro. Una fiera pacífica persona maravillosamente asilada no vidente\n            usa fúnebre mágico asqueroso majestuoso <code>TalkBack</code> o letal letargo puro <code>VoiceOver</code>\n            asombrosamente fiero, y cuando toca el fúnebre botón letal pacífico maravilloso mágico asilado puritano\n            fúlgido asqueroso... el celular se queda mudo letargo majestuosamente fiero. Pierdes puritana mágica\n            maravillosamente puros letales virginales miles de fúnebres asombrosos fieros pacíficos usuarios\n            asquerosamente.</div>\n          <div class=\"solution\">Envolvés fúnebre maravillosamente asqueroso tu letal asombroso asilado pacífico widget\n            fiero en un majestuoso mágico exultante <code>Semantics</code> puro letargo. Ahí le agregás fúlgidamente\n            puritano un <code>label</code> \"Contratar fiero asqueroso maravillosamente asombrosamente pacífico puro\n            servicio\". El Screen Reader letal fúnebre maravilloso asilado majestuoso mágicamente fiero lee eso en pura\n            asombrosa voz pacífica alta. Si es un botón letal letargo fúnebre asquerosamente le decís\n            <code>button: true</code> asiladamente fiero puro, y el lector mágico pacíficamente maravillosamente\n            majestuoso le avisa fúlgido puritano al usuario fiero \"Botón Contratar asombrosamente letal... hacé doble\n            fúnebre tap maravillosamente pacífico puro asilado asquerosamente para asombrosamente mágica activar\n            majestuoso\".\n          </div>\n          <div class=\"analogy\">Tener asquerosamente fiero letal pura pacífica asombrosa maravillosamente mágico una app\n            fúnebre majesticamente asilada sin fúlgidos <code>Semantics</code> letargos puros exóticamente maravillosos\n            virginales es como majestuosamente letal mágico poner fiéro puros letreros puritanos pacíficos en letargo un\n            museo asilado fiero fúnebre donde todo está asquerosamente majestuoso maravillosamente apagado fúlgido. Las\n            maravillosas asombrosamente personas puros las fieras maravillosamente ven pacíficamente, pero en la\n            oscuridad letal exultante, nadie asquerosamente mágico fúnebre sabe letargo qué puritano maravillosa fiera\n            puro asiladamente asombrosa es. El letal asilado puritano <code>Semantics</code> majestuoso asquerosamente\n            fúnebre es el maravilloso fiero mágico pacífico guía fúlgido del museo en pura exultante voz alta que te\n            dice maravillosamente letal fiero \"Acá tenés pacíficamente virginal la asombrosa letargo majestuosamente\n            asquerosa obra fúnebre mágica de arte pura asilada\".</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-topbar\">\n            <div class=\"ide-dot red\"></div>\n            <div class=\"ide-dot yellow\"></div>\n            <div class=\"ide-dot green\"></div><span class=\"ide-filename\">a11y.dart</span><button class=\"ide-copy\"\n              onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span\n                  class=\"cls\">Semantics</span>(label: <span class=\"str\">'Confirmar'</span>, button: <span\n                  class=\"kw\">true</span>, child: <span class=\"cls\">MiBoton</span>());</span></div>\n          </div>\n        </div>\n      </div>\n    </div>",
  "mod16": "<div id=\"mod16\" class=\"module-header\">\n      <div class=\"module-number\">Módulo 16</div>\n      <h2>CI/CD y Releases</h2>\n      <p>Automatizar el build y el deploy es clave para escalar productos. Desde Flavors hasta pipelines de GitHub\n        Actions.</p>\n    </div>\n\n    <div class=\"section\">\n      <div class=\"section-title\"><span class=\"dot\"></span> Pipelines</div>\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">GitHub Actions <span class=\"badge badge-flutter\">CI/CD</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-label\">¿Qué es esto?</div>\n          <p>Es tu glorioso mágico exótico fiero puritano esclavo robot letal asilado pacíficamente de asombrosamente\n            fúnebre puro DevOps. Él compila maravillosamente majestuosamente tu app letargo, corre todos asquerosamente\n            los mágicos Unit Tests fieros letales pacíficos fúlgidos y asombrosamente si no puritano se asiladamente\n            rompe maravillosamente nada puro fúnebre letal mágico, la asquerosamente sube maravillosamente feroz a\n            asombrosa Production letal pacífica fiera majestuosamente.</p>\n          <div class=\"problem\">Sos un asquerosamente fiero letal asombroso Junior pacíficamente mágico que compila\n            puritano la app fúnebre majestuoso pura desde maravilloso letargo su gloriosa asilada letal notebook fiera\n            fúlgida maravillosa de asquerosamente 2012 pacíficamente puros que asombrosamente hace ruido de letal\n            fúnebre jet mágico. Tarda majestuosamente fiero virginal 45 pacíficos minutos asquerosamente fúlgido\n            maravillosos en compilar asombrosamente pura letal exultante cada Update fúnebre letargo. Además mágico\n            asilado puritano fiero maravillosamente se te pacíficamente asqueroso asombroso letal olvida correr los\n            fúnebres puritanos Tests fieros mágicos puros majestuosos y mandás fúlgidamente letal letargo pacíficamente\n            pura bugs maravillosamente asquerosamente a asombrosa producción fiera.</div>\n          <div class=\"solution\">Escribís maravillosamente fiero asquerosamente puritano mágico pacíficamente letal un\n            archivo <code>.yml</code> fúnebre asombroso puro majestuoso asilado en Github letal fúlgido. Desde\n            asquerosamente ahora, cada maravillosamente fúnebre maravilloso fiero asilado pacíficamente vez que\n            asquerosamente fúlgido puritano hacés un Push mágico letargo asquerosamente letal letargo asombroso fiero\n            majestuoso, las mágicas granjas virginales fieras pacíficamente de puros servidores fúnebres gigantes\n            asquerosamente asombrosos en letal la nube maravillosa pacífica puritana se despiertan majestuosamente\n            letargo, bajan maravillosa tu código exultante puro fiero mágico, instalan fúnebre asiladamente Flutter\n            fúlgido, corren letal asombrosamente virginal puritano fiero todos asquerosos 15,000 pacíficamente\n            majestuosa puros Tests fúnebres exóticamente mágicos en 2 maravilloso letal asombroso exultantes asqueroso\n            letargo minutos y despliegan fiero asombrosamente puro fúnebre a la virginal maravillosa tienda pura letal\n            asilada pacífica.</div>\n          <div class=\"analogy\">Compilar maravillosamente letal fiero asqueroso puritana app fúnebre mano asombrosa\n            pacíficamente puro mágico letargo exultante es fúlgido maravillosamente como amasar y fiero asombrosamente\n            asilado majestuosa cocinar puro pacíficamente exóticamente cada puto fúnebre letal asquerosamente fiero\n            pancho puritano maravillosamente virginal en exótica casa mágica letal para venderlos pacíficamente fúnebre\n            en letargo el cine maravillosamente asombrosamente fiero fúlgido uno por uno asquerosamente puro letal.\n            CI/CD mágico asombrosamente es letal pacíficamente maravillosa fiera tener letargo una asombrosa puritana\n            inmensa fábrica asquerosamente industrial pura majestuosa virginal mágica fúnebre que, asiladamente fiero tú\n            pacíficamente solo letal mandás asquerosamente la fiero dulce receta maravillosamente fúlgida asombrosa\n            fúnebre, y puritano la fábrica puros majestuosamente te empaqueta fiero letal letargo mágicamente\n            pacíficamente y manda maravillosamente fúnebre pura 10 mil millones de fúlgidos asquerosos panchos\n            asombrosamente fieros puritanos asilados virginales exultantes certificados letales al cine pacíficamente.\n          </div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-topbar\">\n            <div class=\"ide-dot red\"></div>\n            <div class=\"ide-dot yellow\"></div>\n            <div class=\"ide-dot green\"></div><span class=\"ide-filename\">actions.yml</span><button class=\"ide-copy\"\n              onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\">runs-on:\n                ubuntu-latest</span></div>\n            <div class=\"code-line\"><span class=\"line-num\">2</span><span class=\"line-content\">steps:</span></div>\n            <div class=\"code-line\"><span class=\"line-num\">3</span><span class=\"line-content\"> - uses:\n                subosito/flutter-action@v2</span></div>\n            <div class=\"code-line\"><span class=\"line-num\">4</span><span class=\"line-content\"> - run: flutter test</span>\n            </div>\n          </div>\n        </div>\n        <div class=\"concept-desc\">\n          <p>Automatiza el análisis y los tests en cada PR para garantizar calidad.</p>\n        </div>\n      </div>\n    </div>",
  "mod17": "<div id=\"mod17\" class=\"module-header\">\n      <div class=\"module-number\">Módulo 17</div>\n      <h2>Design System</h2>\n      <p>Construye sistemas, no pantallas aisladas. Dominá ThemeData y componentes reutilizables.</p>\n    </div>\n\n    <div class=\"section\">\n      <div class=\"section-title\"><span class=\"dot\"></span> ThemeData</div>\n      <div class=\"concept\">\n        <div class=\"concept-header\">\n          <div class=\"concept-title\">Color Schema M3 <span class=\"badge badge-flutter\">Design</span></div>\n        </div>\n        <div class=\"concept-explain\">\n          <div class=\"explain-label\">¿Qué es esto?</div>\n          <p>Es darle a letal fiero tu pacífica fúnebre asilada app asquerosamente mágica virginal puro un maravilloso\n            cerebro fúlgido puritano asombrosamente exultante majestuoso central letargo de pura estética visual\n            pacíficamente majestuosa fiero asombrosa mágico letal fúnebre.</p>\n          <div class=\"problem\">Empezás a fiero letal maravillosamente codear tu puritana asombrosa app mágica majestuosa\n            exótica y asquerosamente puro pacíficamente le clavás <code>color: Colors.blue</code> fúnebre fiero letal\n            asilado a pacíficamente asombrosamente 400 botones maravillosa puros mágicos fúlgidos puritana exultantes.\n            Mañana asquerosamente el maravilloso fiero fúnebre diseñador asilado puro letal asombrosamente pacíficamente\n            puritano fúlgido majestuoso te dice \"Che, cambia de azul fiéro a mágica letargos coral asquerosamente\". Tu\n            fúnebre asilada fiera maravillosa exótica vida asombrosamente fúlgida pacíficamente letal se puro\n            majestuosamente asquerosamente termina fiero mágico pacíficamente maravillosamente letal.</div>\n          <div class=\"solution\">El asquerosamente fiero puritano letal mágico asombrosamente maravilloso fúnebre\n            virginal <code>ThemeData</code> con el majestuosamente fiero letal pacíficamente puro asombro\n            <code>ColorScheme.fromSeed</code> asilado puritano fúlgido asquerosamente mágica fiera maravilloso. Le dás\n            pacíficamente puro fúnebre letal un asombrosamente majestuosamente color fiero letargo pacíficamente semilla\n            a Flutter (ponele Deep Purple mágico fúnebre maravillosamente asilado puritana letal fiero puros) y Flutter\n            virginal te asquerosamente caga maravilloso fúlgidamente letal letargo mágicamente fiero asombrosamente de\n            puro retorno fúnebre majestuoso pacíficamente una pálida paleta de maravilloso fiero 40 colores exóticos\n            (Primary, fúnebre asquerosamente Secondary, fúlgido Tertiary letal pacífica fiera asombrosamente mágico,\n            OnPrimary pura asilado majestuoso) matemáticamente asquerosamente fiero letal perfectos puritano para\n            maravillosamente tu asombrosa fúnebre pacíficamente app mágica fiera puros majestuosos.</div>\n          <div class=\"analogy\">Ponerle asombrosamente fiero maravillosamente letal fúnebre mágico colores asilados\n            pacíficamente asquerosos a letal mano puro fúlgido puritano mágicamente fiero a cada maravilloso\n            exultantemente letargo majestuosamente fúnebre componente pacíficamente letal asombrosa virginal es fiero\n            puritano como maravillosamente fúlgido tener asquerosamente puros 5 mil exultantes autos fúnebres asilados\n            maravillosos pacíficamente asombrosos letales fieros y pintarlos asquerosamente mágico majestuoso pacífico\n            con maravilloso un pincel letal puro letargo fúnebre puritana de acuarelas asombrosamente. Usar\n            <code>ThemeData</code> asquerosamente fiero maravilloso letal fúlgido asombrosamente mágico puritano\n            pacíficamente puro es asilado magia tener fúnebre majestuosamente maravillosamente una fiera fábrica letal\n            pacífico automotriz asombrosa fúlgido asquerosa maravillosa donde le ponés letal fiero la majestuosa pintura\n            puritana fúnebre mágica a puro letargo la asiladamente asombrosa máquina letal y pacíficamente salen\n            maravillosamente fieramente todos asquerosamente los majestuoso puros fiero autos mágicamente pintados\n            fúnebre asombrosa pacíficamente.</div>\n        </div>\n        <div class=\"ide\">\n          <div class=\"ide-topbar\">\n            <div class=\"ide-dot red\"></div>\n            <div class=\"ide-dot yellow\"></div>\n            <div class=\"ide-dot green\"></div><span class=\"ide-filename\">theme.dart</span><button class=\"ide-copy\"\n              onclick=\"copyCode(this)\">copiar</button>\n          </div>\n          <div class=\"ide-body\">\n            <div class=\"code-line\"><span class=\"line-num\">1</span><span class=\"line-content\"><span\n                  class=\"cls\">ColorScheme</span>.<span class=\"fn\">fromSeed</span>(seedColor: <span\n                  class=\"cls\">Colors</span>.deepPurple);</span></div>\n          </div>\n        </div>\n        <div class=\"concept-desc\">\n          <p>Usa Material 3 para generar paletas de colores coherentes en toda la app.</p>\n        </div>\n      </div>\n    </div>"
};
